terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Data source for the existing hosted zone
data "aws_route53_zone" "primary" {
  name = "example.com"  # Replace with your domain name
}

# Example Elastic Load Balancer (replace with your actual ALB ARN or DNS name)
resource "aws_lb" "main" {
  name               = "main"
  internal           = false
  load_balancer_type = "application"
  security_groups    = []  # Add your security group IDs
  subnets            = []  # Add your subnet IDs

  enable_deletion_protection = true

  tags = {
    Environment = "production"
  }
}

# Route 53 record pointing to the ELB
resource "aws_route53_record" "main" {
  zone_id = data.aws_route53_zone.primary.zone_id
  name    = "app.${data.aws_route53_zone.primary.name}"  # Replace 'app' with desired subdomain
  type    = "A"

  aliases {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}

