terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

resource "aws_vpc" "main" {
  provider = aws.main
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main"
  }
}

resource "aws_subnet" "main" {
  provider = aws.main
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "${var.main_region}a"
  tags = {
    Name = "main-subnet"
  }
}

resource "aws_db_subnet_group" "main" {
  provider = aws.main
  name       = "main"
  subnet_ids = [aws_subnet.main.id]
}

resource "aws_security_group" "db_main" {
  provider = aws.main
  name_prefix = "db-main"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "primary" {
  provider = aws.main

  identifier           = "primary"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_main.id]
  skip_final_snapshot  = true
  publicly_accessible  = true

  tags = {
    Name = "primary"
  }
}

resource "aws_vpc" "us_east" {
  provider = aws.us-east
  cidr_block = "10.1.0.0/16"
  tags = {
    Name = "us-east"
  }
}

resource "aws_subnet" "us_east" {
  provider = aws.us-east
  vpc_id     = aws_vpc.us_east.id
  cidr_block = "10.1.1.0/24"
  availability_zone = "${var.us_east_region}a"
  tags = {
    Name = "us-east-subnet"
  }
}

resource "aws_db_subnet_group" "us_east" {
  provider = aws.us-east
  name       = "us-east"
  subnet_ids = [aws_subnet.us_east.id]
}

resource "aws_security_group" "db_us_east" {
  provider = aws.us-east
  name_prefix = "db-us-east"
  vpc_id      = aws_vpc.us_east.id

  ingress {
    from_port   = 3306
