  records = [aws_db_instance.replica_ap_southeast.endpoint]
}

resource "aws_route53_record" "weighted_primary" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.example.com"
  type    = "CNAME"
  ttl     = 300
