  tags = {
    Name = "main-db-subnet-group"
  }
}

# Public RDS Instance
resource "aws_db_instance" "public" {
  identifier              = "public"
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  publicly_accessible     = true
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.rds_public.id]
  skip_final_snapshot     = true
  final_snapshot_identifier = "public-final-snapshot"
}

# Private RDS Instance
resource "aws_db_instance" "internal" {
  identifier              = "internal"
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.rds_private.id]
  skip_final_snapshot     = true
  final_snapshot_identifier = "internal-final-snapshot"
}

# Security Groups
resource "aws_security_group" "rds_public" {
  name_prefix = "rds-public-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "rds_private" {
  name_prefix = "rds-private-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    self            = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Route 53 Hosted Zones (example.com domain)
resource "aws_route53_zone" "public" {
  name = "example.com"
}

resource "aws_route53_zone" "private" {
  name = "example.com"

  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# Public A record pointing to public RDS
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public-db.example.com"
  type    = "A"
  ttl     = 300
  records = [aws_db_instance.public.address]
}

# Private A record pointing to internal RDS
resource "aws_route53_record" "private_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal-db.example.com"
  type    = "A"
  ttl     = 300
  records = [aws_db_instance.internal.address]
}

# Output the hosted zone IDs and record names
output "public_hosted_zone_id" {
  value = aws_route53_zone.public.id
}

output "private_hosted_zone_id" {
  value = aws_route53_zone.private.id
}

output "public_db_endpoint" {
  value = aws_db_instance.public.endpoint
}

output "internal_db_endpoint" {
  value = aws_db_instance.internal.endpoint
}
