provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# IAM Role for EC2 instances in Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AWS managed policy for Elastic Beanstalk
resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_api_app" {
  name = "my_api_app"
}

# Elastic Beanstalk Application Version (placeholder - replace with your app zip)
resource "aws_s3_bucket" "eb_app_bucket" {
  bucket = "my-api-app-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_object" "app_version" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = "app.zip"
  source = "app.zip"  # Replace with path to your application zip file
  etag   = filemd5("app.zip")
}

resource "aws_elastic_beanstalk_application_version" "my_api_app_version" {
  name   = "v1.0"
  application = aws_elastic_beanstalk_application.my_api_app.name
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = aws_s3_object.app_version.id
}

# Launch Configuration for Auto Scaling
resource "aws_launch_configuration" "eb_launch_config" {
  name_prefix          = "my-api-launch-"
  image_id             = "ami-0c02fb55956c7d316"  # Amazon Linux 2 AMI - update for your region
  instance_type        = "t3.micro"
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
  security_groups      = [aws_security_group.eb_sg.id]

  user_data = base64encode(<<-EOF
    #!/bin/bash
    # Elastic Beanstalk user data - will be overridden by EB
    echo "EB instance starting"
    EOF
  )

  lifecycle {
    create_before_destroy = true
  }
}

# Security Group for Elastic Beanstalk
resource "aws_security_group" "eb_sg" {
  name_prefix = "eb-my-api-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "EB My API SG"
  }
}

# Default VPC
data "aws_vpc" "default" {
  default = true
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "my_api_env" {
  name                = "my-api-env"
  application         = aws_elastic_beanstalk_application.my_api_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.5 running .NET Core"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "2"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "4"
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  # CPU-based Auto Scaling policies
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "MeasureName"
    value     = "CPUUtilization"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Statistic"
    value     = "Average"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Unit"
    value     = "Percent"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerThreshold"
    value     = "30.0"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerBreachIncrement"
    value     = "-1"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperThreshold"
    value     = "70.0"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperBreachIncrement"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:updatepolicy:rollingupdate"
    name      = "RollingUpdateEnabled"
    value     = "true"
  }

  setting {
    namespace = "aws:autoscaling:updatepolicy:rollingupdate"
    name      = "MaxBatchSize"
    value     = "25"
  }

  depends_on = [aws_elastic_beanstalk_application_version.my_api_app_version]
}

# Output the environment URL
output "environment_url" {
  value = aws_elastic_beanstalk_environment.my_api_env.cname
}

