  bucket = aws_s3_bucket_object.app_version.bucket
  key    = aws_s3_bucket_object.app_version.key
}

# SQS Queue for worker environment
resource "aws_sqs_queue" "batch_queue" {
  name = "batch_job_queue"
}

# Elastic Beanstalk Worker Environment
resource "aws_elastic_beanstalk_environment" "batch_worker" {
  name                = "batch-worker-env"
  application         = aws_elastic_beanstalk_application.batch_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.6 running .NET Core 6"  # Adjust for your app runtime

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "eb_ec2_profile"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = "aws-elasticbeanstalk-service-role"  # Default EB service role
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  setting {
    namespace = "aws:elbv2:loadbalancer"
    name      = "ListenerEnabled"
    value     = "false"  # Worker environments don't need load balancer
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd:queues"
    name      = "QueueUrl"
    value     = aws_sqs_queue.batch_queue.url
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd:queues"
    name      = "QueueName"
    value     = aws_sqs_queue.batch_queue.name
  }

  version_label = aws_elastic_beanstalk_application_version.app_version.name

  depends_on = [aws_elastic_beanstalk_application_version.app_version]
}
