    value     = "application"
  }
}

# Green Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.main.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default.ids)
  }

  setting {
    namespace = "aws:elb:loadbalancer"
    name      = "LoadBalancerType"
    value     = "application"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name = "blue-green-app"
}

# Route 53 Hosted Zone (assuming existing zone)
data "aws_route53_zone" "main" {
  name         = "example.com"  # Replace with your domain
  private_zone = false
}

# Blue Route 53 Record with Weighted Routing Policy (100% initially)
resource "aws_route53_record" "blue" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "app.example.com"  # Replace with your subdomain
  type    = "A"

  set_identifier = "blue"
  weighted_routing_policy {
    region          = "us-east-1"
    failoversafety_lambda_arn = ""
    weight          = 100
  }

  aliases {
    name                   = aws_elastic_beanstalk_environment.blue.cname
    zone_id                = aws_elastic_beanstalk_environment.blue.cname_zone_id
    evaluate_target_health = false
  }
}

# Green Route 53 Record with Weighted Routing Policy (0% initially)
resource "aws_route53_record" "green" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "app.example.com"  # Same name as blue for weighted routing
  type    = "A"

  set_identifier = "green"
  weighted_routing_policy {
    region          = "us-east-1"
    failoversafety_lambda_arn = ""
    weight          = 0
  }

  aliases {
    name                   = aws_elastic_beanstalk_environment.green.cname
    zone_id                = aws_elastic_beanstalk_environment.green.cname_zone_id
    evaluate_target_health = false
  }
}

# Data sources for VPC and Subnets (adjust as needed)
data "aws_vpc" "main" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.main.id]
  }
}

