  name        = "us_west_app"
  description = "US West Elastic Beanstalk Application"
}

resource "aws_elastic_beanstalk_application" "eu_central_app" {
  provider    = aws.eu_central_1
  name        = "eu_central_app"
  description = "EU Central Elastic Beanstalk Application"
}

# Elastic Beanstalk Environment - US West
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider           = aws.us_west_2
  name               = "us_west"
  application        = aws_elastic_beanstalk_application.us_west_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  depends_on = [
    aws_iam_role_policy_attachment.us_west_eb_service_policy,
    aws_iam_role_policy_attachment.us_west_eb_worker_policy
  ]
}

# Elastic Beanstalk Environment - EU Central
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider           = aws.eu_central_1
  name               = "eu_central"
  application        = aws_elastic_beanstalk_application.eu_central_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  depends_on = [
    aws_iam_role_policy_attachment.eu_central_eb_service_policy,
    aws_iam_role_policy_attachment.eu_central_eb_worker_policy
  ]
}

# Route 53 Hosted Zone and Geolocation Records
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

resource "aws_route53_record" "us_west_geolocation" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"

  geolocation_routing_policy {
    continent_code = "NA"
    country_code   = ["US", "CA"]
  }

  set_identifier = "us_west"
  ttl            = 300

  alias {
    name                   = aws_elastic_beanstalk_environment.us_west.cname
    zone_id                = aws_elastic_beanstalk_environment.us_west.cname ? aws_elastic_beanstalk_environment.us_west.environment_id : ""
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "eu_central_geolocation" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"

  geolocation_routing_policy {
    continent_code = "EU"
    country_code   = ["DE", "FR", "GB", "NL"]
  }

  set_identifier = "eu_central"
  ttl            = 300

  alias {
    name                   = aws_elastic_beanstalk_environment.eu_central.cname
    zone_id                = aws_elastic_beanstalk_environment.eu_central.cname ? aws_elastic_beanstalk_environment.eu_central.environment_id : ""
    evaluate_target_health = false
  }
}

# Default record (fallback)
resource "aws_route53_record" "default" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"

  set_identifier = "default"
  ttl            = 300

  alias {
    name                   = aws_elastic_beanstalk_environment.us_west.cname
    zone_id                = aws_elastic_beanstalk_environment.us_west.cname ? aws_elastic_beanstalk_environment.us_west.environment_id : ""
    evaluate_target_health = false
  }
}

output "us_west_environment_url" {
  value = aws_elastic_beanstalk_environment.us_west.cname
}

output "eu_central_environment_url" {
  value = aws_elastic_beanstalk_environment.eu_central.cname
}

output "route53_domain" {
  value = aws_route53_zone.primary.name
}
```

**Notes:**
- Replace `"example.com"` with your actual domain
- S3 bucket names include random suffix for global uniqueness
- IAM roles are simplified; add additional policies as needed
- Geolocation routing directs NA traffic to US West, EU traffic to EU Central
- Default record routes all other traffic to US West
- VPC settings are empty; configure VPC/subnets as needed for production
- Application deployment ZIP file needs to be added via `aws_elastic_beanstalk_application_version` resource

