terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Variables
variable "domain_name" {
  description = "The domain name to host (e.g., example.com)"
  type        = string
}

variable "hosted_zone_id" {
  description = "The Route 53 Hosted Zone ID for the domain"
  type        = string
}

variable "eb_environment_name" {
  default = "myenv"
}

variable "eb_ec2_instance_profile" {
  default = "eb_ec2_profile1"
}

variable "db_name" {
  default = "myapp_db"
}

# IAM Role and Instance Profile for EC2 (assuming role exists, creating profile)
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = var.eb_ec2_instance_profile
  role = var.eb_ec2_instance_profile  # Assumes IAM role "eb_ec2_profile1" exists
}

# RDS Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]  # Replace with your subnet IDs

  tags = {
    Name = "main-db-subnet-group"
  }
}

# RDS Database Instance
resource "aws_db_instance" "myapp_db" {
  identifier             = var.db_name
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = var.db_name
  username               = "admin"
  password               = "SecurePassword123!"  # Use secrets manager in production
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = ["sg-12345678"]  # Replace with your DB SG ID
  skip_final_snapshot    = true

  tags = {
    Name = var.db_name
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name = "myapp"
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = var.eb_environment_name
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"  # Example stack

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "vpc-12345678"  # Replace with your VPC ID
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "subnet-12345678,subnet-87654321"  # Replace with your subnet IDs
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elb:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }

  # Environment variables for DB connection
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.endpoint
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = var.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = "admin"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = "SecurePassword123!"  # Use secrets manager in production
  }

  depends_on = [aws_db_instance.myapp_db]
}

# Route 53 Record to point to Elastic Beanstalk
resource "aws_route53_record" "app" {
  zone_id = var.hosted_zone_id
  name    = var.domain_name
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv.cname_zone_id
    evaluate_target_health = false
  }
}

# Outputs
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.myenv.cname
}

output "rds_endpoint" {
  value = aws_db_instance.myapp_db.endpoint
}

output "route53_record_name" {
  value = aws_route53_record.app.fqdn
}
```

**Note:** Before applying, update the following placeholders:
- `domain_name` and `hosted_zone_id` variables with your actual domain details
- VPC ID, subnet IDs, and security group IDs
- Ensure the IAM role `eb_ec2_profile1` exists with necessary permissions (EBService role)
- Use AWS Secrets Manager for DB credentials in production
- Adjust RDS engine, instance class, and EB solution stack as needed

