  alias {
    name                   = aws_elastic_beanstalk_environment.myenv_us_east.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv_us_east.resources[0].elb.cloudwatch_log_group_name
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "eu_west_alias" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "eu-west-1.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv_eu_west.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv_eu_west.resources[0].elb.cloudwatch_log_group_name
    evaluate_target_health = true
  }
}
```

**Note:** Replace `"example.com."` in the Route 53 zone data source with your actual domain name. The configuration creates complete multi-region infrastructure with VPCs, security groups, RDS databases, Elastic Beanstalk environments, and Route 53 DNS routing. The IAM instance profile is shared across regions.

