}

resource "aws_db_instance" "myapp_db" {
  identifier             = "myapp-db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "myapp_db"
  username               = "admin"
  password               = "SecurePassword123!"
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.web.id]
  skip_final_snapshot    = true
}

# Route 53 Blue-Green with Failover
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "myapp.example.com"
  type    = "A"

  set_identifier = "blue-primary"
  failover_routing_policy = "PRIMARY"

  health_check_id = aws_route53_health_check.blue.id

  aliases {
    name                   = aws_lb.blue.dns_name
    zone_id                = aws_lb.blue.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "secondary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "myapp.example.com"
  type    = "A"

  set_identifier = "green-secondary"
  failover_routing_policy = "SECONDARY"

  aliases {
    name                   = aws_lb.green.dns_name
    zone_id                = aws_lb.green.zone_id
    evaluate_target_health = true
  }
}

# Health Checks
resource "aws_route53_health_check" "blue" {
  fqdn              = aws_lb.blue.dns_name
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30
}

resource "aws_route53_health_check" "green" {
  fqdn              = aws_lb.green.dns_name
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30
}

# Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}
```

**Note:** Create a `user_data.tpl` file with the following content for the EC2 user data:

```bash
#!/bin/bash
yum update -y
yum install -y httpd mysql
systemctl start httpd
systemctl enable httpd

cat > /var/www/html/index.html << EOF
<!DOCTYPE html>
<html><body><h1>Blue/Green Deployment - $(hostname)</h1></body></html>
EOF

# Configure MySQL connection test
cat > /var/www/html/testdb.php << EOF
<?php
\$host = '${db_endpoint}';
\$dbname = '${db_name}';
\$conn = new mysqli(\$host, 'admin', 'SecurePassword123!', \$dbname);
if (\$conn->connect_error) {
    die("Connection failed: " . \$conn->connect_error);
}
echo "Database connection successful!";
\$conn->close();
?>
EOF
```

This configuration sets up:
- Blue/Green environments with separate ALBs and ASGs sharing a common RDS
- Route 53 failover routing policy with health checks
- Blue as PRIMARY, Green as SECONDARY (scale green up for deployment, then swap)
- Uses specified instance profile and database name

