provider "aws" {
  region = var.aws_region
}

# S3 bucket for Elastic Beanstalk application versions
resource "aws_s3_bucket" "eb_app_bucket" {
  bucket = "${var.app_name}-app-bucket-${var.environment}"
}

resource "aws_s3_bucket_versioning" "eb_app_bucket_versioning" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "eb_app_bucket_public_access" {
  bucket = aws_s3_bucket.eb_app_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for Elastic Beanstalk service
resource "aws_iam_role" "eb_service_role" {
  name = "${var.app_name}-eb-service-role-${var.environment}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service_policy" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

# Custom policy for S3 access
resource "aws_iam_role_policy" "eb_s3_policy" {
  name = "${var.app_name}-eb-s3-policy-${var.environment}"
  role = aws_iam_role.eb_service_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.eb_app_bucket.arn}/*"
      },
      {
        Effect = "Allow"
        Action = "s3:ListBucket"
        Resource = aws_s3_bucket.eb_app_bucket.arn
      }
    ]
  })
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name                = var.app_name
  description         = var.app_description

  tags = {
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
}

# Elastic Beanstalk Application Version (placeholder - upload your app zip to S3 first)
resource "aws_elastic_beanstalk_application_version" "default" {
  name        = "${var.app_name}-v${var.app_version}"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = aws_s3_bucket.eb_app_bucket.bucket
  key         = "${var.app_name}-v${var.app_version}.zip" # Upload your app zip with this key

  tags = {
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
}

# Launch Configuration (EC2)
resource "aws_launch_template" "eb_launch_template" {
  name_prefix   = "${var.app_name}-"
  image_id      = data.aws_ami.amazon_linux.id
  instance_type = var.instance_type

  vpc_security_group_ids = [aws_security_group.eb_sg.id]

  iam_instance_profile {
    name = aws_iam_instance_profile.eb_instance_profile.name
  }

  user_data = base64encode(templatefile("${path.module}/user_data.tpl", {
    app_name = var.app_name
  }))

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name        = "${var.app_name}-instance-${var.environment}"
      Environment = var.environment
    }
  }
}

# IAM Instance Profile for EC2
resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "${var.app_name}-eb-instance-profile-${var.environment}"
  role = aws_iam_role.eb_instance_role.name
}

resource "aws_iam_role" "eb_instance_role" {
  name = "${var.app_name}-eb-instance-role-${var.environment}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_worker_policy" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorker"
}

resource "aws_iam_role_policy_attachment" "eb_web_policy" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# VPC and Security Groups (assuming default VPC)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

resource "aws_security_group" "eb_sg" {
  name_prefix = "${var.app_name}-eb-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "${var.app_name}-eb-sg-${var.environment}"
    Environment = var.environment
  }
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "env" {
  name                = "${var.app_name}-${var.environment}"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = var.solution_stack_name # e.g., "64bit Amazon Linux 2 v3.4.5 running Corretto 11"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default.id
  }

