# Terraform configuration for AWS Elastic Beanstalk Go application
# Assumes AWS provider is configured with proper credentials and region

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# VPC and networking
resource "aws_vpc" "eb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "${var.app_name}-vpc"
  }
}

resource "aws_internet_gateway" "eb_igw" {
  vpc_id = aws_vpc.eb_vpc.id

  tags = {
    Name = "${var.app_name}-igw"
  }
}

resource "aws_subnet" "eb_public_subnet_1" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "${var.aws_region}a"

  tags = {
    Name = "${var.app_name}-public-subnet-1"
    Type = "Public"
  }
}

resource "aws_subnet" "eb_public_subnet_2" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "${var.aws_region}b"

  tags = {
    Name = "${var.app_name}-public-subnet-2"
    Type = "Public"
  }
}

resource "aws_route_table" "eb_public_rt" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }

  tags = {
    Name = "${var.app_name}-public-rt"
  }
}

resource "aws_route_table_association" "eb_public_rta_1" {
  subnet_id      = aws_subnet.eb_public_subnet_1.id
  route_table_id = aws_route_table.eb_public_rt.id
}

resource "aws_route_table_association" "eb_public_rta_2" {
  subnet_id      = aws_subnet.eb_public_subnet_2.id
  route_table_id = aws_route_table.eb_public_rt.id
}

# Security Group
resource "aws_security_group" "eb_sg" {
  name_prefix = "${var.app_name}-eb-sg"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.app_name}-eb-sg"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "go_app" {
  name = var.app_name

  tags = {
    Environment = var.environment
  }
}

# Elastic Beanstalk Application Version (upload your Go binary zip)
resource "aws_s3_bucket" "eb_app_bucket" {
  bucket = "${var.app_name}-eb-app-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_object" "go_app_version" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = "go-app-${var.app_version}.zip"
  source = var.go_app_zip_path # Path to your Go app zip file

  tags = {
    Name = "go-app-${var.app_version}"
  }
}

resource "aws_elastic_beanstalk_application_version" "go_app_version" {
  name    = "go-app-${var.app_version}"
  application = aws_elastic_beanstalk_application.go_app.name
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = aws_s3_object.go_app_version.key
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "go_env" {
  name                = "${var.app_name}-env"
  application         = aws_elastic_beanstalk_application.go_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17" # Go supported

  version_label = aws_elastic_beanstalk_application_version.go_app_version.name

  setting {
    namespace = "aws:ec2:vpc"
