  byte_length = 8
}

resource "aws_s3_object" "go_app_version" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = "go-app-${var.app_version}.zip"
  source = var.go_app_zip_path # Path to your Go app zip file

  tags = {
    Name = "go-app-${var.app_version}"
  }
}

resource "aws_elastic_beanstalk_application_version" "go_app_version" {
  name    = "go-app-${var.app_version}"
  application = aws_elastic_beanstalk_application.go_app.name
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = aws_s3_object.go_app_version.key
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "go_env" {
  name                = "${var.app_name}-env"
  application         = aws_elastic_beanstalk_application.go_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17" # Go supported

  version_label = aws_elastic_beanstalk_application_version.go_app_version.name

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.eb_public_subnet_1.id},${aws_subnet.eb_public_subnet_2.id}"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = "${aws_subnet.eb_public_subnet_1.id},${aws_subnet.eb_public_subnet_2.id}"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "AssocPublicIp"
    value     = "true"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_sg.id
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "Port"
    value     = "8080"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/health"
  }

  setting {
    namespace = "aws:elasticbeanstalk:container:nodejs"
    name      = "ProxyServer"
    value     = "nginx"
  }

  # Go-specific platform configuration
  setting {
    namespace = "aws:elasticbeanstalk:container:go"
    name      = "AppServer"
    value     = "go"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "PORT"
    value     = "8080"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  depends_on = [aws_elastic_beanstalk_application_version.go_app_version]
}

# Output
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.go_env.cname
}

output "eb_environment_id" {
  value = aws_elastic_beanstalk_environment.go_env.id
}

# Variables
variable "app_name" {
  description = "Name of the Elastic Beanstalk application"
  type        = string
  default     = "go-beanstalk-app"
}

variable "environment" {
  description = "Environment name (dev/stage/prod)"
  type        = string
  default     = "dev"
}

variable "app_version" {
  description = "Application version"
  type        = string
  default     = "1.0.0"
}

variable "go_app_zip_path" {
  description = "Path to the Go application zip file"
  type        = string
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}
```

**Usage Notes:**
1. Set `go_app_zip_path` variable to path of your Go binary zip file
2. Build your Go app: `GOOS=linux GOARCH=amd64 go build -o main && zip app.zip main`
3. Apply with: `terraform init && terraform apply`
4. Access your app at the output `eb_environment_url`
5. The template includes VPC, security groups, auto-scaling, and Go platform configuration

