provider "aws" {
  region = "us-west-2"
}

# IAM role for Elastic Beanstalk service
resource "aws_iam_role" "beanstalk_service" {
  name = "aws-elasticbeanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "beanstalk_service_enhanced" {
  role       = aws_iam_role.beanstalk_service.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedServer"
}

resource "aws_iam_role_policy_attachment" "beanstalk_service_managed" {
  role       = aws_iam_role.beanstalk_service.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

# IAM instance profile for EC2 instances
resource "aws_iam_role" "beanstalk_worker" {
  name = "aws-elasticbeanstalk-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "beanstalk_worker_enhanced" {
  role       = aws_iam_role.beanstalk_worker.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "beanstalk_worker" {
  name = "aws-elasticbeanstalk-ec2-instance-profile"
  role = aws_iam_role.beanstalk_worker.name
}

# S3 bucket for application versions
resource "aws_s3_bucket" "beanstalk_app_versions" {
  bucket = "my-beanstalk-app-versions-${random_id.bucket_suffix.hex}"
}

