# Sample IAM role for CodeBuild project
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-sample-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy attachment for CodeBuild base policy
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

# CodeBuild project
resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn

  source {
    type     = "GITHUB"
    location = "https://github.com/your-org/your-repo.git"

    git_clone_depth = 1

    # OAuth token (use AWS Secrets Manager or environment variable in production)
    git_submodules_config {
      fetch_submodules = false
    }
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-oauth-token"  # Replace with actual token or use secrets
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "APP_NAME"
      value = "sample-app"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "ENVIRONMENT"
      value = "dev"
      type  = "PLAINTEXT"
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type  = "S3"
    location = aws_s3_bucket.cache.bucket
  }

  # Sample buildspec (inline)
  source_version = "main"

  build_timeout = 60

  tags = {
    Environment = "dev"
    Project     = "sample"
  }
}

# S3 bucket for CodeBuild cache
resource "aws_s3_bucket" "cache" {
  bucket = "sample-codebuild-cache-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Bucket versioning for cache
resource "aws_s3_bucket_versioning" "cache_versioning" {
  bucket = aws_s3_bucket.cache.id
  versioning_configuration {
    status = "Enabled"
  }
}
```

