# Data sources for account and region
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# CodeBuild project
resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn

  source {
    type     = "GITHUB"
    location = "https://github.com/yourusername/your-repo.git"

    git_clone_depth = 1

    auth {
      type            = "OAUTH"
      resource        = "arn:aws:codebuild:us-east-1:your-account:project:your-project-name"
      # Note: In production, use aws_codebuild_source_credential resource for OAuth token
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-token"  # Replace with actual token or use Secrets Manager
      type  = "PLAINTEXT"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/sample-project"
      stream_name = "sample-project-log-stream"
    }

    s3_logs {
      status   = "ENABLED"
      bucket   = "your-codebuild-logs-bucket"  # Create this S3 bucket separately
      prefix   = "codebuild/sample-project/"
    }
  }

  tags = {
    Environment = "dev"
  }
}

# CodeBuild source credential for GitHub (recommended for OAuth)
resource "aws_codebuild_source_credential" "github" {
  auth_type   = "OAUTH"
  server_type = "GITHUB"
  token       = "your-github-oauth-token"  # Replace with your GitHub OAuth token
}
```

**Note:** Before applying this configuration:
1. Replace `yourusername/your-repo.git` with your actual GitHub repository
2. Replace `your-account` in the auth resource ARN with your AWS account ID
3. Replace `your-github-token` and `your-github-oauth-token` with actual GitHub tokens
4. Create an S3 bucket named `your-codebuild-logs-bucket` for S3 logging
5. The `aws_codebuild_source_credential` resource manages GitHub OAuth tokens - create a Personal Access Token in GitHub with `repo` scope

