# Sample IAM role for CodeBuild project
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-sample-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy attachment for CodeBuild base policy
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

# Additional custom policy for S3 and CloudWatch access
resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "codebuild-custom-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::your-source-bucket/*",
          "arn:aws:s3:::your-source-bucket",
          "arn:aws:s3:::your-artifact-bucket/*",
          "arn:aws:s3:::your-artifact-bucket"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# CodeBuild project with secondary source configurations
resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with secondary sources"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    name = "sample-artifacts"
    location = "your-artifact-bucket"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "AWS_DEFAULT_REGION"
      value = "us-east-1"
    }
  }

  source {
    type     = "S3"
    location = "your-source-bucket/path/to/source.zip"
    buildspec = "buildspec.yml"
  }

  # Secondary source 1 - GitHub
  source_version = "main"

  secondary_sources {
    source_identifier = "github-source"

    source {
      type                = "GITHUB"
      location            = "https://github.com/your-org/secondary-repo.git"
      git_clone_depth     = 1
    }
  }

  # Secondary source 2 - Another S3 bucket
  secondary_sources {
    source_identifier = "s3-secondary"

    source {
      type     = "S3"
      location = "your-secondary-bucket/secondary-source.zip"
    }
  }

  # Secondary source 3 - Bitbucket
  secondary_sources {
    source_identifier = "bitbucket-source"

    source {
      type                = "BITBUCKET"
      location            = "https://bitbucket.org/your-workspace/secondary-repo.git"
      git_clone_depth     = 1
    }
  }

  cache {
    type  = "S3"
    location = "your-cache-bucket"
  }

  tags = {
    Environment = "dev"
    Project     = "sample"
  }
}

