# Sample IAM role for CodeBuild project
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-sample-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy attachment for CodeBuild base policy
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CodeBuildBasePolicy"
}

# Additional custom policy for CodeBuild (logs, S3 access, etc.)
resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "codebuild-custom-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:PutObjectVersionAcl"
        ]
        Resource = [
          "arn:aws:s3:::your-source-bucket/*",
          "arn:aws:s3:::your-artifact-bucket/*"
        ]
      }
    ]
  })
}

# CodeBuild project
resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with batch configuration"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false
  }

  source {
    type      = "NO_SOURCE"
    buildspec = <<EOF
version: 0.2

phases:
  pre_build:
    commands:
      - echo Logging in to Amazon ECR...
      - aws ecr get-login-password --region $AWS_DEFAULT_REGION | docker login --username AWS --password-stdin $ACCOUNT_ID.dkr.ecr.$AWS_DEFAULT_REGION.amazonaws.com
  build:
    commands:
      - echo Build started...
      - echo Building the Docker image...
      - docker build -t $REPOSITORY_URI:latest .
      - docker tag $REPOSITORY_URI:latest $REPOSITORY_URI:$IMAGE_TAG
  post_build:
    commands:
      - echo Build completed...
EOF
  }

  # Build batch configuration
  build_batch_config {
    service_role = aws_iam_role.codebuild_role.arn
    timeout_in_minutes = 60

    batch_timeout_in_minutes = 60
    combine_build_spec_from_projects = false

    restrictions {
      maximum_age_in_minutes = 60
      compute_types_allowed  = ["BUILD_GENERAL1_SMALL"]
    }
  }

  tags = {
    Environment = "dev"
  }
}
```

