provider "aws" {
  region = "us-east-1"
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_basic" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lex Bot
resource "aws_lex_bot" "chatbot" {
  name                        = "MyChatbot"
  description                 = "Sample AWS Lex chatbot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  process_behavior            = "BUILD"
  idle_session_ttl_in_seconds = 300
  child_directed             = false

  locale_configuration {
    locale             = "en_US"
    description        = "English (US) locale"
    nlu_confidence_threshold = 0.25

    voice_settings {
      voice_id = "Joanna"
    }
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I didn't understand that. Please try again."
    }
  }
}

# Lex Bot Version
resource "aws_lex_bot_version" "chatbot_version" {
  bot_version_locale_specification {
    source_bot_version_locale_specification {
      locale_specification = {
        "en_US" = {
          source_bot_version = "1"
          source_locale      = "en_US"
        }
      }
    }
    locale_id = "en_US"
  }

  bot_id             = aws_lex_bot.chatbot.id
  bot_version_locale_specification {
    locale_id = "en_US"
  }
  depends_on = [aws_lex_bot.chatbot]
}

# Lex Intent
resource "aws_lex_intent" "greeting_intent" {
  name = "GreetingIntent"

  sample_utterances {
    utterance = "hello"
  }

  sample_utterances {
    utterance = "hi"
  }

  sample_utterances {
    utterance = "hey"
  }

  fulfillment_activity {
    type = "ReturnParameters"

    code_hook {
      message_version = "1.0"
      uri             = "ASK"
    }
  }

  confirmation_statement {
    messages {
      content_type = "PlainText"
      content      = "Hello! How can I help you today?"
    }
    response_card {
      title  = "Welcome"
      subtitle = "How can I assist you?"
    }
  }

  rejection_statement {
    messages {
      content_type = "PlainText"
      content      = "I don't understand. Please try again."
    }
  }

  conclusion_statement {
    messages {
      content_type = "PlainText"
      content      = "Thank you for using our chatbot!"
    }
  }
}

# Lex Slot Type (optional - example)
resource "aws_lex_slot_type" "color_slot" {
  name          = "ColorType"
  version       = 1
  description   = "Color slot type"
  enumeration_value {
    value = "red"
  }
  enumeration_value {
    value = "blue"
  }
  enumeration_value {
    value = "green"
  }
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "chatbot_alias" {
  bot_version       = aws_lex_bot_version.chatbot_version.bot_version_locale_specification[0].source_bot_version_locale_specification[0].locale_specification["en_US"].source_bot_version
  bot_alias_name    = "prod"
  bot_id            = aws_lex_bot.chatbot.id
  description       = "Production alias"
  bot_languages {
    language_code = "en"
  }
}

# Lambda function for fulfillment (optional)
resource "aws_lambda_function" "lex_fulfillment" {
  filename      = "lambda.zip"  # You'll need to create this file
  function_name = "lex-fulfillment-function"
  role          = aws_iam_role.lex_bot_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      BOT_ALIAS = aws_lex_bot_alias.chatbot_alias.bot_alias_name
    }
  }
}

# Lambda permission for Lex
resource "aws_lambda_permission" "lex_invoke" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.lex_fulfillment.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = aws_lex_bot.chatbot.arn
}

output "bot_id" {
  value = aws_lex_bot.chatbot.id
}

output "bot_alias_id" {
  value = aws_lex_bot_alias.chatbot_alias.bot_alias_id
}

output "bot_endpoint" {
  value = aws_lex_bot_alias.chatbot_alias.bot_alias_locale_settings["en_US"].bot_alias_locale_settings[0].endpoint
}

