provider "aws" {
  region = "us-east-1"
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_basic" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexFullAccess"
}

# Lex Intent: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name                        = "OrderPizza"
  description                 = "Intent for ordering pizza"
  confirmation_prompt {
    messages {
      content_type = "PlainText"
      content      = "You want a pizza with ${aws_lex_slot.pizza_toppings.name}? Is that correct?"
    }
    max_attempts = 3
  }
  fulfillment_activity {
    type = "ReturnIntent"
    code_hook {
      message_version = "1.0"
      uri             = "arn:aws:lambda:us-east-1:123456789012:function:LexPizzaHandler" # Replace with your Lambda ARN
    }
  }
  rejection_statement {
    messages {
      content_type = "PlainText"
      content      = "I don't understand that. Please try again."
    }
  }

  slot {
    name           = aws_lex_slot.pizza_toppings.name
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_toppings.name
    priority       = 1
    message {
      content_type = "PlainText"
      content      = "What toppings would you like on your pizza?"
    }
    response_card {
      version         = 1
      content_type    = "application/vnd.amazonaws.card.generic"
      generic_attachments {
        title       = "Choose toppings"
        sub_title   = "Select your pizza toppings"
        image_url   = "https://example.com/pizza.jpg"
        attachment_link_url = "https://example.com/menu"
      }
    }
  }
}

# Lex Slot Type: PizzaToppings
resource "aws_lex_slot_type" "pizza_toppings" {
  name         = "PizzaToppings"
  description  = "Common pizza toppings"
  value_selection_strategy = "ORIGINAL_VALUE"
  enumeration_value {
    name = "pepperoni"
  }
  enumeration_value {
    name = "mushrooms"
  }
  enumeration_value {
    name = "onions"
  }
  enumeration_value {
    name = "sausage"
  }
  enumeration_value {
    name = "extra-cheese"
  }
}

# Lex Slot: pizzaToppings
resource "aws_lex_slot" "pizza_toppings" {
  intent_name = aws_lex_intent.order_pizza.name
  name        = "pizzaToppings"
  slot_type   = aws_lex_slot_type.pizza_toppings.name
  slot_constraint = "Required"
  priority    = 1
}

# Lex Intent: FollowUpDrink (subsequent follow-up prompt)
resource "aws_lex_intent" "follow_up_drink" {
  name                        = "FollowUpDrink"
  description                 = "Follow-up intent for drink order after pizza"
  confirmation_prompt {
    messages {
      content_type = "PlainText"
      content      = "Great! Would you like a drink with that pizza? ${aws_lex_slot.drink_type.name}?"
    }
    max_attempts = 2
  }
  fulfillment_activity {
    type = "ReturnIntent"
    code_hook {
      message_version = "1.0"
      uri             = "arn:aws:lambda:us-east-1:123456789012:function:LexPizzaHandler" # Replace with your Lambda ARN
    }
  }
  rejection_statement {
    messages {
      content_type = "PlainText"
      content      = "No problem! Anything else I can help with?"
    }
  }

  parent_intent_signature = aws_lex_intent.order_pizza.name # Links as follow-up

  slot {
    name           = aws_lex_slot.drink_type.name
    slot_constraint = "Optional"
    slot_type      = aws_lex_slot_type.drink_type.name
    priority       = 1
    message {
      content_type = "PlainText"
      content      = "What drink would you like? Beer, soda, or water?"
    }
  }
}

# Lex Slot Type: DrinkType
resource "aws_lex_slot_type" "drink_type" {
  name         = "DrinkType"
