}

# Lex Slot: drinkType
resource "aws_lex_slot" "drink_type" {
  intent_name = aws_lex_intent.follow_up_drink.name
  name        = "drinkType"
  slot_type   = aws_lex_slot_type.drink_type.name
  slot_constraint = "Optional"
  priority    = 1
}

# Lex Bot: PizzaBot
resource "aws_lex_bot" "pizza_bot" {
  name                               = "PizzaBot"
  description                        = "Pizza ordering bot with follow-up drink prompt"
  abort_statement {
    messages {
      content_type = "PlainText"
      content      = "Sorry, I didn't get that. Goodbye."
    }
  }
  failure_restarting_description = "Ask again"
  idle_session_ttl_in_seconds    = 300
  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }
  intent {
    intent_name    = aws_lex_intent.follow_up_drink.name
    intent_version = "1"
  }
  locale_configuration {
    locale       = "en_US"
    voice_id     = "Joanna"
    nlu_confidence_threshold = 0.65
  }
  session_timeout_seconds = 1800
  time_zone = "America/New_York"

  depends_on = [
    aws_iam_role_policy_attachment.lex_basic,
    aws_lex_intent.order_pizza,
    aws_lex_intent.follow_up_drink
  ]
}

# Lex Bot Version (for production)
resource "aws_lex_bot_version" "pizza_bot_version" {
  bot_name               = aws_lex_bot.pizza_bot.name
  bot_version_locale_specification {
    source_bot_version = "DRAFT"
    locale             = "en_US"
  }
  depends_on = [aws_lex_bot.pizza_bot]
}

# Lex Bot Alias (LIVE)
resource "aws_lex_bot_alias" "pizza_bot_live" {
  bot_name              = aws_lex_bot.pizza_bot.name
  bot_version           = aws_lex_bot_version.pizza_bot_version.version
  bot_alias_locale_specification {
    bot_alias_locale_setting {
      locale              = "en_US"
      bot_version         = aws_lex_bot_version.pizza_bot_version.version
      sort_by             = "LambdaLastUpdatedTime"
      welcome_message {
        content_type = "PlainText"
        content      = "Welcome to PizzaBot! What kind of pizza would you like to order?"
      }
      conversation_log_settings {
        log_settings {
          destination = "CLOUDWATCH_LOGS"
          resource_arn = "arn:aws:logs:us-east-1:123456789012:log-group:/aws/lex/pizzabot:*" # Replace with your CloudWatch log group
        }
      }
    }
  }
  name = "LIVE"
}

