provider "aws" {
  region = "us-east-1"
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "LexBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Sample Lambda function for fulfillment (pizza order processing)
resource "aws_lambda_function" "pizza_fulfillment" {
  filename         = "pizza_fulfillment.zip"
  function_name    = "pizza_fulfillment"
  role            = aws_iam_role.lex_bot_role.arn
  handler         = "index.handler"
  runtime         = "nodejs18.x"
  timeout         = 30

  environment {
    variables = {
      CLOSING_MESSAGE = "Thank you for your pizza order! Here's your summary: {orderSummary}. Your pizza will be ready in 30 minutes."
    }
  }
}

resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_fulfillment.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = aws_lex_bot.pizza_ordering.arn
}

# Intent: OrderPizza
resource "aws_lex_bot" "pizza_ordering" {
  name                               = "PizzaOrderBot"
  description                        = "Bot for handling pizza orders"
  idle_session_ttl_in_seconds        = 300
  voice_id                           = "Joanna"
  process_flow_timeout_retry_in_seconds = [24]

  intent {
    name = "OrderPizza"
    fulfillment_activity {
      type = "LambdaFulfillment"
      lambda {
        function_arn = aws_lambda_function.pizza_fulfillment.arn
      }
    }
  }

  intent {
    name = "AMAZON.CancelIntent"
  }

  intent {
    name = "AMAZON.HelpIntent"
  }

  intent {
    name = "AMAZON.StopIntent"
  }

  slot_type {
    name = "PizzaSize"
    value = jsonencode([
      { name = { value = "small" }, synonyms = ["s", "small size"] },
      { name = { value = "medium" }, synonyms = ["m", "medium size"] },
      { name = { value = "large" }, synonyms = ["l", "large size"] },
      { name = { value = "extra large" }, synonyms = ["xl", "extra large"] }
    ])
  }

  slot_type {
    name = "PizzaTopping"
    value = jsonencode([
      { name = { value = "pepperoni" }, synonyms = ["pep", "pepperoni"] },
      { name = { value = "cheese" }, synonyms = ["just cheese"] },
      { name = { value = "mushroom" }, synonyms = ["mushrooms", "mush"] },
      { name = { value = "sausage" }, synonyms = ["italian sausage"] },
      { name = { value = "veggie" }, synonyms = ["vegetables", "veggie"] }
    ])
  }

  version {
    name = "1"
  }
}

# Bot version alias
resource "aws_lex_bot_alias" "pizza_ordering_alias" {
  bot_name       = aws_lex_bot.pizza_ordering.name
  bot_version    = "1"
  name           = "Prod"

  bot_languages {
    language_code = "en_US"
    intent {
      name = "OrderPizza"
      priority = 1
    }
  }
}

# Lex Bot Policy
resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "LexBotPolicy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "lambda:InvokeFunction"
        ]
        Resource = aws_lambda_function.pizza_fulfillment.arn
      }
    ]
  })
}

output "bot_arn" {
  value = aws_lex_bot_alias.pizza_ordering_alias.arn
}

output "bot_alias_id" {
  value = aws_lex_bot_alias.pizza_ordering_alias.id
}

