provider "aws" {
  region = "us-east-1"
}

# Lex Bot for Pizza Ordering
resource "aws_lex_bot" "pizza_order_bot" {
  name                               = "PizzaOrderBot"
  description                        = "Lex bot for ordering pizza"
  role_arn                           = aws_iam_role.lex_bot_role.arn
  process_flow_role_arn              = aws_iam_role.lex_bot_role.arn
  idle_session_ttl_in_seconds        = 300
  child_directed                     = false
  detect_sentiment                   = false
  enable_data_logging                = false
  create_version                     = true

  abort_statement {
    message {
      content    = "Sorry, I couldn't process your request. Goodbye."
      content_type = "PlainText"
    }
  }

  # Intent: OrderPizza
  intent {
    name = "OrderPizza"
    fulfillment_activity {
      type = "ReturnParameters"
      code_hook {
        message_version = "1.0"
        uri             = "AWS_LAMBDA_FUNCTION_VERSION:AWS:Lambda#DefaultVersion"
      }
    }
  }

  # Intent: OrderPizzaSize
  intent {
    name = "OrderPizzaSize"
    fulfillment_activity {
      type = "ReturnParameters"
    }
  }

  # Intent: OrderPizzaToppings
  intent {
    name = "OrderPizzaToppings"
    fulfillment_activity {
      type = "ReturnParameters"
    }
  }

  # Intent: OrderPizzaDelivery
  intent {
    name = "OrderPizzaDelivery"
    fulfillment_activity {
      type = "ReturnParameters"
    }
  }

  # Intent: ConfirmOrder
  intent {
    name = "ConfirmOrder"
    fulfillment_activity {
      type = "ReturnParameters"
    }
  }
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexFullAccess"
}

# Lex Bot Alias (latest version)
resource "aws_lex_bot_alias" "pizza_order_bot_alias" {
  bot_name            = aws_lex_bot.pizza_order_bot.id
  bot_version         = aws_lex_bot.pizza_order_bot.version
  bot_alias_name      = "PizzaOrderProd"
  description         = "Production alias for Pizza Order Bot"

  conversation_log_configuration {
    log_group_name = aws_cloudwatch_log_group.lex_bot_logs.name
    log_settings {
      enabled = true
      destination {
        cloudwatch_logs {
          log_group_arn = aws_cloudwatch_log_group.lex_bot_logs.arn
        }
      }
    }
  }
}

# CloudWatch Log Group for Lex
