provider "aws" {
  region = "us-east-1"
}

# Lambda execution role
resource "aws_iam_role" "lambda_exec_role" {
  name = "lex-pizza-lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Lambda execution role policy attachment
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda function for pizza order fulfillment
resource "aws_lambda_function" "pizza_order_handler" {
  filename         = "pizza_handler.zip"
  function_name    = "pizza-order-handler"
  role            = aws_iam_role.lambda_exec_role.arn
  handler         = "index.handler"
  runtime         = "nodejs18.x"
  source_code_hash = filebase64sha256("pizza_handler.zip")

  environment {
    variables = {
      ORDER_CONFIRMATION = "Your pizza order has been placed successfully!"
    }
  }
}

# Lambda permission for Lex to invoke
resource "aws_lambda_permission" "lex_invoke" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_handler.function_name
  principal     = "lex.amazonaws.com"
}

# Lex Bot
resource "aws_lex_bot" "pizza_order_bot" {
  name                               = "PizzaOrderBot"
  description                        = "Bot for handling pizza orders"
  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I couldn't process that. Goodbye!"
    }
  }
  create_version                     = true
  idle_session_ttl_in_seconds        = 300
  process_behavior                   = "BUILD"
  voice_id                           = "Joanna"

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }

  locale_configuration {
    locale          = "en_US"
    voice_settings {
      voice_id = "Joanna"
    }
  }
}

# Lex Intent for ordering pizza
resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  fulfillment_activity {
    type = "LambdaFulfillment"
    code_hook {
      message_version = "1.0"
      lambda_function_arn = aws_lambda_function.pizza_order_handler.arn
    }
  }

  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Can I get a pizza"
  }
  sample_utterances {
    utterance = "Order pizza"
  }

  slot {
    name {
      name = "PizzaSize"
      slot_constraint = "Required"
      slot_type = "AMAZON.Size"
      value_elicitation_prompt {
        messages {
          content_type = "PlainText"
          content      = "What size pizza would you like?"
        }
      }
    }
  }

  slot {
    name {
      name = "PizzaToppings"
      slot_constraint = "Optional"
      slot_type = "AMAZON.Food"
      value_elicitation_prompt {
        messages {
          content_type = "PlainText"
          content      = "What toppings would you like on your pizza?"
        }
      }
    }
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Great! Processing your pizza order now."
    }
  }
}

# Lex Bot Version Alias
resource "aws_lex_bot_alias" "pizza_order_alias" {
  bot_name       = aws_lex_bot.pizza_order_bot.name
  bot_version    = aws_lex_bot.pizza_order_bot.version
  name           = "PizzaOrderAlias"
  description    = "Production alias for pizza order bot"

  bot_alias_locale_settings {
    locale_name        = "en_US"
    bot_alias_locale_status = "ACTIVE"
    bot_version        = aws_lex_bot.pizza_order_bot.version
  }
}
```

**Note:** This configuration assumes you have a `pizza_handler.zip` file containing a Lambda function (Node.js) with an `index.handler` export. The Lambda should handle Lex fulfillment requests and return appropriate responses. Create a simple Lambda function that processes pizza order slots and returns fulfillment messages.

