provider "aws" {
  region = "us-east-1"
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "LexBotExecutionRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "LexBotPolicy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lex V2 Bot
resource "aws_lexv2models_bot" "kids_bot" {
  bot_name               = "KidsFunBot"
  role_arn               = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = true
  }
  idle_session_ttl_in_seconds = 300
  bot_tags = {
    Environment = "production"
    Audience    = "kids"
  }
}

# Bot version (alias for production)
resource "aws_lexv2models_bot_version" "kids_bot_version" {
  bot_id     = aws_lexv2models_bot.kids_bot.id
  description = "Initial version for kids bot"
}

resource "aws_lexv2models_bot_alias" "kids_bot_alias" {
  bot_id             = aws_lexv2models_bot.kids_bot.id
  bot_alias_id       = "TSTALIASID"
  bot_version        = aws_lexv2models_bot_version.kids_bot_version.bot_version

  bot_alias_locale_settings {
    locale_id          = "en_US"
    bot_alias_locale_status = "Building"
    bot_version = aws_lexv2models_bot_version.kids_bot_version.bot_version
  }
}

# Sample Intent (HelloIntent for kids)
resource "aws_lexv2models_intent" "hello_intent" {
  intent_name = "HelloIntent"
  description = "Simple greeting intent for kids"
  input_contexts {
    name = "greeting"
  }
  sample_utterances {
    utterance = "hello"
  }
  sample_utterances {
    utterance = "hi"
  }
  sample_utterances {
    utterance = "hey"
  }
  dialog_code_hook {
    enabled = false
  }
  fulfillment_code_hook {
    enabled = false
  }
  intent_closing_setting {
    closing_response {
      message_groups {
        message = "Bye bye! Have fun playing! 🎉"
      }
    }
  }
}

# Sample Bot Locale for en_US
resource "aws_lexv2models_bot_locale" "kids_bot_locale" {
  bot_id            = aws_lexv2models_bot.kids_bot.id
  bot_alias_id      = aws_lexv2models_bot_alias.kids_bot_alias.id
  locale_id         = "en_US"
  description       = "English locale for kids bot"
  nlu_confidence_threshold = 0.7
  voice_settings {
    voice_id = "Joanna"
  }

  intent {
    intent_id   = aws_lexv2models_intent.hello_intent.id
    intent_name = aws_lexv2models_intent.hello_intent.intent_name
  }
}

