terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Example Amazon Connect instance
resource "aws_connect_instance" "example" {
  identity_management_type = "CONNECT_MANAGED"
  inbound_calls_enabled    = true
  instance_alias           = "example-instance"
}

# Example Lex bot (V1)
resource "aws_lex_bot" "example" {
  name             = "ExampleBot"
  abort_statement {
    message {
      content    = "Sorry, I could not process that."
      content_type = "PlainText"
    }
  }
  # Additional bot configuration...
}

# Example Lex bot (V2)
resource "aws_lex_bot_v2" "example" {
  name                        = "ExampleBotV2"
  description                 = "Example Lex V2 Bot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  idle_session_ttl_in_seconds = 300

  bot_locale {
    locale_id       = "en_US"
    description     = "English (US)"
    nlu_confidence_threshold = 0.25
  }
}

# IAM role for Lex bot (required for V2)
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# AWS Connect Bot Association
resource "aws_connect_bot_association" "example" {
  instance_id = aws_connect_instance.example.id
  lex_bots {
    lex_region    = "us-east-1"
    lex_bot_name  = aws_lex_bot.example.name
    lex_bot_alias = "TSTALIASID"  # Replace with actual alias ID
  }

  # For Lex V2 bot
  lex_bots {
    lex_region     = "us-east-1"
    lex_bot_name   = aws_lex_bot_v2.example.name
    lex_bot_alias  = "$LATEST"  # or specific alias ID
    lex_locale_id  = "en_US"
  }
}
```

**Note:** Replace `TSTALIASID` with the actual Lex bot alias ID. For production use, add proper IAM policies to the Lex role and complete the Lex bot configurations with intents, slots, and utterances. The `lex_bots` block supports both Lex V1 and V2 bots.

