  name = "simple-analytics-app"

  inputs {
    name_prefix = "input-"

    kinesis_firehose_input {
      resource_arn = aws_kinesis_stream.input_stream.arn
    }

    processing_configuration {
      zeppelin_application_configuration {
        monitoring_configuration {
          log_level = "INFO"
        }

        custom_artifacts_configuration {
          artifact_type = "UDF"
          s3_content_location {
            bucket_arn = "arn:aws:s3:::your-bucket"  # Replace with your S3 bucket
            file_key   = "udf.jar"                   # Replace with your UDF JAR file
          }
        }
      }
    }
  }

  outputs {
    name = "output-"

    kinesis_stream_output {
      resource_arn = aws_kinesis_stream.output_stream.arn
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_group.analytics.arn
  }
}

# Output Kinesis Stream
