provider "aws" {
  region = "us-east-1"
}

# Kinesis stream as input (for demo purposes)
resource "aws_kinesis_stream" "input_stream" {
  name             = "kinesis-analytics-input-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes",
  ]
}

# Kinesis stream as output (for demo purposes)
resource "aws_kinesis_stream" "output_stream" {
  name             = "kinesis-analytics-output-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
