# IAM role for Kinesis Analytics V2 application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-v2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
