# IAM policy for Kinesis access
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStreamSummary",
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:SubscribeToShard"
        ]
        Resource = [
          aws_kinesis_stream.input_stream.arn,
          aws_kinesis_stream.output_stream.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.output_stream.arn
      }
    ]
  })
}

# Simple Flink application code (pass-through)
resource "local_file" "flink_application_code" {
  content = <<EOF
import org.apache.flink.api.common.functions.MapFunction;
import org.apache.flink.streaming.api.datastream.DataStream;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;
import org.apache.flink.streaming.connectors.kinesis.FlinkKinesisConsumer;
import org.apache.flink.streaming.connectors.kinesis.FlinkKinesisProducer;

public class SimpleFlinkApp {
    public static void main(String[] args) throws Exception {
        StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        Properties consumerConfig = new Properties();
        consumerConfig.setProperty("aws.region", "us-east-1");

        DataStream<String> inputStream = env.addSource(
            new FlinkKinesisConsumer<>("${aws_kinesis_stream.input_stream.name}", 
                                     new SimpleStringSchema(), consumerConfig));

        inputStream.addSink(new FlinkKinesisProducer<>(new SimpleStringSchema()));

        env.execute("Simple Kinesis Analytics V2 Flink App");
    }
}
EOF
  filename         = "SimpleFlinkApp.java"
}

# Upload Flink application code to S3 (required for V2)
resource "aws_s3_bucket" "flink_code_bucket" {
  bucket = "kinesis-analytics-flink-code-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_object" "flink_application_code" {
  bucket = aws_s3_bucket.flink_code_bucket.id
  key    = "SimpleFlinkApp.jar"
  source = "SimpleFlinkApp.jar"  # Note: Pre-compile JAR needed in practice
  etag   = filemd5("SimpleFlinkApp.jar")
}

# Kinesis Analytics V2 Application
resource "aws_kinesisanalyticsv2_application" "flink_app" {
  name                   = "simple-flink-analytics-app"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        metrics_level      = "TASK_MANAGER_METRICS"
        log_level          = "INFO"
      }

      parallelism_configuration {
        configuration_type = "CUSTOM"
        parallel_group_count = 1
      }
    }

    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.flink_code_bucket.arn
          file_key   = aws_s3_object.flink_application_code.key
        }
      }
      code_content_type = "ZIPFILE"
    }

    environment_properties {
      property_group {
        property_group_id = "KinesisAnalytics"
        property_map = {
          "InputStream" = aws_kinesis_stream.input_stream.name
          "OutputStream" = aws_kinesis_stream.output_stream.name
          "Region" = "us-east-1"
        }
      }
    }
  }

  application_mode = "STREAMING"

  tags = {
    Name = "Simple Flink Analytics App"
  }
}

output "kinesis_analytics_app_arn" {
  value = aws_kinesisanalyticsv2_application.flink_app.arn
}

output "input_stream_name" {
  value = aws_kinesis_stream.input_stream.name
}

output "output_stream_name" {
  value = aws_kinesis_stream.output_stream.name
}
```

**Note**: This configuration creates a complete Kinesis Analytics V2 Flink application infrastructure. In practice, you need to:

1. Compile the provided Java Flink code into a JAR file
2. Upload the JAR to the S3 bucket (replace `SimpleFlinkApp.jar` with your actual compiled JAR)
3. The application performs a simple pass-through from input to output stream
4. Update IAM policies and Flink code as needed for your specific business logic

