      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for Firehose to write to S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Kinesis Data Firehose Delivery Stream with Extended S3 Destination and Dynamic Partitioning
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name = "my-extended-s3-firehose-stream"

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_bucket.arn
    prefix             = "data/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_prefix       = "errors/!{timestamp:yyyy/MM/dd/HH}/"
    buffer_size        = 5
    buffer_interval    = 300
  }

  extended_s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_bucket.arn

    # Dynamic partitioning configuration
    dynamic_partitioning_configuration {
      enabled = true
    }

    prefix             = "dynamic/year=!{partitionKeyFromQuery:year}/month=!{partitionKeyFromQuery:month}/day=!{partitionKeyFromQuery:day}/"
    error_prefix       = "dynamic-errors/!{timestamp:yyyy/MM/dd/HH}/"

    buffering_size     = 15
    buffering_interval = 300

    # Processing configuration (optional, for data transformation)
    processing_configuration {
      enabled = true

      processors {
        type = "Lambda"
        parameters {
          parameter_name  = "LambdaFunctionArn"
          parameter_value = "arn:aws:lambda:us-east-1:123456789012:function:my-partition-transform-function"
        }
      }
    }

    # CloudWatch logging
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/my-extended-s3-firehose-stream"
      log_stream_name = "S3Delivery"
    }
  }

  tags = {
    Environment = "production"
  }
}

# CloudWatch Log Group for Firehose logging
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesis/firehose/my-extended-s3-firehose-stream"
  retention_in_days = 14
}

