provider "aws" {
  region = "us-east-1"
}

# VPC for Redshift cluster
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "kinesis-redshift-vpc"
  }
}

# Subnet for Redshift
resource "aws_subnet" "redshift_subnet" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet"
  }
}

# Redshift Security Group
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-kinesis-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-kinesis-sg"
  }
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-kinesis-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]
}

# Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier = "kinesis-redshift-cluster"
  database_name      = "kinesistest"
  master_username    = "admin"
  master_password    = "SuperSecretPassword123!"
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  skip_final_snapshot = true

  tags = {
    Name = "kinesis-redshift-cluster"
  }
}

# Redshift IAM Role for Firehose
resource "aws_iam_role" "firehose_redshift_role" {
  name = "firehose-redshift-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Redshift access
resource "aws_iam_role_policy" "firehose_redshift_policy" {
  name = "firehose-redshift-policy"
  role = aws_iam_role.firehose_redshift_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "redshift:DescribeClusters",
          "redshift-data:DescribeTable",
          "redshift-data:GetStatementResult"
        ]
        Resource = "*"
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "kinesis-firehose-redshift-stream"
  destination = "redshift"

  redshift_configuration {
    cluster_jdbcurl      = "jdbc:redshift://${aws_redshift_cluster.redshift_cluster.endpoint}/kinesistest"
    role_arn             = aws_iam_role.firehose_redshift_role.arn
    username             = "admin"
    password             = "SuperSecretPassword123!"
    database_name        = "kinesistest"
    table_name           = "kinesis_data_table"
    retry_duration       = 300
    copy_command {
      data_table_name = "kinesis_data_table"
      data_table_columns = "event_data"
    }
  }

  server_side_encryption {
    enabled = true
  }

  tags = {
    Name = "kinesis-firehose-redshift-stream"
  }

  depends_on = [aws_redshift_cluster.redshift_cluster]
}

# S3 Bucket for Firehose buffering and failed data
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "kinesis-firehose-redshift-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
