    volume_size = 10
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  tags = {
    Name = "firehose-opensearch"
  }
}

# IAM role for Firehose to access OpenSearch
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Firehose to write to OpenSearch
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        Resource = "${aws_opensearch_domain.firehose_opensearch.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain"
        ]
        Resource = aws_opensearch_domain.firehose_opensearch.arn
      }
    ]
  })
}

# Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-to-opensearch"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn        = aws_opensearch_domain.firehose_opensearch.arn
    index_name        = "firehose-index"
    role_arn          = aws_iam_role.firehose_role.arn
    retry_duration    = 300
    s3_backup_mode    = "FailedDataOnly"
    buffering_size    = 5
    buffering_interval = 300
  }

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffering_size     = 10
    buffering_interval = 400
    compression_format = "GZIP"
  }

  tags = {
    Name = "firehose-to-opensearch"
  }
}

# S3 bucket for failed data backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-opensearch-backup-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

