terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-east-1"
}

# IAM role for Firehose to publish logs to CloudWatch
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Policy for Firehose logging
resource "aws_iam_role_policy" "firehose_logging_policy" {
  name = "firehose-logging-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*"
      }
    ]
  })
}

# Splunk HTTP Event Collector endpoint (replace with your Splunk HEC details)
resource "aws_kinesis_firehose_delivery_stream" "splunk_firehose" {
  name        = "splunk-delivery-stream"
  destination = "http_endpoint"

  http_endpoint_destination {
    endpoint_configuration {
      url = "https://your-splunk-hec-endpoint:8088/services/collector/event/1.0"
      name = "splunk-http-endpoint"
    }

    # Splunk HEC token (use AWS Secrets Manager in production)
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/splunk-firehose"
      log_stream_name = "S3Delivery"
    }

    # HTTP configuration for Splunk HEC
    http_endpoint_configuration {
      access_key = "your-splunk-hec-token"  # Store securely in Secrets Manager
    }

    request_configuration {
      content_encoding = "GZIP"

      common_attributes = [
        {
          attribute_name  = "X-Splunk-HEC-Token"
          attribute_value = "your-splunk-hec-token"
        },
        {
          attribute_name  = "X-Splunk-HEC-Index"
          attribute_value = "main"  # or your specific index
        },
        {
          attribute_name  = "X-Splunk-HEC-Source"
          attribute_value = "kinesis-firehose"
        },
        {
          attribute_name  = "X-Splunk-HEC-Sourcetype"
          attribute_value = "aws:kinesis"
        }
      ]
    }

    # Retry and S3 backup configuration
    s3_backup_mode = "FailedDataOnly"
    buffering_hints {
      size_in_mbs   = 1
      interval_in_seconds = 60
    }
    retry_options {
      duration_in_seconds = 300
    }
  }

  # Server-side encryption (optional)
  server_side_encryption {
    key_arn           = aws_kms_key.firehose_kms.arn
    key_id            = aws_kms_key.firehose_kms.key_id
    kms_key_rotation_enabled = true
  }

  # Processing configuration (optional data transformation)
  processing_configuration {
    enabled = true

    processing_defaults {
      type = "Lambda"

      lambda {
        function_arn = "arn:aws:lambda:us-east-1:123456789012:function:my-transform-function"
      }
    }
  }

  # Backup S3 bucket for failed deliveries
  depends_on = [aws_iam_role_policy.firehose_logging_policy]
}

# KMS key for encryption (optional but recommended)
resource "aws_kms_key" "firehose_kms" {
  description             = "KMS key for Kinesis Firehose encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

resource "aws_kms_alias" "firehose_kms_alias" {
  name          = "alias/firehose-splunk-key"
  target_key_id = aws_kms_key.firehose_kms.key_id
}

# S3 bucket for failed data backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "splunk-firehose-backup-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "firehose_backup_versioning" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup_encryption" {
  bucket = aws_s3_bucket.firehose_backup.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.firehose_kms.arn
      sse_algorithm     = "aws:kms"
    }
  }
}

# Output the Firehose stream ARN
output "firehose_stream_arn" {
  value = aws_kinesis_firehose_delivery_stream.splunk_firehose.arn
}

output "firehose_stream_name" {
  value = aws_kinesis_firehose_delivery_stream.splunk_firehose.name
}

