# Terraform configuration for Amazon Kinesis Data Firehose delivery stream
# to Amazon OpenSearch Service within a VPC

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "kinesis-firehose-vpc"
  }
}

# Subnets (private for OpenSearch)
resource "aws_subnet" "private" {
  count = 2

  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "kinesis-firehose-private-${count.index + 1}"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "kinesis-firehose-igw"
  }
}

# NAT Gateway for outbound traffic
resource "aws_eip" "nat" {
  domain = "vpc"

  tags = {
    Name = "kinesis-firehose-nat-eip"
  }
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public[0].id

  tags = {
    Name = "kinesis-firehose-nat"
  }

  depends_on = [aws_internet_gateway.main]
}

# Public subnet for NAT Gateway
resource "aws_subnet" "public" {
  count = 1

  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.0.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "kinesis-firehose-public"
  }
}

# Route tables
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "kinesis-firehose-public-rt"
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }

  tags = {
    Name = "kinesis-firehose-private-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public[0].id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# Security Group for OpenSearch
resource "aws_security_group" "opensearch" {
  name_prefix = "kinesis-firehose-opensearch-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "kinesis-firehose-opensearch-sg"
  }
}

# OpenSearch Domain
resource "aws_opensearch_domain" "firehose_opensearch" {
  domain_name    = "kinesis-firehose-opensearch"
  engine_version = "OpenSearch_2.11"

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 2
    zone_awareness_enabled = true
  }

  vpc_options {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.opensearch.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp3"
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  tags = {
    Name = "kinesis-firehose-opensearch"
  }
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Firehose to access OpenSearch
resource "aws_iam_role_policy" "firehose_opensearch_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPost",
          "es:ESHttpPut",
          "es:ESHttpDelete"
        ]
        Resource = aws_opensearch_domain.firehose_opensearch.arn
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains"
        ]
        Resource = "*"
      }
    ]
  })
}

# Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "kinesis-firehose-opensearch-stream"
  destination = "opensearch"

  vpc_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.opensearch.id]
  }

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.firehose_opensearch.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-index"
    type_name  = "_doc"
    retry_duration = 300

    s3_backup_mode = "AllDocuments"
  }

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    prefix             = "firehose-backup/"
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "GZIP"
  }

  tags = {
    Name = "kinesis-firehose-opensearch-stream"
  }
}

# S3 Bucket for Firehose backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "kinesis-firehose-backup-${random_string.bucket_suffix.result}"

  tags = {
    Name = "Kinesis Firehose Backup"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

