# IAM Role for Kinesis Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Kinesis Analytics to read from Kinesis Stream
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStreamSummary",
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords"
        ]
        Resource = aws_kinesis_stream.analytics_input.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_caller_identity.current.account_id}:log-group:/aws/kinesis-analytics/*"
      }
    ]
  })
}

# Data source for AWS caller identity (used in policy)
data "aws_caller_identity" "current" {}

# Kinesis Analytics Application
resource "aws_kinesisanalytics_application" "simple_app" {
  name = "simple-analytics-app"

  inputs {
    name_prefix = "input-prefix"

    kinesis_firehose_input {
      resource_arn = aws_kinesis_stream.analytics_input.arn
    }

    parallelism {
      count = 1
    }

    processing_configuration {
      zeppelin_application_configuration {
        monitoring_configuration {
          log_level = "INFO"
          metrics_level = "APPLICATION"
        }

        custom_artifacts_configuration {
          s3_content_location {
            bucket_arn = "arn:aws:s3:::aws-kinesis-analytics-us-east-1-default-reference-data"  # Default reference data bucket
            file_key   = "schema.json"
          }
          artifact_type = "UDF"
        }
      }
    }

    schema {
      record_columns {
        name   = "fieldname1"
        sql_type = "VARCHAR(8)"
      }
      record_columns {
        name   = "fieldname2"
        sql_type = "INTEGER"
      }
      record_format {
        record_format_type = "CSV"
        mapping_parameters {
          csv {
            record_row_delimiter = "
"
            record_column_delimiter = ","
          }
        }
      }
      record_encoding = "UTF-8"
    }
  }

  outputs {
    name = "output-prefix"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.analytics_output.arn
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.analytics_log.arn
  }

  tags = {
    Name = "Simple Kinesis Analytics App"
  }

  depends_on = [aws_iam_role_policy.kinesis_analytics_policy]
}

# Kinesis Stream as output destination
resource "aws_kinesis_stream" "analytics_output" {
  name        = "analytics-output-stream"
  shard_count = 1

  tags = {
    Name = "Analytics Output Stream"
  }
}

# CloudWatch Log Group and Log Stream for analytics logs
resource "aws_cloudwatch_log_group" "analytics_log_group" {
  name              = "/aws/kinesis-analytics/simple-analytics-app"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "analytics_log" {
  name           = "analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.analytics_log_group.name
}

