        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.analytics_bucket.arn,
          "${aws_s3_bucket.analytics_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_caller_identity.current.account_id}:log-group:/aws/kinesis-analytics/*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# Kinesis Data Stream (input source)
resource "aws_kinesis_stream" "input_stream" {
  name             = "analytics-input-stream-${random_id.bucket_suffix.hex}"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes"
  ]
}

# Kinesis Data Stream (output destination)
resource "aws_kinesis_stream" "output_stream" {
  name             = "analytics-output-stream-${random_id.bucket_suffix.hex}"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes"
  ]
}

# Simple SQL application code
resource "local_file" "sql_application_code" {
  content = <<-EOT
    CREATE OR REPLACE STREAM "destination_sql_stream" (name VARCHAR(8), score BIGINT);

    CREATE OR REPLACE PUMP "stream_pump" AS
     INSERT INTO "destination_sql_stream"
     SELECT STREAM "name", "score" FROM SOURCE_SQL_STREAM_001;
  EOT
  filename = "${path.module}/kinesis_analytics_app.sql"
}

# Upload SQL application code to S3
resource "aws_s3_object" "application_code" {
  bucket = aws_s3_bucket.analytics_bucket.id
  key    = "kinesis_analytics_app.sql"
  source = local_file.sql_application_code.filename

  depends_on = [local_file.sql_application_code]
}

# Kinesis Analytics V2 Application
resource "aws_kinesisanalyticsv2_application" "sql_application" {
  name                   = "simple-sql-analytics-app-${random_id.bucket_suffix.hex}"
  runtime_environment    = "SQL-1_8"
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    sql_application_configuration {
      inputs {
        name_prefix = "SOURCE_SQL_STREAM"

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_row_path = "$"
              }
            }
          }

          record_encoding = "UTF-8"

          record_column {
            name   = "name"
            sql_type = "VARCHAR(8)"
            mapping = "$.name"
          }

          record_column {
            name   = "score"
            sql_type = "BIGINT"
            mapping = "$.score"
          }
        }

        input_parallelism {
          count = 1
        }

        input_starting_position_configuration {
          input_starting_position = "NOW"
        }

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
        }

        input_processing_configuration {
          input_lambda_processor {
            resource_arn = ""
          }
        }
      }

      outputs {
        name = "destination_sql_stream"

        kinesis_streams_output {
          resource_arn = aws_kinesis_stream.output_stream.arn
        }

        destination_schema {
          record_format_type = "JSON"
        }
      }

      reference_data_sources {
      }
    }

    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.analytics_bucket.arn
          file_key   = aws_s3_object.application_code.key
        }
      }
      code_content_type = "ZIPFILE" # SQL apps use ZIPFILE even for single SQL file
    }

    environment_properties {
      property_group {
        property_group_id = "KinesisAnalyticsV2"
        property_map      = {}
      }
    }
  }

  application_snapshot_configuration {
    snapshots_enabled = false
  }

  tags = {
    Name = "Simple SQL Analytics App"
  }
}

# CloudWatch Log Group for monitoring
resource "aws_cloudwatch_log_group" "analytics_logs" {
  name              = "/aws/kinesis-analytics/${aws_kinesisanalyticsv2_application.sql_application.name}"
  retention_in_days = 7
}

output "application_arn" {
  description = "ARN of the Kinesis Analytics V2 application"
  value       = aws_kinesisanalyticsv2_application.sql_application.arn
}

output "input_stream_arn" {
  description = "ARN of the input Kinesis stream"
  value       = aws_kinesis_stream.input_stream.arn
}

output "output_stream_arn" {
  description = "ARN of the output Kinesis stream"
  value       = aws_kinesis_stream.output_stream.arn
}

output "s3_bucket_name" {
  description = "Name of the S3 bucket containing application code"
  value       = aws_s3_bucket.analytics_bucket.bucket
}
```

