# IAM Policy for CloudWatch Logs access
resource "aws_iam_role_policy" "kinesis_analytics_logs_policy" {
  name = "kinesis-analytics-logs-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:CreateLogGroup",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams",
          "logs:DescribeLogGroups"
        ]
        Resource = aws_cloudwatch_log_group.kinesis_analytics_logs.arn
