terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# Assume an existing Kendra index
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  edition     = "DEVELOPER"
  role_arn    = aws_iam_role.kendra_role.arn

  # Additional configuration can be added here
}

resource "aws_iam_role" "kendra_role" {
  name = "kendra-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "kendra_basic" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraServiceRolePolicy"
}

resource "aws_kendra_data_source" "web_crawler" {
  index_id      = aws_kendra_index.example.id
  name          = "web-crawler-data-source"
  type          = "WEBCRAWLER"
  role_arn      = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_url_list = ["https://example.com"]
        }
      }

      inclusion_patterns {
        pattern = ["https://example.com/*"]
      }

      exclusion_patterns {
        pattern = [
          "https://example.com/admin/*",
          "https://example.com/login*",
          "*.pdf",
          "*.jpg",
          "*.png"
        ]
      }

      crawl_scope {
        field_mappings {
          data_source_field_name = "Metadata"
          date_field_mapping     = false
          index_field_name       = "source_uri"
        }
      }
    }
  }

  schedule {
    expression = "cron(0 19 ? * MON-FRI *)"
  }

  tags = {
    Environment = "production"
  }
}
