provider "aws" {
  region = "us-east-1"
}

# Hosted Zone (referred to as 'primary')
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# Primary Health Check
resource "aws_route53_health_check" "primary_health_check" {
  fqdn                      = "primary.example.com"
  port                      = 80
  type                      = "HTTP"
  request_interval          = 30
  failure_threshold         = 3
  measure_latency           = false
  cloudwatch_alarm_name     = ""
}

# Primary Record (Active)
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"
  set_identifier = "primary"

  failover_routing_policy {
    type = "PRIMARY"
  }

  health_check_id = aws_route53_health_check.primary_health_check.id

  records = ["192.0.2.1"]
  ttl     = 300
}

# Secondary Health Check
resource "aws_route53_health_check" "secondary_health_check" {
  fqdn                      = "secondary.example.com"
  port                      = 80
  type                      = "HTTP"
  request_interval          = 30
  failure_threshold         = 3
  measure_latency           = false
}

# Secondary Record (Passive)
resource "aws_route53_record" "secondary" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"
  set_identifier = "secondary"

  failover_routing_policy {
    type = "SECONDARY"
  }

  health_check_id = aws_route53_health_check.secondary_health_check.id

  records = ["192.0.2.2"]
  ttl     = 300
}

