resource "aws_route53_record" "secondary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "app.example.com"  # Same FQDN for active-active failover
  type    = "A"
  ttl     = 60
  records = ["192.0.2.2"]  # Replace with secondary IP or use alias
}

# Primary health check
resource "aws_route53_health_check" "primary_health_check" {
  fqdn                      = "primary.example.com"  # FQDN for primary health check
  port                      = 80
  type                      = "HTTP"
  resource_path             = "/"
  failure_threshold         = 3
  request_interval          = 30
  cloudwatch_alarm_name     = null  # Optional

  tags = {
    Name = "primary_health_check"
  }
}

# Secondary health check
resource "aws_route53_health_check" "secondary_health_check" {
  fqdn                      = "secondary.example.com"  # FQDN for secondary health check
  port                      = 80
  type                      = "HTTP"
  resource_path             = "/"
  failure_threshold         = 3
  request_interval          = 30

  tags = {
    Name = "secondary_health_check"
  }
}

# Primary failover record set
resource "aws_route53_record" "failover_primary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "failover-app.example.com"  # Failover FQDN
  type    = "A"
  ttl     = 60
  set_identifier = "primary"

  failover_routing_policy {
    type = "PRIMARY"
  }

  health_check_id = aws_route53_health_check.primary_health_check.id

  records = ["192.0.2.1"]  # Primary IP
}

# Secondary failover record set
resource "aws_route53_record" "failover_secondary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "failover-app.example.com"  # Same FQDN as primary failover
  type    = "A"
  ttl     = 60
  set_identifier = "secondary"

  failover_routing_policy {
