  }

  health_check_id = aws_route53_health_check.secondary_health_check.id

  records = ["192.0.2.2"]  # Secondary IP
}
```

**Notes:**
- Replace `example.com` with your actual domain and `main` hosted zone name
- Update FQDNs (`app.example.com`, `failover-app.example.com`, health check FQDNs) as needed
- Replace IP addresses with actual resources or use `alias` for ELBs/LBs
- Active-active failover typically uses weighted/geolocation routing; this shows standard PRIMARY/SECONDARY failover (active-passive). For true active-active, consider `weighted_routing_policy` instead:

```hcl
# Alternative: Weighted active-active with health checks
resource "aws_route53_record" "active_active_primary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "active-active.example.com"
  type    = "A"
  ttl     = 60
  set_identifier = "primary-weight-100"

  weighted_routing_policy {
    failure_threshold = 0
    weight            = 100
  }

  health_check_id = aws_route53_health_check.primary_health_check.id
  records         = ["192.0.2.1"]
}

resource "aws_route53_record" "active_active_secondary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "active-active.example.com"
  type    = "A"
  ttl     = 60
  set_identifier = "secondary-weight-100"

  weighted_routing_policy {
    failure_threshold = 0
    weight            = 100
  }

  health_check_id = aws_route53_health_check.secondary_health_check.id
  records         = ["192.0.2.2"]
}
```

