terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "bucket_suffix" {
  description = "Suffix for bucket names"
  type        = string
  default     = "test"
}

# CloudGoat data bucket - private with ObjectWriter ownership
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data" {
  bucket = aws_s3_bucket.cloudgoat_data.id

  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_data" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"

  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_data]
}

# Website data bucket with public access blocks and policy
resource "aws_s3_bucket" "website_data" {
  bucket = "website-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_public_access_block" "website_data" {
  bucket = aws_s3_bucket.website_data.id

  block_public_acls       = true
  block_public_policy     = false
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Upload order_data2.csv to website bucket
resource "aws_s3_object" "order_data" {
  bucket       = aws_s3_bucket.website_data.id
  key          = "order_data2.csv"
  source       = "order_data2.csv"
  content_type = "text/csv"
}

# Bucket policy allowing s3:PutObject for all principals
resource "aws_s3_bucket_policy" "website_data" {
  bucket = aws_s3_bucket.website_data.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.website_data.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.website_data]
}

