# Example ElastiCache cluster (Redis) for context - adjust as needed
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "example-rep-group"
  replication_group_description = "Example replication group"
  node_type                 = "cache.t4g.micro"
  port                      = 6379
  engine                    = "redis"
  engine_version            = "7.1"
  num_cache_clusters        = 1
  parameter_group_name      = aws_elasticache_parameter_group.example.id
  auth_token                 = "your-auth-token"  # Required for IAM auth
  transit_encryption_enabled = true

  # Enable IAM database authentication
  auth_token_update_strategy = "SET"
}

# Parameter group to enable IAM authentication
resource "aws_elasticache_parameter_group" "example" {
  family = "redis7.1"
  name   = "example-params"

  parameter {
    name  = "auth_token_update_strategy_type"
    value = "SET"
  }
}

# IAM user for ElastiCache authentication
resource "aws_elasticache_user" "iam_user" {
  user_id        = "iam-admin-user"
  user_name      = "iamadmin"
  engine         = "REDIS"
  access_string  = "on ~* &* +@all"
  passwords      = ["SecurePassword123!"]
  iam_authentication_enabled = true
}

# IAM authentication group to associate the user with the cluster
resource "aws_elasticache_user_group" "iam_group" {
  user_group_id = "iam-admin-group"
  engine        = "REDIS"
  user_ids      = [aws_elasticache_user.iam_user.user_id]
}

# Associate the user group with the replication group
resource "aws_elasticache_replication_group_user_group_association" "example" {
  replication_group_id = aws_elasticache_replication_group.example.id
  user_group_id        = aws_elasticache_user_group.iam_group.user_group_id
}

