terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Example ElastiCache replication group (required for user association)
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "example-rep-group"
  replication_group_description = "Example replication group"
  node_type                  = "cache.t3.micro"
  port                       = 6379
  engine                     = "redis"
  engine_version             = "7.0"
  num_cache_clusters         = 1
  parameter_group_name       = aws_elasticache_parameter_group.example.id
  security_group_ids         = [aws_security_group.example.id]
  subnet_group_name          = aws_elasticache_subnet_group.example.name
}

# Parameter group for Redis (required for user creation)
resource "aws_elasticache_parameter_group" "example" {
  family = "redis7"
  name   = "example-params"
}

# Security group
resource "aws_security_group" "example" {
  name_prefix = "elasticache-example"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port       = 6379
    to_port         = 6379
    protocol        = "tcp"
    cidr_blocks     = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# VPC and subnet group (required)
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "example" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_elasticache_subnet_group" "example" {
  name       = "example-subnet-group"
  subnet_ids = [aws_subnet.example.id]
}

# ElastiCache User with password
resource "aws_elasticache_user" "example" {
  user_id                    = "example-user"
  user_group_ids             = [aws_elasticache_user_group.example.user_group_id]
  engine                     = "REDIS"
  access_string              = "on ~* +@all"
  passwords                  = ["SecurePassword123!"]
  minimum_engine_version     = "6.2"
}

# User Group (required for user)
resource "aws_elasticache_user_group" "example" {
  user_group_id = "example-user-group"
  engine        = "REDIS"

  user_ids = [aws_elasticache_user.example.user_id]
}

# Associate user group with replication group
resource "aws_elasticache_replication_group_user_group_association" "example" {
  replication_group_id = aws_elasticache_replication_group.example.id
  user_group_id        = aws_elasticache_user_group.example.user_group_id
}
```

