terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Data source to reference the existing ElastiCache user
data "aws_elasticache_user" "existing_user" {
  user_id = "existing-user-id"  # Replace with the actual existing user ID
}

# Data source to reference the existing ElastiCache user group
data "aws_elasticache_user_group" "existing_group" {
  user_group_id = "existing-group-id"  # Replace with the actual existing group ID
}

# Resource to associate the existing user with the existing user group
resource "aws_elasticache_user_group_association" "user_group_link" {
  user_group_id = data.aws_elasticache_user_group.existing_group.user_group_id
  user_id       = data.aws_elasticache_user.existing_user.user_id
}
```

**Note:** Replace `"existing-user-id"` and `"existing-group-id"` with the actual IDs of your existing ElastiCache user and user group. Run `terraform apply` to create the association. The association is managed by Terraform and can be destroyed with `terraform destroy` if needed.

