provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "redshift-vpc"
  }
}

# Subnet for Redshift
resource "aws_subnet" "redshift_subnet" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "redshift-subnet"
  }
}

# Subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift cluster with one node
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier              = "redshift-cluster-1"
  database_name                   = "dev"
  master_username                 = "admin"
  master_password                 = "ChangeMe123!"  # Use secrets manager in production
  node_type                       = "dc2.large"
  number_of_nodes                 = 1
  cluster_subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.redshift_sg.id]
  cluster_type                    = "single-node"
  skip_final_snapshot             = true
  final_snapshot_identifier       = "redshift-final-snapshot"
  publicly_accessible             = true  # Set to false in production

  tags = {
    Name = "redshift-cluster"
  }
}

# Output cluster endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.redshift_cluster.endpoint
}

