  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

# Subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift cluster (2 nodes)
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "redshift-cluster"
  database_name           = "dev"
  master_username         = "admin"
  master_password         = "ChangeMe123!"
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]

  cluster_parameter_group_name = "default.redshift-1.0"

  skip_final_snapshot = true

  tags = {
    Name = "redshift-cluster"
  }
}

# Redshift endpoint authorization for account 012345678910
resource "aws_redshift_endpoint_authorization" "cluster_endpoint_auth" {
  cluster_identifier         = aws_redshift_cluster.redshift_cluster.id
  account                    = "012345678910"
  cluster_security_group_name = aws_security_group.redshift_sg.name

  depends_on = [aws_redshift_cluster.redshift_cluster]
}
