# Redshift Cluster (Single Node)
resource "aws_redshift_cluster" "single_node_cluster" {
  cluster_identifier      = "single-node-redshift-cluster"
  database_name           = "dev"
  master_username         = "admin"
  master_password         = "SuperSecurePassword123!"
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  automated_snapshot_retention_period = 7
  preferred_maintenance_window = "sun:23:00-sun:03:00"
  snapshot_schedule_identifier = aws_redshift_scheduled_action.snapshot_schedule.id

  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  subnet_group_name      = aws_redshift_subnet_group.redshift_subnet_group.name

  cluster_parameter_group_name = aws_redshift_parameter_group.default.id

  skip_final_snapshot = true

  tags = {
    Name = "single-node-redshift"
  }
}

# Parameter Group
resource "aws_redshift_parameter_group" "default" {
  name   = "redshift-parameter-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "false"
  }
}

# Scheduled Action for Snapshots every 12 hours (cron: every 12 hours)
resource "aws_redshift_scheduled_action" "snapshot_schedule" {
  name = "snapshot-every-12-hours"

  target_action {
    pause_cluster_message {
      cluster_identifier = aws_redshift_cluster.single_node_cluster.id
    }
  }

  schedule = "cron(0 */12 * * ? *)"

  iam_role_arn = aws_iam_role.redshift_scheduled_action_role.arn
}

# IAM Role for Scheduled Actions
resource "aws_iam_role" "redshift_scheduled_action_role" {
  name = "redshift-scheduled-action-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_scheduled_action_policy" {
  role       = aws_iam_role.redshift_scheduled_action_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRedshiftScheduledActionRolePolicy"
}

