  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-b"
  }
}

# Subnet group spanning both AZs
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security Group
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Parameter Group (multi-AZ fault tolerant)
resource "aws_redshift_parameter_group" "redshift_param_group" {
  name   = "redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_audit_logging"
    value = "true"
  }

  tags = {
    Name = "redshift-param-group"
  }
}

# Redshift Cluster (Multi-AZ deployment for fault tolerance)
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "fault-tolerant-redshift-cluster"
  database_name           = "redshiftdb"
  master_username         = "admin"
  master_password         = "SecurePassword123!"
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 4
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  cluster_parameter_group_name = aws_redshift_parameter_group.redshift_param_group.name

  # Enable automated snapshots for fault tolerance
  automated_snapshot_retention_period = 7

  # Multi-AZ deployment
  availability_zone = "us-east-1a"  # Primary AZ, will span to us-east-1b automatically

  skip_final_snapshot = true

  tags = {
    Name = "fault-tolerant-redshift"
  }
}

# Output cluster endpoint
output "redshift_cluster_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_cluster_master_password" {
  description = "Redshift cluster master password"
  value       = aws_redshift_cluster.redshift_cluster.master_password
  sensitive   = true
}

