        }
      }
    ]
  })
}

# IAM Policy for Redshift (example: S3 access)
resource "aws_iam_role_policy" "redshift_policy" {
  name = "redshift-s3-policy"
  role = aws_iam_role.redshift_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::your-s3-bucket/*",
          "arn:aws:s3:::your-s3-bucket"
        ]
      }
    ]
  })
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]  # Replace with your subnet IDs
}

# Redshift Security Group
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = "vpc-12345678"  # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Replace with your CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "my-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "MySuperSecurePassword123!"
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
