  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift cluster (2 nodes)
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier              = "redshift-cluster-2node"
  node_type                       = "dc2.large"
  number_of_nodes                 = 2
  database_name                   = "dev"
  master_username                 = "admin"
  master_password                 = "ChangeMe123!"
  cluster_subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.redshift_sg.id]
  cluster_type                    = "multi-node"
  publicly_accessible             = false
  automated_snapshot_retention_period = 7
  skip_final_snapshot             = true

  tags = {
    Name = "redshift-cluster-2node"
  }
}

# Resource policy for the Redshift cluster
resource "aws_redshift_cluster_resource_policy" "redshift_policy" {
  resource_arn = aws_redshift_cluster.redshift_cluster.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = ["arn:aws:iam::123456789012:root"]
        }
        Action = [
          "redshift:DescribeClusters",
          "redshift:DescribeClusterSnapshots"
        ]
        Resource = aws_redshift_cluster.redshift_cluster.arn
      }
    ]
  })
}

# Output cluster endpoint
output "redshift_cluster_endpoint" {
  value = aws_redshift_cluster.redshift_cluster.endpoint
}

