  special = false
  upper   = false
}

# Lambda execution role
resource "aws_iam_role" "lambda_role" {
  name = "example_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Simple Lambda function code (Python echo function)
resource "aws_s3_object" "lambda_code" {
  bucket = aws_s3_bucket.lambda_bucket.id
  key    = "lambda_function.zip"
  content_base64 = base64encode(<<-EOF
import json

def lambda_handler(event, context):
    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Hello from example_lambda!',
            'event': event
        })
    }
EOF
  )
}

# Lambda function
resource "aws_lambda_function" "example_lambda" {
  filename         = aws_s3_object.lambda_code.key
  function_name    = "example_lambda"
  role            = aws_iam_role.lambda_role.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = aws_s3_object.lambda_code.content_base64
  runtime         = "python3.9"

  depends_on = [aws_s3_object.lambda_code]
}

# Lambda invocation (using AWS CLI via null_resource)
resource "null_resource" "invoke_lambda" {
  triggers = {
    lambda_arn = aws_lambda_function.example_lambda.arn
    function_version = aws_lambda_function.example_lambda.version
  }

  provisioner "local-exec" {
    command = <<-EOT
      aws lambda invoke \n        --function-name ${aws_lambda_function.example_lambda.function_name} \n        --payload '{}' \n        response.json \n        --region ${var.aws_region}
      cat response.json
      rm response.json
    EOT
  }

  depends_on = [aws_lambda_function.example_lambda]
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}
