provider "aws" {
  region = "us-east-1"
}

# Sample DynamoDB table
resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  tags = {
    Name = "example-table"
  }
}

# Contributor Insights for the DynamoDB table
resource "aws_dynamodb_contributor_insights" "example" {
  table_name              = aws_dynamodb_table.example.name
  contributor_insights_rule {
    one_query {
      # Query for top contributors by write capacity units consumed
      query = <<EOF
SELECT 
  TOP 10 ContributorId,
  SUM(WriteCapacityUnits) as WriteCapacityUnits
FROM 
  ContributorInsightsMetrics
WHERE 
  ContributorInsightsMetrics.WriteCapacityUnits > 0
GROUP BY 
  ContributorId
ORDER BY 
  WriteCapacityUnits DESC
EOF
    }
    one_query {
      # Query for top contributors by read capacity units consumed
      query = <<EOF
SELECT 
  TOP 10 ContributorId,
  SUM(ReadCapacityUnits) as ReadCapacityUnits
FROM 
  ContributorInsightsMetrics
WHERE 
  ContributorInsightsMetrics.ReadCapacityUnits > 0
GROUP BY 
  ContributorId
ORDER BY 
  ReadCapacityUnits DESC
EOF
    }
  }
}

