extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# DynamoDB table
resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  # Enable point-in-time recovery for Kinesis stream support
  point_in_time_recovery {
    enabled = true
  }

  # Enable Kinesis Data Streams
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"
}

# Kinesis Data Stream
resource "aws_kinesis_stream" "example" {
  name             = "example-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes",
  ]
}

# IAM role for DynamoDB to publish to Kinesis
resource "aws_iam_role" "dynamodb_kinesis_role" {
  name = "dynamodb-kinesis-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Kinesis publishing
resource "aws_iam_role_policy" "dynamodb_kinesis_policy" {
  name = "dynamodb-kinesis-policy"
  role = aws_iam_role.dynamodb_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.example.arn
      }
    ]
  })
}

# Kinesis Data Stream as DynamoDB Stream destination
resource "aws_dynamodb_kinesis_streaming_destination" "example" {
  table_name                      = aws_dynamodb_table.example.name
  stream_arn                      = aws_kinesis_stream.example.arn
  destination_status              = "ENABLED"
  approximate_creation_date_epoch = timeadd(timestamp(), "1h")  # Must be future timestamp

  depends_on = [
    aws_iam_role.dynamodb_kinesis_role,
    aws_iam_role_policy.dynamodb_kinesis_policy
  ]
}

