provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Custom DAX parameter group for personalized settings
resource "aws_dax_parameter_group" "personalized_dax_params" {
  name = "personalized-dax-params"

  # Personalized query TTL (Time To Live) in seconds
  parameters {
    name  = "query-ttl"
    value = "300"
  }

  # Record TTL for item caching
  parameters {
    name  = "record-ttl"
    value = "3600"
  }

  # Enable cluster discovery
  parameters {
    name  = "cluster-discovery-endpoint"
    value = "enabled"
  }

  # Subnet group for DAX cluster (required for VPC deployment)
  parameters {
    name  = "subnet-group"
    value = aws_dax_subnet_group.main.name
  }

  # Additional personalized settings
  parameters {
    name  = "iam-auth-enabled"
    value = "false"
  }

  parameters {
    name  = "encryption-at-rest"
    value = "false"
  }

  tags = {
    Environment = "production"
    Purpose     = "personalized-dax"
  }
}

# VPC for DAX cluster
resource "aws_vpc" "dax_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "dax-vpc"
  }
}

# Subnets for DAX
resource "aws_subnet" "dax_subnet_a" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "dax-subnet-a"
  }
}

resource "aws_subnet" "dax_subnet_b" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "dax-subnet-b"
  }
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "main" {
  name       = "dax-subnet-group"
  subnet_ids = [aws_subnet.dax_subnet_a.id, aws_subnet.dax_subnet_b.id]

  tags = {
    Name = "dax-subnet-group"
  }
}

# Example DAX Cluster using the personalized parameter group
resource "aws_dax_cluster" "personalized_dax" {
  cluster_name       = "personalized-dax-cluster"
  iam_auth_enabled   = false
  parameter_group_name = aws_dax_parameter_group.personalized_dax_params.name
  subnet_group_name  = aws_dax_subnet_group.main.name
  server_side_encryption {
    enabled = false
  }
  node_type = "dax.t3.small"
  number_of_nodes = 1

  tags = {
    Environment = "production"
    Purpose     = "personalized"
  }
}

# Output the DAX cluster endpoint
output "dax_cluster_endpoint" {
  description = "Endpoint for the DAX cluster"
  value       = aws_dax_cluster.personalized_dax.cluster_endpoint
}

output "parameter_group_name" {
  description = "Name of the personalized DAX parameter group"
  value       = aws_dax_parameter_group.personalized_dax_params.name
}

