provider "aws" {
  region = "us-west-2"  # Change to your desired region
}

# VPC and subnets (required for SageMaker Domain)
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "sagemaker_subnet" {
  vpc_id     = aws_vpc.sagemaker_vpc.id
  cidr_block = "10.0.1.0/24"
  tags = {
    Name = "sagemaker-subnet"
  }
}

resource "aws_route_table" "sagemaker_rt" {
  vpc_id = aws_vpc.sagemaker_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.sagemaker_igw.id
  }

  tags = {
    Name = "sagemaker-rt"
  }
}

resource "aws_route_table_association" "sagemaker_rta" {
  subnet_id      = aws_subnet.sagemaker_subnet.id
  route_table_id = aws_route_table.sagemaker_rt.id
}

resource "aws_internet_gateway" "sagemaker_igw" {
  vpc_id = aws_vpc.sagemaker_vpc.id
  tags = {
    Name = "sagemaker-igw"
  }
}

# IAM Role for SageMaker Execution
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "SageMakerExecutionRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_execution_policy" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Domain
resource "aws_sagemaker_domain" "example" {
  domain_name = "example-domain"
  auth_mode   = "SSO"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    security_groups = []  # Optional: specify custom security groups

    sharing_settings {
      notebook_output_option = "Disabled"
      s3_output_path         = "s3://sagemaker-example-bucket"
    }
  }

  tags = {
    Name = "example-sagemaker-domain"
  }

  depends_on = [
    aws_iam_role_policy_attachment.sagemaker_execution_policy
  ]
}

# Output the Domain ARN
output "sagemaker_domain_arn" {
  value = aws_sagemaker_domain.example.arn
}

