# Configure the AWS Provider
provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# AWS SageMaker User Profile
resource "aws_sagemaker_user_profile" "example" {
  domain_id = aws_sagemaker_domain.example.id  # Reference to a SageMaker Domain
  user_profile_name = "example-user-profile"

  # Optional: Single sign-on user identifier
  single_sign_on_user_value = "user@example.com"

  # Optional: User settings
  user_settings {
    execution_role = aws_iam_role.sagemaker_execution.arn  # IAM role for execution

    sharing_settings {
      notebook_output_option     = "Disabled"
      s3_output_path            = "s3://my-sagemaker-bucket/"
      s3_kms_key_id             = ""
    }

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  tags = {
    Name = "example-sagemaker-user-profile"
  }
}

# Prerequisite: SageMaker Domain (required for user profile)
resource "aws_sagemaker_domain" "example" {
  domain_name = "example-domain"

  domain_settings {
    execution_role_name = aws_iam_role.sagemaker_execution.name
    security_group_ids  = [aws_security_group.sagemaker_sg.id]
  }

  vpc_id = aws_vpc.example.id  # Optional: VPC for domain

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution.arn
  }

  tags = {
    Name = "example-sagemaker-domain"
  }
}

