provider "aws" {
  region = "us-east-1"
}

# IAM role for SageMaker Space
resource "aws_iam_role" "sagemaker_space_role" {
  name = "sagemaker-space-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_execution" {
  role       = aws_iam_role.sagemaker_space_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Domain for Space
resource "aws_sagemaker_domain" "space_domain" {
  domain_name             = "sagemaker-space-domain"
  auth_mode              = "SSO"
  vpc_id                 = aws_vpc.main.id
  subnet_ids             = [aws_subnet.main.id]
  default_user_settings {
    execution_role = aws_iam_role.sagemaker_space_role.arn
  }

  tags = {
    Name = "sagemaker-space-domain"
  }
}

# SageMaker Space (App)
resource "aws_sagemaker_space" "example_space" {
  domain_id      = aws_sagemaker_domain.space_domain.id
  space_name     = "my-sagemaker-space"
  space_settings {
    s3_uri = "s3://my-sagemaker-bucket/space-data"
  }

  depends_on = [aws_iam_role_policy_attachment.sagemaker_execution]
}

# Supporting VPC and Subnet (required for SageMaker Domain)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  tags = {
    Name = "sagemaker-subnet"
  }
}

# S3 bucket for space data
resource "aws_s3_bucket" "sagemaker_space_bucket" {
  bucket = "my-sagemaker-space-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "sagemaker_space_bucket_versioning" {
  bucket = aws_s3_bucket.sagemaker_space_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

