terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"
}

# IAM role for SageMaker Pipeline execution
resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for SageMaker Pipeline
resource "aws_iam_role_policy" "sagemaker_pipeline_policy" {
  name = "sagemaker-pipeline-policy"
  role = aws_iam_role.sagemaker_pipeline_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sagemaker:CreateTrainingJob",
          "sagemaker:CreateProcessingJob",
          "sagemaker:CreateModel",
          "sagemaker:CreateEndpointConfig",
          "sagemaker:CreateEndpoint",
          "sagemaker:UpdateEndpoint",
          "sagemaker:DescribeTrainingJob",
          "sagemaker:DescribeProcessingJob",
          "sagemaker:DescribeModel",
          "sagemaker:DescribeEndpoint",
          "sagemaker:StopTrainingJob",
          "sagemaker:StopProcessingJob",
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:CreateBucket"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 bucket for pipeline artifacts
resource "aws_s3_bucket" "sagemaker_pipeline_bucket" {
  bucket = "sagemaker-pipeline-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "sagemaker_pipeline_bucket_versioning" {
  bucket = aws_s3_bucket.sagemaker_pipeline_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# SageMaker Pipeline definition
resource "aws_sagemaker_pipeline" "example_pipeline" {
  name     = "example-pipeline"
  role_arn = aws_iam_role.sagemaker_pipeline_role.arn

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Parameters = [
      {
        Name = "input_data"
        Type = "String"
        DefaultValue = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/input/data.csv"
      },
      {
        Name = "model_output_path"
        Type = "String"
        DefaultValue = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/output/model.tar.gz"
      }
    ]
    Steps = [
      {
        Name = "ProcessData"
        Type = "Processing"
        Arguments = {
          ProcessingOutputConfig = {
            Outputs = [
              {
                OutputName = "train_data"
                S3Output = {
                  S3Uri = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/processed/train/"
                  LocalPath = "/opt/ml/processing/output/train/"
                }
              },
              {
                OutputName = "test_data"
                S3Output = {
                  S3Uri = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/processed/test/"
                  LocalPath = "/opt/ml/processing/output/test/"
                }
              }
            ]
          }
          ProcessingInputs = [
            {
              InputName = "raw_data"
              S3Input = {
                S3Uri = "$${input_data}"
                LocalPath = "/opt/ml/processing/input/"
              }
            }
          ]
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-west-2.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
            ContainerEntrypoint = ["python3", "/opt/ml/processing/entrypoint.py"]
          }
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount = 1
              InstanceType = "ml.m5.large"
              VolumeSizeInGB = 30
            }
          }
        }
      },
      {
        Name = "TrainModel"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = "683313688378.dkr.ecr.us-west-2.amazonaws.com/sagemaker-xgboost:1.5-1"
            TrainingInputMode = "File"
          }
          InputDataConfig = [
            {
              ChannelName = "train"
              DataSource = {
                S3DataSource = {
                  S3DataType = "S3Prefix"
                  S3Uri = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/processed/train/"
                }
              }
            }
          ]
          OutputDataConfig = {
            S3OutputPath = "$${model_output_path}"
          }
          ResourceConfig = {
            InstanceCount = 1
            InstanceType = "ml.m5.large"
            VolumeSizeInGB = 30
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 3600
          }
        }
      }
    ]
  })

  tags = {
    Environment = "dev"
    Project     = "ml-pipeline"
  }
}

