# S3 bucket to store the HTML file
resource "aws_s3_bucket" "sagemaker_html" {
  bucket = "sagemaker-human-task-ui-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_ownership_controls" "sagemaker_html" {
  bucket = aws_s3_bucket.sagemaker_html.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "sagemaker_html" {
  depends_on = [aws_s3_bucket_ownership_controls.sagemaker_html]

  bucket = aws_s3_bucket.sagemaker_html.id
  acl    = "private"
}

resource "aws_s3_object" "sagemaker_html_file" {
  bucket = aws_s3_bucket.sagemaker_html.id
  key    = "sagemaker-human-task-ui-template.html"
  content = <<EOF
<!DOCTYPE html>
<html>
<head>
    <title>SageMaker Human Task UI</title>
</head>
<body>
    <h1>TEST</h1>
</body>
</html>
EOF
  content_type = "text/html"
}

# IAM role for SageMaker Human Task UI (minimal permissions)
resource "aws_iam_role" "sagemaker_human_task_ui_role" {
  name = "sagemaker-human-task-ui-role-${random_string.bucket_suffix.result}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "sagemaker_html_s3_access" {
  name = "sagemaker-html-s3-access"
  role = aws_iam_role.sagemaker_human_task_ui_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject"
        ]
        Resource = "${aws_s3_object.sagemaker_html_file.arn}"
      }
    ]
  })
}

# SageMaker Human Task UI
