  name = "tensorflow-model-${random_string.model_suffix.result}"

  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    image  = "763104351884.dkr.ecr.us-west-2.amazonaws.com/tensorflow-inference:2.3-cpu-py37-ubuntu18.04"
    model_data_url = "s3://${aws_s3_bucket.model_bucket.bucket}/model.tar.gz"
  }

  depends_on = [aws_iam_role_policy_attachment.sagemaker_execution_policy]
}

resource "random_string" "model_suffix" {
  length  = 8
  special = false
  upper   = false
}

# SageMaker Endpoint Configuration
