  name = "tensorflow-endpoint-config-${random_string.endpoint_suffix.result}"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = aws_sagemaker_model.ml_model.name
    initial_instance_count = 1
    instance_type          = "ml.m5.large"
  }
}

resource "random_string" "endpoint_suffix" {
  length  = 8
  special = false
  upper   = false
}

# SageMaker Endpoint
resource "aws_sagemaker_endpoint" "endpoint" {
  name                 = "tensorflow-endpoint-${random_string.endpoint_name_suffix.result}"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.endpoint_config.name

  depends_on = [aws_sagemaker_endpoint_configuration.endpoint_config]
}

resource "random_string" "endpoint_name_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Output the endpoint name and ARN
output "sagemaker_endpoint_name" {
  value = aws_sagemaker_endpoint.endpoint.name
}

output "sagemaker_endpoint_arn" {
  value = aws_sagemaker_endpoint.endpoint.arn
}

output "s3_model_bucket" {
  value = aws_s3_bucket.model_bucket.bucket
}

output "execution_role_arn" {
  value = aws_iam_role.sagemaker_execution_role.arn
}

