# Terraform configuration for a caching strategy using AWS ElastiCache (Redis)
# This minimizes database queries by caching frequent read operations

provider "aws" {
  region = "us-east-1"
}

# Example RDS database (your primary DB)
resource "aws_db_instance" "main" {
  identifier           = "app-database"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  username             = "admin"
  password             = "SecurePass123!"
  skip_final_snapshot  = true
  publicly_accessible  = false

  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.main.name

  tags = {
    Name = "app-database"
  }
}

# VPC and networking
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "app-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-b"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "app-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "app-subnet-group"
  }
}

# Security groups
resource "aws_security_group" "db_sg" {
  name_prefix = "db-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-sg"
  }
}

resource "aws_security_group" "cache_sg" {
  name_prefix = "cache-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "cache-sg"
  }
}

# ElastiCache Redis cluster for caching (KEY STRATEGY: Cache-aside pattern)
resource "aws_elasticache_subnet_group" "main" {
  name       = "app-cache-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "app-cache-subnet-group"
  }
}

resource "aws_elasticache_cluster" "main" {
  cluster_id           = "app-cache"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379

  subnet_group_name = aws_elasticache_subnet_group.main.name
  security_group_ids = [aws_security_group.cache_sg.id]

  tags = {
    Name = "app-cache"
  }
}

# Application Load Balancer (example app that uses cache)
resource "aws_lb" "app" {
  name               = "app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id] # Assume public subnets exist

  tags = {
    Name = "app-lb"
  }
}

# Outputs
output "database_endpoint" {
  description = "RDS Database endpoint"
  value       = aws_db_instance.main.endpoint
}

output "redis_endpoint" {
  description = "ElastiCache Redis endpoint for caching"
  value       = aws_elasticache_cluster.main.cache_nodes[0].address
}

output "strategy_recommendation" {
  description = "STRATEGY: Implement Cache-Aside pattern. Check Redis cache first (TTL: 5-300s based on data volatility). Cache MISS → query DB → store in Redis. Reduces DB load by 70-90% for read-heavy apps."
  value       = "Use Redis cache-aside pattern with TTLs matching data freshness needs"
}

