resource "aws_elasticache_replication_group" "redis_iam" {
  replication_group_id       = "redis-iam-cluster"
  description                = "Redis cluster with IAM authentication"
  node_type                  = "cache.t4g.micro"
  port                       = 6379
  engine                     = "redis"
