}

output "iam_user_access_key_id" {
  value = aws_iam_access_key.elasticache_user.id
}

# IAM Access Key for the user (required for IAM auth)
resource "aws_iam_access_key" "elasticache_user" {
  user = aws_iam_user.elasticache_user.name
}

output "iam_user_secret_key" {
  value     = aws_iam_access_key.elasticache_user.secret
  sensitive = true
}

