  subnet_ids = ["subnet-0123456789abcdef0", "subnet-0123456789abcdef1"]  # Replace with your subnet IDs
}

# ElastiCache Redis Cluster with Authentication Enabled
resource "aws_elasticache_replication_group" "redis_with_auth" {
  replication_group_id       = "redis-auth-cluster"
  description                = "Redis cluster with password authentication"
  engine                     = "redis"
  node_type                  = "cache.t4g.micro"
  port                       = 6379
  num_cache_clusters         = 1
  parameter_group_name       = "default.redis7"
  security_group_ids         = ["sg-0123456789abcdef0"]  # Replace with your security group ID
  subnet_group_name          = aws_elasticache_subnet_group.main.name
  auth_token                  = "SecurePassword123!"  # Must match the user's password
  transit_encryption_enabled  = true
  at_rest_encryption_enabled  = true
  auth_token_update_strategy = "ROTATE"

  user_group_ids = [aws_elasticache_user_group.user_group.user_group_id]

  tags = {
    Name = "redis-auth-cluster"
  }
}

# Output cluster endpoint for connection
output "redis_endpoint" {
  value = aws_elasticache_replication_group.redis_with_auth.primary_endpoint_address
}

output "redis_port" {
  value = aws_elasticache_replication_group.redis_with_auth.port
}

output "user_id" {
  value = aws_elasticache_user.elasticache_user.user_id
}
```

**Connection Example:**
```bash
redis-cli -h ${aws_elasticache_replication_group.redis_with_auth.primary_endpoint_address} -p 6379 -a SecurePassword123!
```

**Key Points:**
- `auth_token` enables password authentication on the Redis cluster
- `aws_elasticache_user` defines users with passwords
- `user_group_ids` associates users with the cluster
- Replace placeholder subnet/security group IDs with your actual values
- Password must match between `auth_token` and user `passwords`
- `transit_encryption_enabled = true` required for auth token support

