provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

# Subnets (3 public subnets across different AZs)
resource "aws_subnet" "msk_subnet" {
  count = 3

  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Internet Gateway
resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

# Route Table
resource "aws_route_table" "msk_rt" {
  vpc_id = aws_vpc.msk_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.msk_igw.id
  }

  tags = {
    Name = "msk-rt"
  }
}

resource "aws_route_table_association" "msk_rta" {
  count = 3

  subnet_id      = aws_subnet.msk_subnet[count.index].id
  route_table_id = aws_route_table.msk_rt.id
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]
    vpc_security_group_ids = [aws_security_group.msk_sg.id]
  }

  tags = {
    Name = "my-msk-cluster"
  }

  depends_on = [aws_security_group.msk_sg]
}

# Output cluster details
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "msk_cluster_bootstrap_brokers" {
  value = aws_msk_cluster.msk_cluster.bootstrap_broker_string
}

output "msk_cluster_zookeeper_connect_string" {
  value = aws_msk_cluster.msk_cluster.zookeeper_connect_string
}

