provider "aws" {
  region = "us-east-1"
}

# CloudWatch Logs group for MSK logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/my-cluster"
  retention_in_days = 7

  tags = {
    Name = "msk-cluster-logs"
  }
}

# MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.private[*].id
    security_groups = [aws_security_group.msk.id]
    ebs_volume_size = 100

    vpc_config {
      subnet_ids         = aws_subnet.private[*].id
      security_group_ids = [aws_security_group.msk.id]
    }
  }

  # Configure CloudWatch Logs
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  # IAM role for MSK to write to CloudWatch Logs
  client_authentication {
    saslauthentication {
      enabled = true
    }
  }

  tags = {
    Name = "my-msk-cluster"
  }

  depends_on = [aws_iam_role_policy_attachment.msk_cloudwatch_logs]
}

# VPC for MSK
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Private subnets
resource "aws_subnet" "private" {
  count = 3

  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-private-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for MSK
resource "aws_security_group" "msk" {
  name_prefix = "msk-cluster-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# IAM role for MSK CloudWatch Logs access
resource "aws_iam_role" "msk_cloudwatch_logs" {
  name = "msk-cloudwatch-logs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# IAM policy for CloudWatch Logs
resource "aws_iam_role_policy" "msk_cloudwatch_logs" {
  name = "msk-cloudwatch-logs-policy"
  role = aws_iam_role.msk_cloudwatch_logs.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:DescribeLogGroups",
          "logs:DescribeLogStreams",
          "logs:GetLogEvents",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:log-group:/aws/msk/my-cluster:*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_cloudwatch_logs" {
  role       = aws_iam_role.msk_cloudwatch_logs.name
  policy_arn = aws_iam_role_policy.msk_cloudwatch_logs.arn
}

# Attach CloudWatch Logs role to MSK cluster
resource "aws_msk_cluster" "main" {
  # ... (previous configuration remains the same until client_authentication block)

  encryption_info {
    encryption_at_rest {
      data_volume_kms_key_id = "aws/kafka"
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  # Reference the CloudWatch Logs IAM role
  client_authentication {
    saslauthentication {
      enabled = true
    }
  }

  # Ensure the logging_info block uses the correct log group
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  # Link the IAM role for CloudWatch Logs (this is automatically handled by AWS MSK)
}

