  tags = {
    Name = "msk-encryption-key"
  }
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-encryption-key"
  target_key_id = aws_kms_key.msk_encryption_key.key_id
}

# MSK Cluster with encryption at rest
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "encrypted-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = [
      aws_subnet.msk_subnet_a.id,
      aws_subnet.msk_subnet_b.id,
