    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest {
      data_volume_kms_key_id = aws_kms_key.msk_encryption_key.arn
    }
  }

  monitoring_info {
    cloudwatch_log_group = aws_cloudwatch_log_group.msk_log_group.name
  }

  client_authentication {
    saslauth {
      enabled = true
    }
  }

  tags = {
    Name = "encrypted-msk-cluster"
  }

  depends_on = [aws_cloudwatch_log_group.msk_log_group]
}

# CloudWatch Log Group for MSK monitoring
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/encrypted-msk-cluster"
  retention_in_days = 14
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Output cluster details
output "msk_bootstrap_brokers" {
  description = "Bootstrap brokers for MSK cluster"
