  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "msk-public-rt"
  }
}

resource "aws_route_table_association" "public_a" {
  subnet_id      = aws_subnet.private_a.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.public.id
}

# Security Group for MSK
resource "aws_security_group" "msk" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MSK from VPC"
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  ingress {
    description = "JMX Exporter"
    from_port   = 9404
    to_port     = 9404
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  ingress {
    description = "Node Exporter"
    from_port   = 9100
    to_port     = 9100
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# MSK Configuration for JMX and Node Exporters
resource "aws_msk_configuration" "exporters" {
  kafka_version = "3.7.1"
  server_properties = <<PROPERTIES
auto.create.topics.enable=true
delete.topic.enable=true
jmx.metrics.enabled=true
jmx.metrics.reporter.class.name=org.apache.kafka.jmx.exporter.JmxExporter
jmx.metrics.reporter.topic=jmx-metrics
node.exporter.enabled=true
PROPERTIES
}

# MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-exporters-cluster"
  kafka_version          = "3.7.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = [
      aws_subnet.private_a.id,
      aws_subnet.private_b.id
    ]
    security_groups = [aws_security_group.msk.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn         = aws_msk_configuration.exporters.arn
    revision    = aws_msk_configuration.exporters.latest_revision
  }

  vpc_config {
    subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]
    security_group_ids = [aws_security_group.msk.id]
  }

  tags = {
    Name = "msk-exporters"
  }
}

# Output cluster details
output "msk_bootstrap_brokers" {
  description = "Bootstrap brokers"
  value       = aws_msk_cluster.main.bootstrap_brokers
}

output "msk_arn" {
  description = "MSK Cluster ARN"
  value       = aws_msk_cluster.main.arn
}

