  name       = "debezium-plugin"
  description = "Debezium connector plugin"
  content_type = "ZIPFILE"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect.arn
      file_path  = aws_s3_object.debezium_plugin.key
    }
  }

  depends_on = [aws_s3_object.debezium_plugin]
}

# MSK Connect Worker Configuration
resource "aws_mskconnect_worker_configuration" "debezium_worker" {
  name = "debezium-worker-config"

  properties = jsonencode({
    "connector.client.config.override.policy" = "All"
    "connector.client.config.topics.create.enabled" = "true"
    "group.id" = "debezium-connect"
    "key.converter" = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter" = "org.apache.kafka.connect.json.JsonConverter"
    "key.converter.schemas.enable" = "false"
    "value.converter.schemas.enable" = "false"
    "offset.storage.topic" = "connect-offsets"
    "config.storage.topic" = "connect-configs"
    "status.storage.topic" = "connect-status"
  })
}

# MSK Connect Connector using Debezium plugin
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-source-connector"
  capacity {
    autoscaling {
      mku_count      = 1
      max_worker_count = 4
      min_worker_count = 1
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }
  connector_configuration = jsonencode({
    "connector.class" = "io.debezium.connector.postgresql.PostgresConnector"
    "database.hostname" = "your-postgres-host.example.com"
    "database.port" = "5432"
    "database.user" = "debezium"
    "database.password" = "your-password"
    "database.dbname" = "yourdb"
    "table.include.list" = "public.inventory"
    "topic.prefix" = "dbserver1"
    "plugin.name" = "pgoutput"
  })
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = [aws_security_group.msk_connect_sg.id]
        subnets         = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
      }
      kafka_cluster_ref {
        arn  = aws_msk_cluster.main.arn
        id   = aws_msk_cluster.main.kafka_cluster_id
      }
    }
  }
  kafka_connect_version = "3.5"
  plugins {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect.arn
  worker_configuration {
    arn = aws_mskconnect_worker_configuration.debezium_worker.arn
  }

  depends_on = [aws_mskconnect_custom_plugin.debezium]
}

resource "aws_security_group" "msk_connect_sg" {
  name_prefix = "msk-connect-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 0
    to_port         = 65535
    protocol        = "tcp"
    security_groups = [aws_security_group.msk_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect" {
  name = "msk-connect-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRolePolicy"
}

resource "aws_iam_role_policy" "msk_connect_s3" {
  name = "msk-connect-s3-policy"
  role = aws_iam_role.msk_connect.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.msk_connect.arn,
          "${aws_s3_bucket.msk_connect.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_msk" {
  name = "msk-connect-msk-policy"
  role = aws_iam_role.msk_connect.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeBroker"
        ]
        Resource = [aws_msk_cluster.main.arn]
      },
      {
        Effect = "Allow"
        Action = [
          "kafka:CreateTopic",
          "kafka:DescribeTopic",
          "kafka:WriteData",
          "kafka-cluster:ReadData"
        ]
        Resource = "*"
      }
    ]
  })
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.main.bootstrap_brokers_sasl_iam
}

output "msk_connect_connector_arn" {
  value = aws_mskconnect_connector.debezium_connector.arn
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
