terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and networking
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "msk-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "msk-subnet-b"
  }
}

resource "aws_subnet" "subnet_c" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "msk-subnet-c"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "msk-igw"
  }
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "msk-rt"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.subnet_a.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.subnet_b.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "c" {
  subnet_id      = aws_subnet.subnet_c.id
  route_table_id = aws_route_table.main.id
}

# MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "debezium-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  vpc_config {
    subnet_ids         = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  # Enable public access for simplicity (adjust for production)
  client_authentication {
    saslauth = {
      enabled = true
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn
  }

  monitoring_info {
    cloudwatch_log_group = aws_cloudwatch_log_group.msk.name
  }

  tags = {
    Name = "debezium-msk"
  }

  depends_on = [aws_cloudwatch_log_group.msk, aws_cloudwatch_log_resource_policy.msk]
}

resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_kms_key" "msk" {
  description             = "KMS key for MSK encryption"
  enable_key_rotation     = true
}

resource "aws_cloudwatch_log_group" "msk" {
  name              = "/aws/msk/debezium-cluster"
  retention_in_days = 14
}

resource "aws_cloudwatch_log_resource_policy" "msk" {
  policy_name     = "msk-log-policy"
  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:*"
      }
    ]
  })
}

# MSK Connect Custom Plugin (Debezium)
resource "aws_s3_bucket" "msk_connect" {
  bucket = "debezium-msk-connect-${random_id.bucket.hex}"
}

resource "random_id" "bucket" {
  byte_length = 8
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect.id
  key    = "debezium.zip"
  source = "debezium.zip"  # Local file path - replace with your actual Debezium connector ZIP
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name       = "debezium-plugin"
  description = "Debezium connector plugin"
  content_type = "ZIPFILE"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect.arn
      file_path  = aws_s3_object.debezium_plugin.key
    }
  }

  depends_on = [aws_s3_object.debezium_plugin]
}

# MSK Connect Worker Configuration
resource "aws_mskconnect_worker_configuration" "debezium_worker" {
  name = "debezium-worker-config"

  properties = jsonencode({
    "connector.client.config.override.policy" = "All"
    "connector.client.config.topics.create.enabled" = "true"
    "group.id" = "debezium-connect"
    "key.converter" = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter" = "org.apache.kafka.connect.json.JsonConverter"
    "key.converter.schemas.enable" = "false"
    "value.converter.schemas.enable" = "false"
    "offset.storage.topic" = "connect-offsets"
    "config.storage.topic" = "connect-configs"
    "status.storage.topic" = "connect-status"
  })
}

# MSK Connect Connector using Debezium plugin
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-source-connector"
  capacity {
    autoscaling {
      mku_count      = 1
      max_worker_count = 4
      min_worker_count = 1
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }
  connector_configuration = jsonencode({
    "connector.class" = "io.debezium.connector.postgresql.PostgresConnector"
    "database.hostname" = "your-postgres-host.example.com"
    "database.port" = "5432"
    "database.user" = "debezium"
    "database.password" = "your-password"
    "database.dbname" = "yourdb"
    "table.include.list" = "public.inventory"
    "topic.prefix" = "dbserver1"
    "plugin.name" = "pgoutput"
  })
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = [aws_security_group.msk_connect_sg.id]
        subnets         = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
      }
      kafka_cluster_ref {
        arn  = aws_msk_cluster.main.arn
        id   = aws_msk_cluster.main.kafka_cluster_id
      }
    }
  }
  kafka_connect_version = "3.5"
  plugins {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect.arn
  worker_configuration {
    arn = aws_mskconnect_worker_configuration.debezium_worker.arn
  }

  depends_on = [aws_mskconnect_custom_plugin.debezium]
}

resource "aws_security_group" "msk_connect_sg" {
  name_prefix = "msk-connect-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 0
    to_port         = 65535
    protocol        = "tcp"
    security_groups = [aws_security_group.msk_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect" {
  name = "msk-connect-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRolePolicy"
}

resource "aws_iam_role_policy" "msk_connect_s3" {
  name = "msk-connect-s3-policy"
  role = aws_iam_role.msk_connect.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.msk_connect.arn,
          "${aws_s3_bucket.msk_connect.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_msk" {
  name = "msk-connect-msk-policy"
  role = aws_iam_role.msk_connect.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeBroker"
        ]
        Resource = [aws_msk_cluster.main.arn]
      },
      {
        Effect = "Allow"
        Action = [
          "kafka:CreateTopic",
          "kafka:DescribeTopic",
          "kafka:WriteData",
          "kafka-cluster:ReadData"
        ]
        Resource = "*"
      }
    ]
  })
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.main.bootstrap_brokers_sasl_iam
}

output "msk_connect_connector_arn" {
  value = aws_mskconnect_connector.debezium_connector.arn
}
```

**Important Notes:**
1. Replace `"debezium.zip"` with the path to your actual Debezium connector ZIP file
2. Update PostgreSQL connection details (`database.hostname`, `database.password`, etc.) in the connector configuration
3. Adjust security groups and network access for production use
4. The connector is configured for PostgreSQL Debezium source - modify `connector.class` and properties for your source database
5. Ensure the Debezium ZIP contains the correct connector version compatible with Kafka 3.5.1

