  role       = aws_iam_role.mskconnect.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRolePolicy"
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium" {
  connector_name = "debezium-connector"
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = [aws_security_group.mskconnect.id]
        subnets         = [
          aws_subnet.private_a.id,
          aws_subnet.private_b.id,
          aws_subnet.private_c.id
        ]
      }
      apache_kafka_cluster_arn = aws_msk_cluster.main.arn
    }
  }
  capacity {
    auto_scaling {
      mcu_count       = 1
      min_worker_count = 1
      max_worker_count = 4
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }
  connector_configuration = {
    "connector.class"               = "io.debezium.connector.SourceConnector"
    "tasks.max"                     = "1"
    "database.hostname"             = "your-db-host"
    "database.port"                 = "3306"
    "database.user"                 = "debezium"
    "database.password"             = "your-password"
    "database.server.id"            = "12345"
    "database.server.name"          = "mysql1"
    "database.include.list"         = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.main.bootstrap_brokers_tls
    "database.history.kafka.topic"  = "dbhistory"
  }
  kafka_connect_version = "3.5"
  plugin {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }
  service_execution_role_arn = aws_iam_role.mskconnect.arn
  worker_configuration {
    arn = aws_mskconnect_worker_configuration.main.arn
  }

  depends_on = [
    aws_msk_cluster.main,
    aws_mskconnect_custom_plugin.debezium
  ]
}

resource "aws_security_group" "mskconnect" {
  name_prefix = "mskconnect-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 0
    to_port         = 65535
    protocol        = "tcp"
    security_groups = [aws_security_group.msk.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Outputs
output "msk_bootstrap_brokers_tls" {
  value = aws_msk_cluster.main.bootstrap_brokers_tls
}

output "msk_connect_connector_arn" {
  value = aws_mskconnect_connector.debezium.arn
}

