```hcl
provider "aws" {
  region = "us-east-1"
}

# CloudWatch Logs group for MSK logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/my-cluster"
  retention_in_days = 7
}

# S3 bucket for MSK logs
resource "aws_s3_bucket" "msk_logs" {
  bucket = "my-msk-logs-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_server_side_encryption_configuration" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Kinesis Firehose delivery stream for MSK logs
resource "aws_kinesis_firehose_delivery_stream" "msk_logs" {
  name        = "msk-logs-firehose"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs.arn
    prefix     = "firehose/"
  }
}

# IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.msk_logs.arn,
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      }
    ]
  })
}

# MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 1000    # GB

    client_subnets = [
      aws_subnet.private_a.id,
      aws_subnet.private_b.id,
      aws_subnet.private_c.id
    ]
    security_groups = [aws_security_group.msk.id]
    vpc_config {
      subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id, aws_subnet.private_c.id]
      security_group_ids = [aws_security_group.msk.id]
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      s3 {
        enabled  = true
        bucket   = aws_s3_bucket.msk_logs.bucket
        prefix   = "logs/"
      }
      firehose {
        enabled = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs.name
      }
    }
  }

  depends_on = [
    aws_cloudwatch_log_group.msk_logs,
    aws_s3_bucket.msk_logs,
    aws_kinesis_firehose_delivery_stream.msk_logs
  ]
}

# KMS Key for encryption at rest
resource "aws_kms_key" "msk" {
  description             = "KMS key for MSK encryption"
  enable_key_rotation     = true
}

resource "aws_kms_alias" "msk" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk.key_id
}

# VPC and networking
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-b"
  }
}

resource "aws_subnet" "private_c" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "private-c"
  }
}

resource "aws_security_group" "msk" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name       = "debezium-plugin"
  description = "Debezium connector plugin"
  content_type = "ZIPFILE"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.mskconnect.bucket_arn
      file_key   = "debezium.zip"
    }
  }

  depends_on = [aws_s3_object.debezium_zip]
}

# S3 bucket for MSK Connect
resource "aws_s3_bucket" "mskconnect" {
  bucket = "mskconnect-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_public_access_block" "mskconnect" {
  bucket = aws_s3_bucket.mskconnect.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Upload debezium.zip (placeholder - replace with actual S3 upload mechanism)
resource "aws_s3_object" "debezium_zip" {
  bucket = aws_s3_bucket.mskconnect.bucket
  key    = "debezium.zip"
  source = "debezium.zip"  # Local file path
}

# MSK Connect Worker Configuration
resource "aws_mskconnect_worker_configuration" "main" {
  name = "debezium-worker-config"

  properties = {
    "client.producer.max.request.size" = "2097152"
    "connector.client.config.override.policy" = "All"
  }
}

# IAM role for MSK Connect
resource "aws_iam_role" "mskconnect" {
  name = "mskconnect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "mskconnect_basic" {
  role       = aws_iam_role.mskconnect.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRolePolicy"
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium" {
  connector_name = "debezium-connector"
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = [aws_security_group.mskconnect.id]
        subnets         = [
          aws_subnet.private_a.id,
          aws_subnet.private_b.id,
          aws_subnet.private_c.id
        ]
      }
      apache_kafka_cluster_arn = aws_msk_cluster.main.arn
    }
  }
  capacity {
    auto_scaling {
      mcu_count       = 1
      min_worker_count = 1
      max_worker_count = 4
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }
  connector_configuration = {
    "connector.class"               = "io.debezium.connector.SourceConnector"
    "tasks.max"                     = "1"
    "database.hostname"             = "your-db-host"
    "database.port"                 = "3306"
    "database.user"                 = "debezium"
    "database.password"             = "your-password"
    "database.server.id"            = "12345"
    "database.server.name"          = "mysql1"
    "database.include.list"         = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.main.bootstrap_brokers_tls
    "database.history.kafka.topic"  = "dbhistory"
  }
  kafka_connect_version = "3.5"
  plugin {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }
  service_execution_role_arn = aws_iam_role.mskconnect.arn
  worker_configuration {
    arn = aws_mskconnect_worker_configuration.main.arn
  }

  depends_on = [
    aws_msk_cluster.main,
    aws_mskconnect_custom_plugin.debezium
  ]
}

resource "aws_security_group" "mskconnect" {
  name_prefix = "mskconnect-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 0
    to_port         = 65535
    protocol        = "tcp"
    security_groups = [aws_security_group.msk.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Outputs
output "msk_bootstrap_brokers_tls" {
  value = aws_msk_cluster.main.bootstrap_brokers_tls
}

output "msk_connect_connector_arn" {
  value = aws_mskconnect_connector.debezium.arn
}
```

**Note:** This configuration includes placeholder values for Debezium connector properties (database connection details) that need to be customized for your specific source database. Also, ensure the `debezium.zip` file is available locally or uploaded to S3 before running `terraform apply`.

