terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  project = "your-project-id"
  region  = "us-central1"
}

# VPC network
resource "google_compute_network" "vpc" {
  name                    = "mysql-cluster-vpc"
  auto_create_subnetworks = false
}

# Subnets in 3 zones with 100 GB storage provisioned via regional SSD persistent disk
resource "google_compute_subnetwork" "subnet_a" {
  name          = "mysql-subnet-a"
  ip_cidr_range = "10.0.1.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc.id
}

resource "google_compute_subnetwork" "subnet_b" {
  name          = "mysql-subnet-b"
  ip_cidr_range = "10.0.2.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc.id
}

resource "google_compute_subnetwork" "subnet_c" {
  name          = "mysql-subnet-c"
  ip_cidr_range = "10.0.3.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc.id
}

# 100 GB Regional SSD Persistent Disks (one per zone)
resource "google_compute_region_disk" "mysql_data_a" {
  name   = "mysql-data-disk-a"
  region = "us-central1"
  type   = "pd-ssd"
  size   = 100
}

resource "google_compute_region_disk" "mysql_data_b" {
  name   = "mysql-data-disk-b"
  region = "us-central1"
  type   = "pd-ssd"
  size   = 100
}

resource "google_compute_region_disk" "mysql_data_c" {
  name   = "mysql-data-disk-c"
  region = "us-central1"
  type   = "pd-ssd"
  size   = 100
}

# Cloud SQL MySQL Primary Instance (Zone A)
resource "google_sql_database_instance" "mysql_primary" {
  name             = "mysql-primary"
  database_version = "MYSQL_8_0"
  region           = "us-central1"

  settings {
    tier = "db-n1-standard-2"
    availability_type = "REGIONAL"

    disk_autoresize = false
    disk_size = 100
    disk_type = "PD_SSD"

    location_preference {
      zone = "us-central1-a"
    }

    backup_configuration {
      enabled = true
    }

    ip_configuration {
      ipv4_enabled    = true
      private_network = google_compute_network.vpc.id
    }
  }

  depends_on = [google_compute_region_disk.mysql_data_a]
}

# Cloud SQL MySQL Read Replica (Zone B)
resource "google_sql_database_instance" "mysql_replica_b" {
  name             = "mysql-replica-b"
  database_version = "MYSQL_8_0"
  master_instance_name = google_sql_database_instance.mysql_primary.name
  region           = "us-central1"

  settings {
    tier = "db-n1-standard-2"

    disk_autoresize = false
    disk_size = 100
    disk_type = "PD_SSD"

    location_preference {
      zone = "us-central1-b"
    }

    ip_configuration {
      ipv4_enabled    = false
      private_network = google_compute_network.vpc.id
    }
  }

  depends_on = [google_compute_region_disk.mysql_data_b]
}

# Cloud SQL MySQL Read Replica (Zone C)
resource "google_sql_database_instance" "mysql_replica_c" {
  name             = "mysql-replica-c"
  database_version = "MYSQL_8_0"
  master_instance_name = google_sql_database_instance.mysql_primary.name
  region           = "us-central1"

  settings {
    tier = "db-n1-standard-2"

    disk_autoresize = false
    disk_size = 100
    disk_type = "PD_SSD"

    location_preference {
      zone = "us-central1-c"
    }

    ip_configuration {
      ipv4_enabled    = false
      private_network = google_compute_network.vpc.id
    }
  }

  depends_on = [google_compute_region_disk.mysql_data_c]
}

# MySQL Database
resource "google_sql_database" "app_db" {
  name     = "app_database"
  instance = google_sql_database_instance.mysql_primary.name
}

# MySQL User
resource "google_sql_user" "app_user" {
  name     = "app_user"
  instance = google_sql_database_instance.mysql_primary.name
  password = "secure_password_123!"
}

