terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "mysql-cluster-vpc"
  }
}

# Subnets across AZs
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "mysql-private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "mysql-private-b"
  }
}

resource "aws_subnet" "private_c" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "mysql-private-c"
  }
}

# Subnet group for RDS
resource "aws_db_subnet_group" "mysql" {
  name       = "mysql-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id, aws_subnet.private_c.id]

  tags = {
    Name = "mysql-subnet-group"
  }
}

# Security group for MySQL
resource "aws_security_group" "mysql" {
  name_prefix = "mysql-cluster-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MySQL/Aurora"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-cluster-sg"
  }
}

# Aurora MySQL Cluster (Serverless v2 for distributed storage)
resource "aws_rds_cluster" "mysql" {
  cluster_identifier      = "mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.05.0"
  database_name           = "mydb"
  master_username         = "admin"
  master_user_secret {
    kms_key_id = aws_kms_key.mysql.arn
  }
  storage_type            = "aurora-iopt1"
  serverlessv2_scaling_configuration {
    min_capacity = 0.5
    max_capacity = 8.0
  }
  db_subnet_group_name   = aws_db_subnet_group.mysql.name
  vpc_security_group_ids = [aws_security_group.mysql.id]
  skip_final_snapshot    = true

  tags = {
    Name = "mysql-cluster"
  }
}

# Aurora cluster instances across AZs (~33GB each for 100GB total)
resource "aws_rds_cluster_instance" "mysql_replicas" {
  count              = 3
  identifier         = "mysql-replica-${count.index}"
  cluster_identifier = aws_rds_cluster.mysql.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.mysql.engine
  engine_version     = aws_rds_cluster.mysql.engine_version
  publicly_accessible = false

  tags = {
    Name = "mysql-replica-${count.index}"
  }
}

# KMS key for secrets
resource "aws_kms_key" "mysql" {
  description             = "KMS key for MySQL cluster"
  enable_key_rotation     = true
  deletion_window_in_days = 7

  tags = {
    Name = "mysql-kms-key"
  }
}

resource "aws_kms_alias" "mysql" {
  name          = "alias/mysql-cluster"
  target_key_id = aws_kms_key.mysql.key_id
}

# Output cluster endpoint
output "mysql_cluster_endpoint" {
  description = "Cluster endpoint for MySQL connection"
  value       = aws_rds_cluster.mysql.endpoint
}

output "mysql_reader_endpoint" {
  description = "Reader endpoint for read traffic"
  value       = aws_rds_cluster.mysql.reader_endpoint
}

