provider "aws" {
  region = "us-east-2"
  alias  = "us_east_2"
}

provider "aws" {
  region = "us-west-2"
  alias  = "us_west_2"
}

# Primary DynamoDB table in us-east-2
resource "aws_dynamodb_table" "global_table" {
  provider = aws.us_east_2

  name           = "global-replicated-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PartitionKey"
  range_key      = "SortKey"

  attribute {
    name = "PartitionKey"
    type = "S"
  }

  attribute {
    name = "SortKey"
    type = "S"
  }

  global_secondary_index {
    name               = "GSI1"
    hash_key           = "PartitionKey"
    range_key          = "SortKey"
    projection_type    = "ALL"
  }

  tags = {
    Name = "GlobalReplicatedTable"
  }
}

# Replica in us-west-2
resource "aws_dynamodb_table_replica" "replica_us_west_2" {
  provider = aws.us_west_2

  global_table_arn = aws_dynamodb_table.global_table.arn
  region_name      = "us-west-2"
}

# Global Table resource to manage replication
resource "aws_dynamodb_global_table" "global_table" {
  provider = aws.us_east_2

  name = aws_dynamodb_table.global_table.name

  replica {
    region_name = "us-east-2"
  }

  replica {
    region_name = "us-west-2"
  }

  depends_on = [
    aws_dynamodb_table_replica.replica_us_west_2
  ]
}

