# Example Terraform configuration for AWS CloudFront with personalized TTL settings
# This sets up a CloudFront distribution with custom TTL fields for managing data expiration

provider "aws" {
  region = "us-east-1"
}

# S3 bucket for origin content
resource "aws_s3_bucket" "origin_bucket" {
  bucket = "my-personalized-content-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_acl" "origin_bucket_acl" {
  bucket = aws_s3_bucket.origin_bucket.id
  acl    = "private"
}

# CloudFront distribution with personalized TTL settings
resource "aws_cloudfront_distribution" "personalized_ttl_distribution" {
  origin {
    domain_name = aws_s3_bucket.origin_bucket.bucket_regional_domain_name
    origin_id   = "S3Origin"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  # Default cache behavior with personalized TTL settings
  default_cache_behavior {
    allowed_methods        = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "S3Origin"
    compress               = true
    viewer_protocol_policy = "redirect-to-https"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    # Personalized TTL field settings for data expiration management
    min_ttl     = 0
    default_ttl = 3600  # 1 hour default TTL
    max_ttl     = 86400 # 24 hours maximum TTL
  }

  # Custom cache policy for more granular TTL control
  cache_policy_id = aws_cloudfront_cache_policy.personalized_ttl_policy.id

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  # TTL settings at distribution level (overrides behavior defaults)
  default_cache_behavior {
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    smooth_origin_failures = true
  }
}

# Custom Cache Policy with personalized TTL configuration
resource "aws_cloudfront_cache_policy" "personalized_ttl_policy" {
  comment = "Personalized TTL policy for data expiration management"

  min_ttl   = 0
  default_ttl = 1800  # 30 minutes personalized default TTL
  max_ttl   = 7200   # 2 hours maximum TTL

  parameters_in_cache_key_and_forwarded_to_origin {
    cookies_config {
      cookie_behavior = "none"
    }
    headers_config {
      header_behavior = "none"
    }
    query_strings_config {
      query_string_behavior = "none"
    }
  }
}

# Origin Access Identity for S3
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for personalized TTL distribution"
}

# S3 bucket policy to allow CloudFront access
resource "aws_s3_bucket_policy" "origin_bucket_policy" {
  bucket = aws_s3_bucket.origin_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowCloudFrontAccess"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_origin_access_identity.oai.id}"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.origin_bucket.arn}/*"
      }
    ]
  })
}

output "cloudfront_distribution_id" {
  value = aws_cloudfront_distribution.personalized_ttl_distribution.id
}

output "cloudfront_distribution_domain" {
  value = aws_cloudfront_distribution.personalized_ttl_distribution.domain_name
}

output "cache_policy_id" {
  value = aws_cloudfront_cache_policy.personalized_ttl_policy.id
}
```

This configuration sets up:
- **S3 bucket** as content origin
- **CloudFront distribution** with personalized TTL settings:
  - `min_ttl = 0` (immediate expiration allowed)
  - `default_ttl = 3600` (1 hour default expiration)
  - `max_ttl = 86400` (24 hours maximum caching)
- **Custom Cache Policy** for granular TTL control (30 min default, 2 hr max)
- Complete infrastructure for managing data expiration through TTL fields

