terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# AWS VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Egress-Only Internet Gateway (for IPv6-only outbound traffic)
resource "aws_egress_only_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-egress-only-igw"
  }
}

# Example IPv6 CIDR block association (required for Egress-Only IGW to function)
resource "aws_vpc_ipv6_cidr_block_association" "main" {
  vpc_id     = aws_vpc.main.id
  ipv6_cidr_block = "2600:1f18:1234:8900::/56"  # Amazon-provided IPv6 CIDR
}

# Optional: Route table and route for IPv6 egress
resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.main.id
  }

  tags = {
    Name = "main-rt"
  }
}

# Optional: Associate route table with a subnet (create a subnet first)
resource "aws_subnet" "example" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  assign_ipv6_address_on_creation = true
  ipv6_cidr_block         = cidrsubnet(aws_vpc_ipv6_cidr_block_association.main.ipv6_cidr_block, 8, 1)

  tags = {
    Name = "example-subnet"
  }
}

resource "aws_route_table_association" "example" {
  subnet_id      = aws_subnet.example.id
  route_table_id = aws_route_table.main.id
}

