  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "neptune-subnet-2"
  }
}

# Subnet group for Neptune
resource "aws_neptune_subnet_group" "main" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Custom parameter group for Neptune
resource "aws_neptune_parameter_group" "custom" {
  family = "neptune1"
  name   = "custom-neptune-params"

  parameter {
    name  = "neptune_enable_audit_log"
    value = 1
  }

  tags = {
    Name = "custom-neptune-params"
  }
}

# Neptune cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier      = "neptune-cluster"
  engine                  = "neptune"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  iam_database_authentication_enabled = true

  neptune_subnet_group_name   = aws_neptune_subnet_group.main.name
  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name

  vpc_security_group_ids = [aws_security_group.neptune_sg.id]

  tags = {
    Name = "neptune-cluster"
  }
}

# Neptune cluster instance
resource "aws_neptune_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "neptune-cluster-instance-${count.index}"
  cluster_identifier = aws_neptune_cluster.main.id
  instance_class     = "db.r6g.large"
  engine             = "neptune"

  tags = {
    Name = "neptune-cluster-instance-${count.index}"
  }
}

# Security group for Neptune - only accessible from the two sample subnets
resource "aws_security_group" "neptune_sg" {
  name_prefix = "neptune-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Neptune from subnet1"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet1.cidr_block]
  }

  ingress {
    description = "Neptune from subnet2"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet2.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}
