extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-east-1"
}

# AWS KMS Key for encryption
resource "aws_kms_key" "chime_voice_connector" {
  description             = "KMS key for Amazon Chime Voice Connector encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 7

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Effect = "Allow"
        Principal = {
          Service = "voiceconnector.chime.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

# KMS Key alias
resource "aws_kms_alias" "chime_voice_connector" {
  name          = "alias/chime-voice-connector-key"
  target_key_id = aws_kms_key.chime_voice_connector.key_id
}

# Current AWS account ID
data "aws_caller_identity" "current" {}

# Amazon Chime Voice Connector with encryption and media metrics logging
resource "aws_chime_voice_connector" "main" {
  name                      = "my-voice-connector"
  require_encryption        = true
  kms_key_id                = aws_kms_key.chime_voice_connector.arn

  logging_config {
    enable_media_metric_logs = true
  }

  tags = {
    Name = "MyVoiceConnector"
    Environment = "production"
  }
}

# Output the Voice Connector ID and ARN
output "voice_connector_id" {
  description = "The ID of the Chime Voice Connector"
  value       = aws_chime_voice_connector.main.id
}

output "voice_connector_arn" {
  description = "The ARN of the Chime Voice Connector"
  value       = aws_chime_voice_connector.main.aws_chime_voice_connector_id
}

