provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# SNS Topic for notifications
resource "aws_sns_topic" "chime_voice_connector_notifications" {
  name = "chime-voice-connector-notifications"
}

# IAM role and policy for Chime Voice Connector streaming
resource "aws_iam_role" "chime_streaming_role" {
  name = "chime-voice-connector-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy" "chime_streaming_policy" {
  name = "chime-voice-connector-streaming-policy"
  role = aws_iam_role.chime_streaming_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.chime_voice_connector_notifications.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:*:*"
      }
    ]
  })
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

# Encrypted Chime Voice Connector
resource "aws_chime_voice_connector" "encrypted_voice_connector" {
  name               = "encrypted-voice-connector"
  require_encryption = true

  tags = {
    Name = "EncryptedVoiceConnector"
  }
}

# Chime Voice Connector Streaming Configuration
resource "aws_chime_voice_connector_streaming_configuration" "voice_connector_streaming" {
  voice_connector_id = aws_chime_voice_connector.encrypted_voice_connector.id

  data_retention_in_hours = 5
  streaming_notification_targets {
    sns_topic_arn = aws_sns_topic.chime_voice_connector_notifications.arn
  }
  kinesis {
    disabled = true
  }

  depends_on = [aws_iam_role.chime_streaming_role]
}

