# IAM policy for Kinesis Video Streams access
resource "aws_iam_role_policy" "chime_kinesis_policy" {
  name = "chime-voice-connector-kinesis-policy"
  role = aws_iam_role.chime_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesisvideo:CreateStream",
          "kinesisvideo:DescribeStream",
          "kinesisvideo:GetDataEndpoint",
          "kinesisvideo:PutMedia"
        ]
        Resource = "*"
      }
    ]
  })
}

# Create Kinesis Video Stream
resource "aws_kinesis_video_stream" "chime_media_stream" {
  name        = "chime-voice-connector-media-stream"
  media_type  = "audio/x-alaw"
  retention_period_hours = 24
}

# Create Chime Voice Connector
resource "aws_chime_voice_connector" "main" {
  name               = "chime-voice-connector-main"
  require_encryption = true

  tags = {
    Name = "ChimeVoiceConnector"
  }
}

# Configure Voice Connector streaming configuration for Kinesis Video Streams
resource "aws_chime_voice_connector_streaming_configuration" "kinesis_streaming" {
  voice_connector_id = aws_chime_voice_connector.main.id

  streaming_notification_targets {
    notification_target = aws_kinesis_video_stream.chime_media_stream.arn
  }

  data_retention_in_hours = 24
  media_stream_type       = "Local"
  disabled                = false

  depends_on = [aws_iam_role.chime_kinesis_role]
}

# Attach the IAM role to the Voice Connector (via tagging for service role assumption)
resource "aws_chime_voice_connector_logging_configuration" "logging" {
  voice_connector_id = aws_chime_voice_connector.main.id
  enable_media_metric_logs = true
  enable_sip_logs         = true
}
```

This configuration:

1. Creates an IAM role and policy for Chime Voice Connector to stream media to Kinesis Video Streams
2. Provisions a Kinesis Video Stream to receive the media bypass streams
3. Creates an AWS Chime Voice Connector with encryption enabled
4. Configures the Voice Connector streaming to send media streams to the Kinesis Video Stream
5. Enables logging for monitoring

**Note**: After deployment, you may need to update the Voice Connector service role ARN in the AWS Chime console or via AWS CLI if additional configuration is required for the specific streaming setup. The streaming configuration will route media bypass traffic to Kinesis Video Streams.

