# Provider configuration - update region as needed
provider "aws" {
  region = "us-west-2"
}

# VPC for Redshift cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "redshift-vpc"
  }
}

# Subnet 1
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "redshift-subnet-1"
  }
}

# Subnet 2
resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

# Subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift cluster (parameter group)
resource "aws_redshift_parameter_group" "redshift_param_group" {
  name   = "redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  tags = {
    Name = "redshift-param-group"
  }
}

# Redshift cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier              = "redshift-cluster"
  database_name                   = "mydb"
  master_username                 = "admin"
  master_password                 = "ChangeMe123!"
  node_type                       = "dc2.large"
  cluster_type                    = "multi-node"
  number_of_nodes                 = 2
  cluster_subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.redshift_sg.id]
  cluster_parameter_group_name    = aws_redshift_parameter_group.redshift_param_group.name
  skip_final_snapshot             = true
  final_snapshot_identifier       = "redshift-final-snapshot"
  publicly_accessible             = false
  apply_immediately               = true

  tags = {
    Name = "redshift-cluster"
  }
}

# IAM role for SNS notifications
resource "aws_iam_role" "redshift_sns_role" {
  name = "redshift-sns-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for SNS publishing
resource "aws_iam_role_policy" "redshift_sns_policy" {
  name = "redshift-sns-policy"
  role = aws_iam_role.redshift_sns_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.redshift_events.arn
      }
    ]
  })
}

# SNS topic for Redshift events
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-events-topic"
}

# Attach IAM role policy to role
resource "aws_redshift_cluster_iam_roles" "redshift_iam_roles" {
  cluster_identifier = aws_redshift_cluster.redshift_cluster.id
  iam_role_arn       = aws_iam_role.redshift_sns_role.arn
}

# Redshift event subscription
resource "aws_redshift_event_subscription" "redshift_events_subscription" {
  name                = "redshift-events-subscription"
  event_categories    = ["cluster", "maintenance", "security"]
  enabled             = true
  sns_topic_arn       = aws_sns_topic.redshift_events.arn
  source_ids          = [aws_redshift_cluster.redshift_cluster.id]
  source_type         = "cluster"
  severity            = "INFO"

  depends_on = [aws_redshift_cluster.redshift_cluster]
}

# Optional: SNS topic subscription (email example)
resource "aws_sns_topic_subscription" "redshift_events_email" {
  topic_arn = aws_sns_topic.redshift_events.arn
  protocol  = "email"
  endpoint  = "your-email@example.com"
}

