```hcl
provider "aws" {
  region = "us-west-2"
}

# VPC and subnets for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet_a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "redshift-subnet-a"
  }
}

resource "aws_subnet" "redshift_subnet_b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "redshift-subnet-b"
  }
}

resource "aws_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Redshift Parameter Group
resource "aws_redshift_parameter_group" "redshift_param_group" {
  name   = "redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  parameter {
    name  = "query_timeout"
    value = "600000"
  }

  tags = {
    Name = "redshift-param-group"
  }
}

# Redshift Security Group
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "sample_cluster" {
  cluster_identifier              = "sample-redshift-cluster"
  database_name                   = "sampledb"
  master_username                 = "admin"
  master_password                 = "SamplePassword123!"
  node_type                       = "dc2.large"
  cluster_type                    = "multi-node"
  number_of_nodes                 = 2
  cluster_subnet_group_name       = aws_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.redshift_sg.id]
  cluster_parameter_group_name    = aws_redshift_parameter_group.redshift_param_group.name
  automated_snapshot_retention_period = 7
  publicly_accessible             = false
  skip_final_snapshot             = true

  tags = {
    Name = "sample-redshift-cluster"
  }
}

# SNS Topic for event notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-events-topic"
}

# Redshift Event Subscription tied to the parameter group and cluster events
resource "aws_redshift_event_subscription" "redshift_event_sub" {
  name                = "redshift-event-subscription"
  sns_topic_arn       = aws_sns_topic.redshift_events.arn
  source_type         = "cluster"
  source_ids          = [aws_redshift_cluster.sample_cluster.id]
  event_categories    = ["cluster", "maintenance", "security"]
  enabled             = true

  depends_on = [aws_redshift_cluster.sample_cluster]
}
```

