}

# S3 bucket
resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

# Bucket versioning (required for inventory)
resource "aws_s3_bucket_versioning" "mybucket_versioning" {
  bucket = aws_s3_bucket.mybucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 bucket inventory destination bucket
resource "aws_s3_bucket" "inventory_destination" {
  bucket = "mybucket-inventory-destination"
}

resource "aws_s3_bucket_versioning" "inventory_destination_versioning" {
  bucket = aws_s3_bucket.inventory_destination.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Bucket policy for inventory destination
resource "aws_s3_bucket_policy" "inventory_destination_policy" {
  bucket = aws_s3_bucket.inventory_destination.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AWSBucketInventoryPolicy"
        Effect    = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource  = "${aws_s3_bucket.inventory_destination.arn}/*.csv.gz"
        Condition = {
          StringEquals = {
            "s3:x-amz-acl" = "bucket-owner-full-control"
          }
        }
      }
    ]
  })
}

# S3 bucket inventory configuration
resource "aws_s3_bucket_inventory_configuration" "mybucket_inventory" {
  bucket = aws_s3_bucket.mybucket.id
  id     = "DailyInventory"
  included_object_versions = "All"

  schedule {
    frequency = "Daily"
  }

  destination {
    bucket {
      name          = aws_s3_bucket.inventory_destination.bucket
      account_id    = data.aws_caller_identity.current.account_id
      format        = "CSV"
      prefix        = "inventory"
    }
  }

  filter {
    prefix = ""
  }
}

