extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# S3 bucket to host the PDF file
resource "aws_s3_bucket" "pdf_bucket" {
  bucket = "my-pdf-hosting-bucket-${random_string.bucket_suffix.result}"  # Unique bucket name
}

# Random string to ensure unique bucket name
resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Enable static website hosting
resource "aws_s3_bucket_website_configuration" "pdf_bucket_website" {
  bucket = aws_s3_bucket.pdf_bucket.id

  index_document {
    suffix = "index.html"
  }

  routing_rule {
    redirect {
      replace_key_prefix_with = ""
    }
  }
}

# Bucket policy to allow public read access
resource "aws_s3_bucket_policy" "pdf_bucket_policy" {
  bucket = aws_s3_bucket.pdf_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resources = ["${aws_s3_bucket.pdf_bucket.arn}/*"]
      }
    ]
  })
}

# Upload the PDF file to S3
resource "aws_s3_object" "test_pdf" {
  bucket       = aws_s3_bucket.pdf_bucket.id
  key          = "assets/test.pdf"
  source       = "assets/test.pdf"  # Local path to the PDF file
  content_type = "application/pdf"

  depends_on = [aws_s3_bucket_policy.pdf_bucket_policy]
}

# Optional: Output the website endpoint and direct PDF URL
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.pdf_bucket_website.website_endpoint
}

output "pdf_url" {
  value = "https://${aws_s3_bucket_website_configuration.pdf_bucket_website.website_endpoint}/assets/test.pdf"
}

reference:
resource "aws_s3_bucket" "example" {
  bucket = "test-bucket"
}

resource "aws_s3_object" "object" {
  bucket = "my-bucket"
  key    = "new_object_key"
  source = "assets/test.pdf"
}

response:
```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# S3 bucket to host the PDF file
resource "aws_s3_bucket" "pdf_bucket" {
  bucket = "my-pdf-hosting-bucket-${random_string.bucket_suffix.result}"  # Unique bucket name
}

# Random string to ensure unique bucket name
resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Enable static website hosting
resource "aws_s3_bucket_website_configuration" "pdf_bucket_website" {
  bucket = aws_s3_bucket.pdf_bucket.id

  index_document {
    suffix = "index.html"
  }

  routing_rule {
    redirect {
      replace_key_prefix_with = ""
    }
  }
}

# Bucket policy to allow public read access
resource "aws_s3_bucket_policy" "pdf_bucket_policy" {
  bucket = aws_s3_bucket.pdf_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resources = ["${aws_s3_bucket.pdf_bucket.arn}/*"]
      }
    ]
  })
}

# Upload the PDF file to S3
resource "aws_s3_object" "test_pdf" {
  bucket       = aws_s3_bucket.pdf_bucket.id
  key          = "assets/test.pdf"
  source       = "assets/test.pdf"  # Local path to the PDF file
  content_type = "application/pdf"

  depends_on = [aws_s3_bucket_policy.pdf_bucket_policy]
}

# Optional: Output the website endpoint and direct PDF URL
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.pdf_bucket_website.website_endpoint
}

output "pdf_url" {
  value = "https://${aws_s3_bucket_website_configuration.pdf_bucket_website.website_endpoint}/assets/test.pdf"
}
```

**Note:** Ensure the local file `assets/test.pdf` exists in your working directory before running `terraform apply`. The bucket name is made unique using a random suffix. The PDF will be publicly accessible at the `pdf_url` output.

