terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Object Lock requires US East (N. Virginia) or other supported regions
}

# S3 bucket with Object Lock enabled
resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

# Enable Object Lock on the bucket
resource "aws_s3_bucket_object_lock_configuration" "mybucket" {
  bucket = aws_s3_bucket.mybucket.id

  rule {
    default_retention {
      mode  = "GOVERNANCE"
      days  = 30
    }
  }
}

# Bucket versioning must be enabled for Object Lock
resource "aws_s3_bucket_versioning" "mybucket" {
  bucket = aws_s3_bucket.mybucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

reference:
