provider "aws" {
  region = "us-east-1"
}

# First S3 bucket with access logging enabled
resource "aws_s3_bucket" "primary" {
  bucket = "my-primary-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_logging" "primary_logging" {
  bucket = aws_s3_bucket.primary.id

  target_bucket = aws_s3_bucket.logging.id
  target_prefix = "log/"
}

# Second S3 bucket for storing access logs
resource "aws_s3_bucket" "logging" {
  bucket = "my-logging-bucket-${random_string.bucket_suffix.result}"
}

# Required bucket policy for the logging bucket to allow primary bucket to write logs
resource "aws_s3_bucket_policy" "logging_policy" {
  bucket = aws_s3_bucket.logging.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPrimaryBucketToWriteLogs"
        Effect    = "Allow"
        Principal = {
          Service = "logging.s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource  = "${aws_s3_bucket.logging.arn}/log/*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.primary.arn
          }
        }
      }
    ]
  })
}

# Data source for current AWS account ID
data "aws_caller_identity" "current" {}

# Random suffix to ensure unique bucket names
resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

