resource "aws_codebuild_project" "autograding" {
  name          = "cs-autograding-project"
  description   = "Autograding system for CS course"
  service_role  = aws_iam_role.codebuild_role.arn
  artifacts {
    type = "CODEPIPELINE"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-token-here" # Replace with GitHub token or use SSM/Secrets Manager
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "COURSE_TEST_SCRIPT"
      value = "run_tests.sh" # Main grading script
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/cs-course-submissions.git" # Update with actual repo
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograding"
      stream_name = "autograding-logs"
    }
  }

  # buildspec.yml content embedded
  buildspec = <<EOF
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
      nodejs: 18
    commands:
      - pip install pytest coverage pylint
      - npm install -g mocha
      - echo "Dependencies installed"

  pre_build:
    commands:
      - echo "Student repo: $CODEBUILD_SOURCE_VERSION"
      - |
        if [ -n "$STUDENT_GITHUB_REPO" ]; then
          git clone $STUDENT_GITHUB_REPO student-repo || echo "Clone failed"
          cd student-repo
        fi

  build:
    commands:
      - echo "Running autograding tests..."
      - chmod +x ../${COURSE_TEST_SCRIPT}
      - ../${COURSE_TEST_SCRIPT} > grading-results.txt 2>&1
      - |
        if grep -q "PASS" grading-results.txt; then
          echo "Build succeeded"
          exit 0
        else
          echo "Tests failed - see grading-results.txt"
          exit 1
        fi

  post_build:
    commands:
      - echo "Saving results..."
      - cp grading-results.txt ./results/
      - echo "Grading complete"
artifacts:
  files:
    - results/**/*
    - grading-results.txt
  name: autograding-results
EOF
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/cs-autograding"
  retention_in_days = 30
}

# Optional: EventBridge rule to trigger builds from GitHub webhook
resource "aws_cloudwatch_event_rule" "github_webhook" {
  name        = "cs-autograding-github-trigger"
  description = "Trigger autograding on GitHub push"

  event_pattern = jsonencode({
    source      = ["aws.codecommit"] # or use GitHub via API Gateway
    detail-type = ["CodeCommit Repository State Change"]
  })
}

resource "aws_cloudwatch_event_target" "codebuild_target" {
  rule      = aws_cloudwatch_event_rule.github_webhook.name
  target_id = "autograding-target"
  arn       = aws_codebuild_project.autograding.arn

  role_arn = aws_iam_role.codebuild_event_role.arn
}

