    type      = "S3"
    location  = "${aws_s3_bucket.autograding.bucket}/submissions/${var.student_submission_key}"
    buildspec = "buildspec.yml"
  }

  tags = {
    Project = "CS-Autograding"
  }
}

# S3 bucket policy to allow CodeBuild access
resource "aws_s3_bucket_policy" "autograding" {
  bucket = aws_s3_bucket.autograding.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.codebuild_role.arn
        }
