  content = <<-EOT
    version: 0.2

    phases:
      install:
        runtime-versions:
          python: 3.9
          java: corretto17
          nodejs: 18

      pre_build:
        commands:
          - echo Installing dependencies...
          - pip install -r requirements.txt || true
          - npm install || true

      build:
        commands:
          - echo Running test suite...
          - python -m pytest tests/ -v --junitxml=test-results.xml || true
