      post_build:
        commands:
          - echo Uploading results...
          - aws s3 cp test-results.xml s3://$S3_BUCKET/results/$STUDENT_ID/
          - echo Grading complete
    EOT
  etag = filemd5("${path.module}/buildspec.yml")
}

