          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild",
          "codebuild:BatchGetBuilds"
        ]
        Resource = aws_codebuild_project.autograding.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject"
        ]
        Resource = "${aws_s3_bucket.autograding.arn}/*"
      }
    ]
  })
}

# Lambda function code (inline example - in production use S3 or container)
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "/tmp/autograding_lambda.zip"

  source {
    content = <<-EOT
      import json
      import boto3
      import urllib.request
      import os

      s3 = boto3.client('s3')
      codebuild = boto3.client('codebuild')
      BUCKET = os.environ['S3_BUCKET']

      def lambda_handler(event, context):
          # Extract GitHub payload
          payload = json.loads(event['body'])
          repo = payload['repository']['clone_url']
          student_id = payload['sender']['login']

          # Download repo to S3
          req = urllib.request.Request(repo.replace('https://', 'https://api:token@github.com/') + '/zipball/main')
          with urllib.request.urlopen(req) as response:
              zip_content = response.read()

          s3_key = f"submissions/{student_id}/{payload['head_commit']['id']}.zip"
          s3.put_object(Bucket=BUCKET, Key=s3_key, Body=zip_content)

          # Trigger CodeBuild
          codebuild.start_build(
              projectName='cs-autograding-project',
              environmentVariablesOverride=[
                  {'name': 'STUDENT_ID', 'value': student_id},
                  {'name': 'GITHUB_REPO', 'value': repo},
                  {'name': 'SUBMISSION_KEY', 'value': s3_key}
              ]
          )

          return {'statusCode': 200}
    EOT
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "github_webhook" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "autograding-github-webhook"
  role            = aws_iam_role.lambda_role.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime         = "python3.9"
  timeout         = 30

