  name        = "$default"
  auto_deploy = true
}

# Lambda permission for API Gateway
resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.github_webhook.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.autograding.execution_arn}/*/*"
}

# DynamoDB for grading results tracking
resource "aws_dynamodb_table" "grading_results" {
  name         = "CS-GradingResults"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "student_id"
  range_key    = "submission_id"

