# CloudWatch dashboard for monitoring
resource "aws_cloudwatch_dashboard" "autograding" {
  dashboard_name = "CS-Autograding-Dashboard"

  dashboard_body = jsonencode({
    "widgets": [
      {
        "type": "metric",
