```hcl
provider "aws" {
  region = "us-east-1"
}

# S3 bucket for storing grading outputs and source code
resource "aws_s3_bucket" "grading_outputs" {
  bucket = "cs-course-autograding-outputs-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_versioning" "grading_outputs" {
  bucket = aws_s3_bucket.grading_outputs.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "grading_outputs" {
  bucket = aws_s3_bucket.grading_outputs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_lifecycle_configuration" "grading_outputs" {
  bucket = aws_s3_bucket.grading_outputs.id

  rule {
    id     = "keep-last-30-days"
    status = "Enabled"

    expiration {
      days = 30
    }

    noncurrent_version_expiration {
      noncurrent_days = 7
    }
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild access to S3
resource "aws_iam_role_policy" "codebuild_s3_policy" {
  name = "cs-autograding-s3-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.grading_outputs.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = aws_s3_bucket.grading_outputs.arn
      }
    ]
  })
}

# CloudWatch Logs policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_logs_policy" {
  name = "cs-autograding-logs-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# CodeBuild service role attachment
resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/CloudWatchLogsPolicy"
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "cs-course-autograder"
  description   = "Autograding system for CS course submissions from GitHub"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 1800  # 30 minutes

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_LARGE"  # 4 vCPU, 8 GB memory - suitable for grading
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true  # Required for Docker builds if students use containers

    environment_variable {
      name  = "S3_OUTPUT_BUCKET"
      value = aws_s3_bucket.grading_outputs.bucket
    }

    environment_variable {
      name  = "S3_OUTPUT_PREFIX"
      value = "grading-results/"
    }
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/YOUR_ORG/cs-course-submissions.git"  # Replace with your GitHub repo

    git_clone_depth = 1
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-course-autograder"
      stream_name = "autograder-logs"
    }
  }

  # Sample buildspec - customize for your grading requirements
  buildspec = <<-EOF
    version: 0.2

    phases:
      install:
        runtime-versions:
          python: 3.11
          nodejs: 18
        commands:
          - pip install pytest coverage flake8
          - npm install -g mocha

      pre_build:
        commands:
          - echo "Setting up grading environment..."
          - echo "Assignment: $ASSIGNMENT_ID"
          - echo "Student: $STUDENT_ID"

      build:
        commands:
          - echo "Running tests..."
          # Example grading commands - customize based on your needs
          - python -m pytest tests/ --junitxml=results.xml --cov=submission/ || true
          - coverage report --fail-under=70 > coverage.txt || true
          - flake8 submission/ > flake8.txt || true
          # Generate grading report
          - |
            cat > grading_report.json << 'EOF'
            {
              "student_id": "$STUDENT_ID",
              "assignment_id": "$ASSIGNMENT_ID",
              "pytest_passed": $(python -c "import xml.etree.ElementTree as ET; tree=ET.parse('results.xml'); print('1' if len(tree.findall('.//testcase[not(failure) and not(error)]')) == len(tree.findall('.//testcase')) else '0')"),
              "coverage_percentage": $(python -c "import re; cov_file=open('coverage.txt'); cov_pct=re.search(r'\d+\.?\d+%', cov_file.read()).group(); print(cov_pct.strip('%'))"),
              "flake8_issues": $(wc -l < flake8.txt),
              "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)"
            }
            EOF

      post_build:
        commands:
          - echo "Uploading results to S3..."
          - |
            aws s3 cp grading_report.json s3://$S3_OUTPUT_BUCKET/$S3_OUTPUT_PREFIX$STUDENT_ID/$ASSIGNMENT_ID/grading_report.json
          - |
            aws s3 cp results.xml s3://$S3_OUTPUT_BUCKET/$S3_OUTPUT_PREFIX$STUDENT_ID/$ASSIGNMENT_ID/results.xml --no-guess-mime-type
          - |
            aws s3 cp coverage.txt s3://$S3_OUTPUT_BUCKET/$S3_OUTPUT_PREFIX$STUDENT_ID/$ASSIGNMENT_ID/coverage.txt --no-guess-mime-type
          - |
            aws s3 cp flake8.txt s3://$S3_OUTPUT_BUCKET/$S3_OUTPUT_PREFIX$STUDENT_ID/$ASSIGNMENT_ID/flake8.txt --no-guess-mime-type
          - echo "Grading complete!"

    reports:
      pytest_report:
        files:
          - "results.xml"
        base-directory: "./"
  EOF
}

# Output values
output "s3_bucket_name" {
  description = "Name of the S3 bucket for grading outputs"
  value       = aws_s3_bucket.grading_outputs.bucket
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "codebuild_project_arn" {
  description = "ARN of the CodeBuild project"
  value       = aws_codebuild_project.autograder.arn
}
```

**Key Features:**

1. **S3 Bucket**: Versioned bucket with 30-day lifecycle for storing grading results
2. **CodeBuild Project**: Configured for GitHub source with large compute (4 vCPU, 8GB RAM)
3. **Autograding Pipeline**: Sample buildspec with pytest, coverage, flake8 - easily customizable
4. **Environment Variables**: Supports `$STUDENT_ID` and `$ASSIGNMENT_ID` for dynamic grading
5. **S3 Integration**: Automatically uploads results organized by student/assignment
6. **Security**: Least-privilege IAM policies and private bucket

**To use:**
1. Replace GitHub repo URL in `source.location`
2. Customize buildspec for your specific grading requirements
3. Trigger builds via CodeBuild API/CLI with environment variables:
   ```bash
   aws codebuild start-build \n     --project-name cs-course-autograder \n     --environment-variables-override name=STUDENT_ID,value=student123,name=ASSIGNMENT_ID,value=hw1
   ```

