    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC without internet access
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Network ACL to block all outbound internet traffic
resource "aws_network_acl" "autograder_nacl" {
  vpc_id = aws_vpc.autograder_vpc.id

  subnet_ids = [aws_subnet.private_subnet.id]

  egress {
    rule_no    = 100
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
    protocol   = "all"
  }

  ingress {
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
    protocol   = "all"
  }

  tags = {
    Name = "autograder-nacl"
  }
}

# Security group for CodeBuild - minimal permissions
resource "aws_security_group" "codebuild_sg" {
  name_prefix = "autograder-codebuild"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow SSH from nowhere (CodeBuild doesn't need inbound)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # No egress rules - NACL blocks internet anyway

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# S3 bucket for CodeBuild artifacts and source
resource "aws_s3_bucket" "autograder_source" {
  bucket = "autograder-source-${random_string.bucket_suffix.result}"

  tags = {
    Name = "autograder-source"
  }
}

resource "aws_s3_bucket_versioning" "autograder_source_versioning" {
  bucket = aws_s3_bucket.autograder_source.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# IAM policy for CodeBuild - S3 access + CloudWatch logs + GitHub webhook
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = [
          "${aws_s3_bucket.autograder_source.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograding system for CS course - no internet access"
  service_role  = aws_iam_role.codebuild_role.arn
  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_REPO"
      value = "student-submission-repo" # Replace with actual repo
      type  = "PLAINTEXT"
    }
    environment_variable {
      name  = "TEST_SCRIPT"
      value = "run_tests.sh"
      type  = "PLAINTEXT"
    }
  }

  artifacts {
    type = "S3"
    name = "autograder-artifacts"
    location = aws_s3_bucket.autograder_source.bucket
  }

  source {
    type = "S3"
    location = aws_s3_bucket.autograder_source.bucket
    buildspec = "buildspec.yml"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnet_ids         = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = "autograder-codebuild"
  }
}

# Sample buildspec.yml - uploaded to S3 separately
resource "aws_s3_object" "buildspec" {
  bucket = aws_s3_bucket.autograder_source.id
  key    = "buildspec.yml"
  content = yamlencode({
    version = "0.2"

    env:
      variables:
        TEST_TIMEOUT: "300"

    phases:
      install:
        commands:
          - echo "Installing test dependencies (from cached packages only)"
          - yum install -y git gcc make python3 python3-pip || true

      pre_build:
        commands:
          - echo "Cloning student submission from GitHub (pre-cached)"
          - git clone $GITHUB_REPO student-code

      build:
        commands:
          - echo "Running autograding tests"
          - timeout $TEST_TIMEOUT bash $TEST_SCRIPT > test-results.txt 2>&1
          - |
            if grep -q "PASSED" test-results.txt; then
              echo "BUILD PASSED" > build-status.txt
              exit 0
            else
              echo "BUILD FAILED" > build-status.txt
              exit 1
            fi

      post_build:
        commands:
          - echo "Saving results"
          - cp test-results.txt ./ 
          - cp build-status.txt ./
  })
}

# CloudWatch Logs group
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name_prefix       = "/aws/codebuild/autograder"
  retention_in_days = 30
}

# Lambda function for GitHub webhook trigger (optional)
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = "codebuild:StartBuild"
        Resource = aws_codebuild_project.autograder.arn
      }
    ]
  })
}

# Output important values
output "vpc_id" {
  value = aws_vpc.autograder_vpc.id
}

output "subnet_id" {
  value = aws_subnet.private_subnet.id
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.autograder_source.bucket
}

output "codebuild_role_arn" {
  value = aws_iam_role.codebuild_role.arn
}

