terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC with no internet access for private subnets
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet (no internet)
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# NAT Gateway subnet (for outbound to S3 only)
resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.100.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-public-subnet"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw"
  }
}

# Route table for public subnet
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

resource "aws_route_table_association" "public_rta" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# NAT Gateway for S3 access from private subnet
resource "aws_eip" "nat_eip" {
  domain = "vpc"

  tags = {
    Name = "autograder-nat-eip"
  }
}

resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public_subnet.id

  tags = {
    Name = "autograder-nat-gw"
  }
}

# Private route table (S3 access only via NAT)
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gw.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private_rta" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# S3 bucket for student submissions and grading results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-autograder-${random_string.bucket_suffix.result}"

  tags = {
    Name = "autograder-bucket"
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "autograder_versioning" {
  bucket = aws_s3_bucket.autograder_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_encryption" {
  bucket = aws_s3_bucket.autograder_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_block" {
  bucket = aws_s3_bucket.autograder_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 bucket policy for CodeBuild access
resource "aws_s3_bucket_policy" "autograder_policy" {
  bucket = aws_s3_bucket.autograder_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action   = ["s3:GetObject", "s3:PutObject", "s3:DeleteObject"]
        Resource = "${aws_s3_bucket.autograder_bucket.arn}/*"
      }
    ]
  })
}

# VPC endpoint for S3 (private access)
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id            = aws_vpc.autograder_vpc.id
  service_name      = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private_rt.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# CodeBuild service role policy
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder_bucket.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = "student-repo-url" # Replace with actual GitHub repo
    }

    environment_variable {
      name  = "NO_INTERNET"
      value = "true"
    }
  }

  source {
    type      = "S3"
    location  = "${aws_s3_bucket.autograder_bucket.bucket}/submissions/${var.assignment_id}"
    buildspec = "buildspec.yml"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnet_ids         = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = "cs-autograder"
  }
}

# Security group for CodeBuild (no outbound internet except S3)
resource "aws_security_group" "codebuild_sg" {
  name_prefix = "autograder-codebuild-"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "tcp"
    self        = true
    description = "CodeBuild self"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound (S3 via VPC endpoint)"
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# Sample buildspec.yml content (upload this to S3 separately)
resource "aws_s3_object" "buildspec" {
  bucket       = aws_s3_bucket.autograder_bucket.bucket
  key          = "buildspec.yml"
  source       = "buildspec.yml" # Local file with autograding logic
  content_type = "text/yaml"
}

# Lambda function to trigger grading from GitHub webhook
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild",
          "codebuild:BatchGetBuilds"
        ]
        Resource = aws_codebuild_project.autograder.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject"
        ]
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_lambda_function" "github_trigger" {
  filename         = "lambda_function.zip" # Contains GitHub webhook handler
  function_name    = "autograder-github-trigger"
  role            = aws_iam_role.lambda_role.arn
  handler         = "index.handler"
  runtime         = "python3.9"
  source_code_hash = filebase64sha256("lambda_function.zip")

  vpc_config {
    subnet_ids         = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      S3_BUCKET         = aws_s3_bucket.autograder_bucket.bucket
    }
  }
}

# API Gateway for GitHub webhook endpoint
resource "aws_apigatewayv2_api" "autograder_api" {
  name          = "autograder-webhook"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_integration" "lambda_integration" {
  api_id             = aws_apigatewayv2_api.autograder_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.github_trigger.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "webhook_route" {
  api_id    = aws_apigatewayv2_api.autograder_api.id
  route_key = "POST /webhook"
  target    = "integrations/${aws_apigatewayv2_integration.lambda_integration.id}"
}

resource "aws_apigatewayv2_stage" "default_stage" {
  api_id      = aws_apigatewayv2_api.autograder_api.id
  name        = "$default"
  auto_deploy = true
}

# Lambda permission for API Gateway
resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.github_trigger.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.autograder_api.execution_arn}/*/*"
}

variable "assignment_id" {
  description = "Current assignment ID"
  type        = string
  default     = "assignment1"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.autograder_bucket.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "webhook_url" {
  value = aws_apigatewayv2_api.autograder_api.api_endpoint
}

