provider "aws" {
  region = "us-east-1"
}

# VPC for isolated environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet (no internet access)
resource "aws_subnet" "autograder_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-subnet"
  }
}

# Security group - blocks all outbound internet access
resource "aws_security_group" "autograder_sg" {
  vpc_id = aws_vpc.autograder_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Block all outbound traffic"
  }

  tags = {
    Name = "autograder-sg"
  }
}

# S3 bucket for storing student submissions and grading results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-autograder-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "autograder_bucket_versioning" {
  bucket = aws_s3_bucket.autograder_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_bucket_access" {
  bucket = aws_s3_bucket.autograder_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild to access S3 and ECR
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:log-group:/aws/codebuild/*"
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# ECR repository for autograder Docker image
resource "aws_ecr_repository" "autograder_repo" {
  name = "cs-autograder"

  image_tag_mutability = "MUTABLE"

  image_scanning_configuration {
    scan_on_push = true
  }
}

# CodeBuild project
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_LARGE"
    image           = "${aws_ecr_repository.autograder_repo.repository_url}:latest"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder_bucket.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = "student-submission-repo" # Replace with actual GitHub repo
    }
  }

  source {
    type      = "S3"
    location  = aws_s3_bucket.autograder_bucket.bucket
    buildspec = "buildspec.yml"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnet_ids         = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Name = "cs-autograder"
  }
}

# Sample buildspec.yml content (upload this to S3 separately)
resource "aws_s3_object" "buildspec" {
  bucket = aws_s3_bucket.autograder_bucket.id
  key    = "buildspec.yml"
  content = yamlencode({
    version = "0.2"
    phases = {
      install = {
        commands = [
          "echo Installing dependencies...",
          "apt-get update -y",
          "apt-get install -y git python3 python3-pip"
        ]
      }
      pre_build = {
        commands = [
