        ]
      }
      post_build = {
        commands = [
          "echo Grading complete"
        ]
      }
    }
  })
}

# Lambda trigger for S3 events (optional automation)
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
