      requestId      = "$context.requestId"
      ip             = "$context.identity.sourceIp"
      caller         = "$context.identity.caller"
      user           = "$context.identity.user"
      requestTime    = "$context.requestTime"
      httpMethod     = "$context.httpMethod"
      resourcePath   = "$context.resourcePath"
      status         = "$context.status"
      protocol       = "$context.protocol"
      responseLength = "$context.responseLength"
    })
  }
}

# CloudWatch Log Group for API Gateway
resource "aws_cloudwatch_log_group" "api_logs" {
  name              = "/aws/apigateway/cat-api"
  retention_in_days = 14
}

# Output the API endpoint
output "api_endpoint" {
  value = "${aws_apigatewayv2_stage.default.invocation_url}"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_images.bucket
}
```

**Note:** You'll need to create the following files for the Lambda functions:

**upload_handler.py:**
```python
import json
import boto3
import uuid
from urllib.parse import parse_qs

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body'])
        image_data = body.get('image_data', '').encode()
        filename = f"cat_{uuid.uuid4().hex}.jpg"

        bucket = event['environment']['BUCKET_NAME']
        s3.put_object(Bucket=bucket, Key=filename, Body=image_data, ContentType='image/jpeg')

        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Image uploaded successfully', 'filename': filename})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
```

**random_cat_handler.py:**
```python
import json
import boto3
import random
import urllib.parse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        bucket = event['environment']['BUCKET_NAME']
        objects = s3.list_objects_v2(Bucket=bucket)

        if 'Contents' not in objects or not objects['Contents']:
            return {'statusCode': 404, 'body': json.dumps({'error': 'No cat images found'})}

        random_obj = random.choice(objects['Contents'])
        url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket, 'Key': random_obj['Key']},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'image_url': url})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
```

**Usage:**
- POST `/upload` with JSON `{"image_data": "base64_image_string"}`
- GET `/random` to get a random signed URL for a cat image

