data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content = <<-EOT
      import json
      import boto3
      import urllib.parse
      import uuid
      import os
      import random

      s3 = boto3.client('s3')
      dynamodb = boto3.resource('dynamodb')
      table = dynamodb.Table(os.environ['TABLE_NAME'])
      bucket = os.environ['BUCKET_NAME']

      def lambda_handler(event, context):
          http_method = event['httpMethod']
          resource_path = event['resourcePath']

          if http_method == 'POST' and resource_path == '/upload':
              return handle_upload(event)
          elif http_method == 'GET' and resource_path == '/random':
              return handle_random()
          else:
              return {
                  'statusCode': 404,
                  'body': json.dumps({'error': 'Not found'})
              }

      def handle_upload(event):
          try:
              body = base64.b64decode(event['body'])
              image_id = str(uuid.uuid4())
              key = f"images/{image_id}.jpg"

              s3.put_object(Bucket=bucket, Key=key, Body=body, ContentType='image/jpeg')

              table.put_item(Item={
                  'id': image_id,
                  's3_key': key
              })

              return {
                  'statusCode': 200,
                  'headers': {'Access-Control-Allow-Origin': '*'},
                  'body': json.dumps({'image_id': image_id})
              }
          except Exception as e:
              return {
                  'statusCode': 500,
                  'headers': {'Access-Control-Allow-Origin': '*'},
                  'body': json.dumps({'error': str(e)})
              }

      def handle_random():
          try:
              response = table.scan(Limit=1000)
              items = response['Items']

              if not items:
                  return {
                      'statusCode': 404,
                      'headers': {'Access-Control-Allow-Origin': '*'},
                      'body': json.dumps({'error': 'No images available'})
                  }

              random_item = random.choice(items)
              image_url = f"https://{bucket}.s3.amazonaws.com/{random_item['s3_key']}"

              return {
                  'statusCode': 200,
                  'headers': {'Access-Control-Allow-Origin': '*'},
                  'body': json.dumps({'image_url': image_url})
              }
          except Exception as e:
              return {
                  'statusCode': 500,
                  'headers': {'Access-Control-Allow-Origin': '*'},
                  'body': json.dumps({'error': str(e)})
              }
    EOT
    filename = "lambda_function.py"
  }
}

