  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.cat_app.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "upload_route" {
  api_id    = aws_apigatewayv2_api.cat_app_api.id
  route_key = "POST /upload"
  target    = "integrations/${aws_apigatewayv2_integration.upload_integration.id}"
  api_key_required = false
}

resource "aws_apigatewayv2_integration" "random_integration" {
  api_id             = aws_apigatewayv2_api.cat_app_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.cat_app.invoke_arn
  integration_method = "GET"
}

resource "aws_apigatewayv2_route" "random_route" {
  api_id    = aws_apigatewayv2_api.cat_app_api.id
  route_key = "GET /random"
  target    = "integrations/${aws_apigatewayv2_integration.random_integration.id}"
  api_key_required = false
}

# Lambda Permission for API Gateway
resource "aws_lambda_permission" "api_gateway_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_app.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_app_api.execution_arn}/*/*"
}

resource "aws_lambda_permission" "api_gateway_random" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_app.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_app_api.execution_arn}/*/*"
}

# CORS for API Gateway
resource "aws_apigatewayv2_route" "options_upload" {
  api_id    = aws_apigatewayv2_api.cat_app_api.id
  route_key = "OPTIONS /upload"
  api_key_required = false
  target = "integrations/${aws_apigatewayv2_integration.upload_integration.id}"
  operation_name = "options_upload"
}

resource "aws_apigatewayv2_route" "options_random" {
  api_id    = aws_apigatewayv2_api.cat_app_api.id
  route_key = "OPTIONS /random"
  api_key_required = false
  target = "integrations/${aws_apigatewayv2_integration.random_integration.id}"
  operation_name = "options_random"
}

# Output
output "api_endpoint" {
  value = aws_apigatewayv2_stage.default.invoke_url
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_images.bucket
}
```

**Note:** This configuration uses HTTP API (v2) which is more cost-effective and modern than REST API (v1). The Lambda function handles:

1. **POST /upload** - Uploads cat images to S3 and stores metadata in DynamoDB
2. **GET /random** - Returns a random cat image URL from stored images

Deploy with `terraform init && terraform apply`. The API endpoint will be available in the outputs. Test with curl:

```bash
# Upload (base64 encoded image required)
curl -X POST $API_ENDPOINT/upload -H "Content-Type: application/json" -d '{"body": "BASE64_IMAGE_DATA"}'

# Get random cat
curl $API_ENDPOINT/random
```

