provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "backup-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "backup-igw"
  }
}

# Public Subnet
resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "backup-public-subnet"
  }
}

# Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "backup-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Security Group
resource "aws_security_group" "ec2_backup" {
  name_prefix = "ec2-backup-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-backup-sg"
  }
}

# EC2 Instance
resource "aws_instance" "backup_instance" {
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.ec2_backup.id]
  tags = {
    Name = "backup-instance"
  }
}

# AWS Backup Vault
resource "aws_backup_vault" "backup_vault" {
  name = "ec2-backup-vault"
  tags = {
    Name = "ec2-backup-vault"
  }
}

# Backup Vault Policy (optional - for encryption key access)
resource "aws_backup_vault_policy" "backup_vault_policy" {
  backup_vault_name = aws_backup_vault.backup_vault.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowBackupAdmin"
        Effect    = "Allow"
        Principal = { "AWS" : "*" }
        Action    = "backup:DeleteRecoveryPoint"
        Resource  = aws_backup_vault.backup_vault.arn
      }
    ]
  })
}

# Backup Plan - Daily at 12:00 AM UTC (use cron expression)
resource "aws_backup_plan" "daily_plan" {
  name = "daily-ec2-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at 00:00 UTC (12:00 AM)
    lifecycle {
      delete_after = 30 # Keep backups for 30 days
    }
  }

  tags = {
    Name = "daily-ec2-backup-plan"
  }
}

# Backup Selection for EC2 instance
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  name         = "ec2-backup-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  resources = [
    aws_instance.backup_instance.arn
  ]

  tags {
    key         = "Backup"
    value       = "Daily"
    selection_type = "BY_TAG"
  }

  depends_on = [aws_backup_plan.daily_plan]
}

