      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy attachment for basic Lambda execution
resource "aws_iam_role_policy_attachment" "lambda_basic_exec" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Simple Lambda function (replace with your actual code)
resource "aws_lambda_function" "daily_task" {
  filename         = "lambda.zip"  # Upload your code as lambda.zip
  function_name    = "daily-task-function"
  role            = aws_iam_role.lambda_exec_role.arn
  handler         = "index.handler"
  runtime         = "nodejs18.x"
  source_code_hash = filebase64sha256("lambda.zip")

  # Example: logs retention
  depends_on = [aws_iam_role_policy_attachment.lambda_basic_exec]
}

# EventBridge rule for daily schedule at 07:00 UTC
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-task-rule"
  schedule_expression = "cron(0 7 * * ? *)"  # 07:00 UTC every day
  description         = "Run daily task at 07:00 UTC"
}

# EventBridge target - Lambda function
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "daily-task-lambda"
  arn       = aws_lambda_function.daily_task.arn
}

# Lambda permission to allow EventBridge invocation
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_schedule.arn
}
```

**Note:** Create a `lambda.zip` file with your code (e.g., `index.js` with `exports.handler = async () => { console.log('Daily task executed!'); return { statusCode: 200 }; };`). Run `terraform init`, `terraform plan`, and `terraform apply` to deploy.

