  handler         = "index.handler"  # Adjust based on your Lambda runtime and handler
  runtime         = "nodejs18.x"     # Adjust runtime as needed
  source_code_hash = filebase64sha256("lambda.zip")

  # Optional: Add environment variables, VPC config, etc.
}

