provider "aws" {
  region = "us-east-1"  # CloudFront and Route 53 require us-east-1 for some resources
}

# S3 bucket for video content (origin for CloudFront)
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-platform-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "Video Streaming Content"
    Environment = "Production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Enable versioning and server-side encryption
resource "aws_s3_bucket_versioning" "video_content" {
  bucket = aws_s3_bucket.video_content.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 bucket policy for CloudFront access
resource "aws_s3_bucket_policy" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowCloudFront"
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.streaming.arn
          }
        }
      }
    ]
  })
}

# CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "video_content_oac" {
  name                              = "video-streaming-oac"
  description                       = "OAC for video streaming S3 bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution with global CDN configuration
resource "aws_cloudfront_distribution" "streaming" {
  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"
  comment             = "Global video streaming CDN"

  # Default cache behavior optimized for video streaming
  default_cache_behavior {
    allowed_methods        = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = aws_s3_bucket.video_content.bucket_regional_domain_name
    compress               = true
    viewer_protocol_policy = "redirect-to-https"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    # Video streaming optimizations
    min_ttl     = 0
    default_ttl = 3600
    max_ttl     = 86400

    smooth_streaming = true
  }

  # Price class for global distribution (All regions)
  price_class = "PriceClass_100"

  # Global distribution with multiple edge locations
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # SSL certificate (request public certificate via ACM)
  viewer_certificate {
    cloudfront_default_certificate = true
  }

  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id                = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.video_content_oac.id
  }

  # Custom error pages
  custom_error_response {
    error_code         = 404
    response_code      = 200
    response_page_path = "/index.html"
  }

  tags = {
    Name        = "Video Streaming CDN"
    Environment = "Production"
  }

  # Web Application Firewall (WAF)
  web_acl_id = aws_wafv2_web_acl.streaming.arn
}

# ACM Certificate for custom domain (prerequisite: validate via DNS)
resource "aws_acm_certificate" "streaming" {
  domain_name       = "streaming.example.com"
  validation_method = "DNS"

  tags = {
    Environment = "Production"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Route 53 Hosted Zone
data "aws_route53_zone" "main" {
  name         = "example.com"
  private_zone = false
}

# Route 53 Record pointing to CloudFront
resource "aws_route53_record" "streaming" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "streaming.${data.aws_route53_zone.main.name}"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.streaming.domain_name
    zone_id                = aws_cloudfront_distribution.streaming.hosted_zone_id
    evaluate_target_health = false
  }
}

# WAF Web ACL for bot protection and security
resource "aws_wafv2_web_acl" "streaming" {
  name  = "video-streaming-waf"
  scope = "CLOUDFRONT"

  default_action {
    allow {}
  }

  # Rate limiting
  rule {
    name     = "RateLimit"
    priority = 1

    action {
      block {}
    }

    statement {
      rate_based_statement {
        limit              = 2000
        aggregate_key_type = "IP"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "RateLimit"
      sampled_requests_enabled   = true
    }
  }

  # AWS Managed Rules for bot control
  rule {
    name     = "BotControl"
    priority = 2

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesBotControlRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "BotControl"
      sampled_requests_enabled   = true
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "VideoStreamingWAF"
    sampled_requests_enabled   = true
  }
}

# Lambda@Edge for advanced caching and personalization (optional)
resource "aws_lambda_function" "edge_viewer_request" {
  filename         = "lambda_edge.zip"  # Upload your Lambda code
  function_name    = "video-streaming-viewer-request"
  role            = aws_iam_role.lambda_edge.arn
  handler         = "index.handler"
  runtime         = "nodejs18.x"
  publish         = true
  source_code_hash = filebase64sha256("lambda_edge.zip")

  # Lambda@Edge requires us-east-1
  provider = aws.us_east_1
}

resource "aws_iam_role" "lambda_edge" {
  name = "lambda-edge-role-video-streaming"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = [
            "lambda.amazonaws.com",
            "edgelambda.amazonaws.com"
          ]
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_edge_basic" {
  role       = aws_iam_role.lambda_edge.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda@Edge association with CloudFront (add to cache behavior after creation)
resource "aws_cloudfront_distribution" "streaming_with_lambda" {
  # ... (same config as above but add this to default_cache_behavior)
  # lambda_function_association {
  #   event_type   = "viewer-request"
  #   lambda_arn   = aws_lambda_function.edge_viewer_request.qualified_arn
  #   include_body = false
  # }
}

# Output important values
output "cloudfront_domain" {
  description = "CloudFront distribution domain"
  value       = aws_cloudfront_distribution.streaming.domain_name
}

output "s3_bucket_name" {
  description = "S3 bucket for video content"
  value       = aws_s3_bucket.video_content.id
}

output "route53_record_name" {
  description = "Route 53 record name"
  value       = aws_route53_record.streaming.fqdn
}

output "waf_web_acl_arn" {
  description = "WAF Web ACL ARN"
  value       = aws_wafv2_web_acl.streaming.arn
}
```

This configuration creates a production-ready, globally distributed video streaming platform with:

1. **S3 bucket** with versioning, encryption, and CloudFront-only access
2. **CloudFront CDN** with global edge locations, video streaming optimizations, and HTTPS
3. **Route 53** DNS routing to CloudFront
4. **WAF** with rate limiting and bot protection
5. **OAC** for secure S3 access
6. **Lambda@Edge** foundation for advanced features
7. **ACM certificate** ready for custom domain validation

**Next steps:**
1. Replace `example.com` with your domain
2. Validate ACM certificate via DNS
3. Upload video content to S3 bucket
4. Deploy Lambda@Edge code (optional)
5. Update CloudFront to use custom certificate

