  name = "netflix.com"
}

# Route53 Record for CloudFront (A record with alias)
resource "aws_route53_record" "netflix_cloudfront" {
  zone_id = aws_route53_zone.netflix.zone_id
  name    = "video.netflix.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.netflix_video.domain_name
    zone_id                = aws_cloudfront_distribution.netflix_video.hosted_zone_id
    evaluate_target_health = false
  }
}

# Route53 Record for apex domain (example CNAME - note: apex typically uses A/AAAA)
resource "aws_route53_record" "netflix_apex" {
  zone_id = aws_route53_zone.netflix.zone_id
  name    = "netflix.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_cloudfront_distribution.netflix_video.domain_name]
}

