terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket (assumed to exist, referenced by name)
# resource "aws_s3_bucket" "video_content" {
#   bucket = "netflix-video-content.example.com"
# }

# CloudFront Origin Access Control
resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "netflix-s3-oac"
  description                       = "OAC for Netflix S3 video content"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "netflix_video" {
  origin {
    domain_name              = "netflix-video-content.example.com.s3.amazonaws.com"  # Replace with your S3 bucket domain
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = "s3_video_content_origin"
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "s3_video_content_origin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  price_class = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  tags = {
    Environment = "production"
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "netflix" {
  name = "netflix.com"
}

# Route53 Record for CloudFront (A record with alias)
resource "aws_route53_record" "netflix_cloudfront" {
  zone_id = aws_route53_zone.netflix.zone_id
  name    = "video.netflix.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.netflix_video.domain_name
    zone_id                = aws_cloudfront_distribution.netflix_video.hosted_zone_id
    evaluate_target_health = false
  }
}

# Route53 Record for apex domain (example CNAME - note: apex typically uses A/AAAA)
resource "aws_route53_record" "netflix_apex" {
  zone_id = aws_route53_zone.netflix.zone_id
  name    = "netflix.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_cloudfront_distribution.netflix_video.domain_name]
}
```

