```hcl
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
  enable_vpn_gateway = false

  tags = {
    Name = "video-streaming-vpc"
  }
}

# Security Group for EC2 instances
resource "aws_security_group" "ec2_sg" {
  name_prefix = "video-streaming-ec2-"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "video-streaming-ec2-sg"
  }
}

# Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name_prefix = "video-streaming-alb-"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "video-streaming-alb-sg"
  }
}

# ALB Target Group
resource "aws_lb_target_group" "streaming_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    unhealthy_threshold = 2
  }

  tags = {
    Name = "video-streaming-tg"
  }
}

# Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "video-streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-streaming-alb"
  }
}

# ALB Listener
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# EC2 Instances (3 servers for load distribution)
resource "aws_instance" "streaming_server" {
  count         = 3
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 AMI (update for your region)
  instance_type = "t3.medium"
  subnet_id     = element(module.vpc.private_subnets, count.index % 2)

  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  user_data = base64encode(templatefile("${path.module}/userdata.sh", {
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }))

  tags = {
    Name = "video-streaming-server-${count.index + 1}"
  }
}

# Attach EC2 instances to target group
resource "aws_lb_target_group_attachment" "streaming_tg_attachment" {
  count            = 3
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_server[count.index].id
  port             = 80
}

# Route53 Hosted Zone
resource "aws_route53_zone" "streaming_zone" {
  name = "streaming.example.com"
}

# Route53 Record pointing to ALB
resource "aws_route53_record" "streaming_record" {
  zone_id = aws_route53_zone.streaming_zone.zone_id
  name    = "app.streaming.example.com"
  type    = "A"

  aliases {
    name                   = aws_lb.streaming_alb.dns_name
    zone_id                = aws_lb.streaming_alb.zone_id
    evaluate_target_health = true
  }
}

# Output important values
output "alb_dns_name" {
  value = aws_lb.streaming_alb.dns_name
}

output "route53_zone_id" {
  value = aws_route53_zone.streaming_zone.zone_id
}

output "route53_record_name" {
  value = aws_route53_record.streaming_record.fqdn
}
```

**Note:** Create a `userdata.sh` file with the following content for the EC2 instances:

```bash
#!/bin/bash
yum update -y
yum install -y httpd
systemctl start httpd
systemctl enable httpd
echo "<h1>Video Streaming Server $(hostname)</h1>" > /var/www/html/index.html

# Install AWS CLI and configure target group health check
yum install -y awscli
aws configure set default.region us-east-1

# Register instance with target group (handled by Terraform attachment)
```

This configuration creates:
- VPC with public/private subnets and NAT gateway
- Security groups for ALB and EC2 instances
- Application Load Balancer with target group
- 3 EC2 instances in private subnets for load distribution
- Route53 hosted zone and DNS record pointing to ALB
- Auto-scaling ready target group attachments

