  name_prefix = "db-sg-"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL access from VPC CIDR (reachable within VPC)
  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  # Allow SSH access to bastion or app servers (optional, customize as needed)
  ingress {
    description = "SSH from VPC"
