provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "postgres-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "postgres-igw"
  }
}

# Public Subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Security Group for PostgreSQL (allows SSH and Postgres from anywhere - adjust for production)
resource "aws_security_group" "postgres_sg" {
  name_prefix = "postgres-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "PostgreSQL"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-security-group"
  }
}

# EC2 Instance for PostgreSQL 17.1 (5GB instance - t3.small with custom volume)
resource "aws_instance" "postgres" {
  ami           = "ami-0e86e20dae922d783" # Amazon Linux 2023 AMI (update to latest)
  instance_type = "t3.small"
  subnet_id     = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  key_name      = "your-key-pair" # Replace with your existing key pair name

  root_block_device {
    volume_size = 8
    volume_type = "gp3"
  }

  user_data = <<-EOF
#!/bin/bash
yum update -y
yum install -y postgresql17-server postgresql17
postgresql17-setup initdb
systemctl enable postgresql-17
systemctl start postgresql-17
sudo -u postgres psql -c "ALTER USER postgres PASSWORD 'admin123';"
sudo -u postgres psql -c "CREATE DATABASE mydb;"
firewall-cmd --permanent --add-port=5432/tcp
firewall-cmd --reload
EOF

  tags = {
    Name = "postgres-17-instance"
  }
}

# Output the public IP for connection
output "postgres_public_ip" {
  value = aws_instance.postgres.public_ip
}

output "postgres_endpoint" {
  value = "postgres://${aws_instance.postgres.public_ip}:5432/postgres"
}

