  name       = "mysql-subnet-group"
  subnet_ids = [aws_subnet.public.id]

  tags = {
    Name = "mysql-subnet-group"
  }
}

# Database Security Group
resource "aws_security_group" "database" {
  name_prefix = "mysql-db-sg-"
  vpc_id      = aws_vpc.main.id

  # Allow MySQL port 3306 from anywhere (adjust as needed for production)
  ingress {
    description = "MySQL access"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH access to EC2 instances that might need DB access
  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-db-security-group"
  }
}

# RDS MySQL Instance
