terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Configure the AWS Provider
provider "aws" {
  region = var.aws_region
}

# Variables
variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "vpc_id" {
  description = "Existing VPC ID"
  type        = string
}

variable "public_subnet_ids" {
  description = "List of public subnet IDs"
  type        = list(string)
}

variable "db_username" {
  description = "Database administrator username"
  type        = string
  default     = "airbyte"
}

variable "db_password" {
  description = "Database administrator password"
  type        = string
  sensitive   = true
}

# Data sources for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# RDS PostgreSQL Subnet Group using public subnets
resource "aws_db_subnet_group" "airbyte_test" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = var.public_subnet_ids

  tags = {
    Name = "airbyte-test-subnet-group"
  }
}

# RDS PostgreSQL 15 Instance
resource "aws_db_instance" "airbyte_test" {
  identifier              = "airbyte-test-db"
  engine                  = "postgres"
  engine_version          = "15.5"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  storage_type            = "gp3"
  storage_encrypted       = true
  db_name                 = "airbyte_test"
  username                = var.db_username
  password                = var.db_password
  vpc_security_group_ids  = [aws_security_group.rds_public.id]
  db_subnet_group_name    = aws_db_subnet_group.airbyte_test.name

  # Publicly accessible for connector testing
  publicly_accessible     = true

  # Managed configuration - automatic backups, maintenance, etc.
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"
  auto_minor_version_upgrade = true

  # Deletion protection for safety
  deletion_protection     = false

  # Performance insights and enhanced monitoring
  performance_insights_enabled = true
  monitoring_interval     = 60
  monitoring_role_arn     = aws_iam_role.rds_monitoring.arn

  # Parameter group for PostgreSQL optimizations
  parameter_group_name    = aws_db_parameter_group.postgres15.name

  skip_final_snapshot     = true

  tags = {
    Name        = "airbyte-test-postgres"
    Environment = "test"
  }
}

# Security Group for RDS (allow all inbound from anywhere for testing - restrict in production)
resource "aws_security_group" "rds_public" {
  name_prefix = "airbyte-rds-public-"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-public"
  }
}

# RDS Enhanced Monitoring Role
resource "aws_iam_role" "rds_monitoring" {
  name = "rds-monitoring-role-airbyte"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "monitoring.rds.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_monitoring" {
  role       = aws_iam_role.rds_monitoring.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
}

# PostgreSQL 15 Parameter Group
resource "aws_db_parameter_group" "postgres15" {
  name   = "airbyte-postgres15-params"
  family = "postgres15"

  parameter {
    name  = "log_destination"
    value = "stderr"
  }

  parameter {
    name  = "logging_collector"
    value = "on"
  }

  parameter {
    name  = "log_statement"
    value = "all"
  }

  tags = {
    Name = "airbyte-postgres15-params"
  }
}

# Output the connection details
output "db_endpoint" {
  description = "RDS PostgreSQL endpoint"
  value       = aws_db_instance.airbyte_test.endpoint
}

output "db_port" {
  description = "RDS PostgreSQL port"
  value       = aws_db_instance.airbyte_test.port
}

output "db_username" {
  description = "Database username"
  value       = aws_db_instance.airbyte_test.username
}

output "db_name" {
  description = "Database name"
  value       = aws_db_instance.airbyte_test.db_name
}

