  maintenance_window     = "sun:04:00-sun:05:00"

  skip_final_snapshot = true
  deletion_protection = false

  # Performance insights and monitoring
  performance_insights_enabled          = true
  performance_insights_retention_period = 7
  monitoring_interval                   = 60
  monitoring_role_arn                   = aws_iam_role.rds_monitoring.arn

  # Parameters for PostgreSQL optimization
  parameter_group_name = aws_db_parameter_group.postgres15.id

  tags = {
    Name        = "airbyte-test-postgres"
    Environment = "test"
    Purpose     = "airbyte-connector-tests"
  }
}

# Security group for public RDS access
resource "aws_security_group" "rds_public" {
  name_prefix = "airbyte-rds-public-"
  vpc_id      = data.aws_vpc.selected.id

  ingress {
    description = "PostgreSQL access"
