  }
}

# Route table for public subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Private subnet for RDS
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet"
  }
}

# NAT Gateway for private subnet outbound traffic
resource "aws_eip" "nat" {
  domain = "vpc"

  tags = {
    Name = "nat-eip"
  }
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "nat-gw"
  }

  depends_on = [aws_internet_gateway.main]
}

# Route table for private subnet
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }

  tags = {
    Name = "private-rt"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# VPC Security Group for RDS
resource "aws_security_group" "rds" {
  name_prefix = "postgres-rds-"
  vpc_id      = aws_vpc.main.id

  # Allow inbound PostgreSQL traffic from within VPC
  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-rds-sg"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.private.id]

  tags = {
    Name = "postgres-subnet-group"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier             = "postgres-db"
  engine                 = "postgres"
  engine_version         = "15.4"  # Latest PostgreSQL 15 minor version
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true

  # Networking
  vpc_security_group_ids         = [aws_security_group.rds.id]
  db_subnet_group_name           = aws_db_subnet_group.main.name
  publicly_accessible            = false

  # Credentials (use secrets manager or variables in production)
  username = "postgresadmin"
  password = "SecurePassword123!"

  # Backup and maintenance
  backup_retention_period      = 7
  backup_window                = "03:00-04:00"
  maintenance_window           = "sun:04:00-sun:05:00"
  preferred_maintenance_window = "sun:04:00-sun:05:00"

  # Upgrades and patching
  allow_major_version_upgrade     = true
  auto_minor_version_upgrade      = true
  apply_immediately               = true

  # Deletion protection (remove for production if needed)
  deletion_protection = false
  skip_final_snapshot = true

  # Performance insights (optional)
  performance_insights_enabled = true

  tags = {
    Name = "postgres-database"
  }
}

# Output the RDS endpoint
output "postgres_endpoint" {
  description = "The endpoint of the PostgreSQL instance"
  value       = aws_db_instance.postgres.endpoint
}

