resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }

  tags = {
    Name = "aurora-private-rt"
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id
}

# Security Groups
resource "aws_security_group" "aurora" {
  name_prefix = "aurora-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
    description = "Aurora MySQL"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-sg"
  }
}

resource "aws_security_group" "rds_proxy" {
  name_prefix = "rds-proxy-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.aurora.id]
  }

  egress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.aurora.id]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Secrets Manager Secret for DB Credentials
resource "aws_secretsmanager_secret" "db_master" {
  name_prefix = "aurora-master-secret-"
  description = "Master password for Aurora MySQL cluster"

  tags = {
    Name = "aurora-master-secret"
  }
}

resource "aws_secretsmanager_secret_version" "db_master" {
  secret_id     = aws_secretsmanager_secret.db_master.id
  secret_string = jsonencode({
    username = "admin"
    password = "SecurePassword123!"
    engine   = "mysql"
    host     = ""
    port     = 3306
  })
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy" {
  name_prefix = "rds-proxy-role-"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_secrets" {
  role       = aws_iam_role.rds_proxy.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSCustomForSQLServer"
}

resource "aws_iam_role_policy" "rds_proxy_secret_access" {
  name_prefix = "rds-proxy-secret-access-"
  role        = aws_iam_role.rds_proxy.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.db_master.arn
      }
    ]
  })
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.02.0"
  availability_zones      = ["us-east-1a", "us-east-1b"]
  database_name           = "mydatabase"
  master_username         = jsondecode(data.aws_secretsmanager_secret_version.db_master.secret_string)["username"]
  manage_master_user_password = true
  master_user_secret {
    secret_arn = aws_secretsmanager_secret.db_master.arn
  }
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  storage_encrypted       = true
  vpc_security_group_ids  = [aws_security_group.aurora.id]
  db_subnet_group_name    = aws_db_subnet_group.aurora.name
  skip_final_snapshot     = true

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# Aurora Cluster Instances
resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 2
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version

  tags = {
    Name = "aurora-instance-${count.index}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# RDS Proxy
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy.arn
  vpc_security_group_ids = [aws_security_group.rds_proxy.id]
  vpc_subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-proxy-auth"
    secret_arn  = aws_secretsmanager_secret.db_master.arn
    iam_auth    = "DISABLED"
  }

  tags = {
    Name = "aurora-proxy"
  }
}

# RDS Proxy Target
resource "aws_db_proxy_target" "aurora_target" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name
  target_group_name = aws_db_proxy_default_target_group.main.name
  db_cluster_name   = aws_rds_cluster.aurora.id
}

resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    max_connections_percent = 100
    max_idle_connections_percent = 50
  }

  depends_on = [aws_db_proxy.aurora_proxy]
}
```

**Note:** This configuration assumes a public subnet exists for the NAT Gateway (add `aws_subnet.public_a` if needed). The master password is set via Secrets Manager for security. Connect to the RDS Proxy endpoint instead of the cluster endpoint for production use. Adjust instance classes, regions, and passwords as needed for your environment.

