provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Generate a distinct RSA key pair for Lightsail
resource "tls_private_key" "lightsail_ssh" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Save the private key to a local file (for user access)
resource "local_file" "lightsail_ssh_private_key" {
  content         = tls_private_key.lightsail_ssh.private_key_pem
  filename        = "${path.module}/lightsail_ssh_key.pem"
  file_permission = "0600"
}

# Save the public key to a local file
resource "local_file" "lightsail_ssh_public_key" {
  content             = tls_private_key.lightsail_ssh.public_key_openssh
  filename            = "${path.module}/lightsail_ssh_key.pub"
  file_permission     = "0644"
}

# Create Lightsail key pair
resource "aws_lightsail_key_pair" "lightsail_instance" {
  key_pair_name = "lightsail-instance-key"
  public_key    = tls_private_key.lightsail_ssh.public_key_openssh
}

# Create Lightsail instance with the custom key pair
resource "aws_lightsail_instance" "example" {
  name              = "example-instance"
  availability_zone = "us-east-1a"  # Adjust to your region
  blueprint_id      = "amazon_linux_2"  # Amazon Linux 2 blueprint
  bundle_id         = "nano_2_0"         # nano bundle (smallest)

  key_pair_name = aws_lightsail_key_pair.lightsail_instance.key_pair_name
}

# Output the instance details
output "instance_public_ip" {
  value = aws_lightsail_instance.example.public_ip_address
}

output "ssh_private_key_path" {
  value       = local_file.lightsail_ssh_private_key.filename
  description = "Path to the private key file for SSH access"
}

output "ssh_command" {
  value       = "ssh -i ${local_file.lightsail_ssh_private_key.filename} ec2-user@${aws_lightsail_instance.example.public_ip_address}"
  description = "SSH command to connect to the instance"
}

