provider "aws" {
  region = "us-east-1"
}

# VPC for Lightsail managed database
resource "aws_vpc" "lightsail_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "lightsail-vpc"
  }
}

resource "aws_subnet" "lightsail_subnet" {
  vpc_id            = aws_vpc.lightsail_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "lightsail-subnet"
  }
}

# Lightsail managed database (PostgreSQL example)
resource "aws_lightsail_database" "managed_db" {
  relational_database_name      = "my-managed-db"
  relational_database_blueprint_id = "postgres_15"  # PostgreSQL 15
  relational_database_bundle_id = "micro_1_0"       # Smallest bundle
  skip_final_snapshot          = true
  availability_zone            = "us-east-1a"

  relational_database_master_database_name = "mydb"
  relational_database_master_user_password = "SecurePassword123!"

  # Backup settings
  backup_retention_enabled = true

  # Apply immediately
  apply_immediately = true

  tags = {
    Name = "my-managed-database"
  }
}

# Lightsail instance that can connect to the database
resource "aws_lightsail_instance" "app_instance" {
  name              = "my-app-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # Amazon Linux 2
  bundle_id         = "nano_2_0"        # Nano bundle

  # User data to configure database connection
  user_data = templatefile("${path.module}/user_data.sh", {
    db_endpoint = aws_lightsail_database.managed_db.relational_database_endpoint
    db_port     = aws_lightsail_database.managed_db.relational_database_master_endpoint_port
    db_name     = "mydb"
    db_user     = "admin"
    db_password = "SecurePassword123!"
  })

  depends_on = [aws_lightsail_database.managed_db]

  tags = {
    Name = "my-app-instance"
  }
}

# Output important information
output "database_endpoint" {
  description = "Database endpoint"
  value       = aws_lightsail_database.managed_db.relational_database_endpoint
}

output "database_port" {
  description = "Database port"
  value       = aws_lightsail_database.managed_db.relational_database_master_endpoint_port
}

output "instance_public_ip" {
  description = "Lightsail instance public IP"
  value       = aws_lightsail_instance.app_instance.public_ip
}

