terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# Lightsail instance
resource "aws_lightsail_instance" "example" {
  name              = "my-lightsail-server"
  availability_zone = "us-west-2a"
  blueprint_id      = "amazon_linux_2"  # Amazon Linux 2 blueprint
  bundle_id         = "nano_2_0"        # nano bundle (adjust as needed)

  # User data to format and mount additional disks
  user_data = <<-EOF
#!/bin/bash
# Wait for disks to be attached
sleep 30

# Format and mount /dev/xvdb as /data1 (first additional disk)
if ! blkid /dev/xvdb; then
  mkfs.ext4 /dev/xvdb
  mkdir -p /data1
  mount /dev/xvdb /data1
  echo '/dev/xvdb /data1 ext4 defaults,nofail 0 2' >> /etc/fstab
fi

# Format and mount /dev/xvdc as /data2 (second additional disk)
if ! blkid /dev/xvdc; then
  mkfs.ext4 /dev/xvdc
  mkdir -p /data2
  mount /dev/xvdc /data2
  echo '/dev/xvdc /data2 ext4 defaults,nofail 0 2' >> /etc/fstab
fi
EOF
}

# Additional block storage disk 1 (128 GB)
resource "aws_lightsail_disk" "disk1" {
  name              = "disk-1"
  size_in_gb        = 128
  availability_zone = "us-west-2a"
}

# Additional block storage disk 2 (256 GB)
resource "aws_lightsail_disk" "disk2" {
  name              = "disk-2"
  size_in_gb        = 256
  availability_zone = "us-west-2a"
}

# Attach disk 1 to the instance
resource "aws_lightsail_disk_attachment" "disk1_attachment" {
  disk_name       = aws_lightsail_disk.disk1.name
  instance_name   = aws_lightsail_instance.example.name
  disk_path       = "/dev/xvdb"
  depends_on      = [aws_lightsail_instance.example]
}

# Attach disk 2 to the instance
resource "aws_lightsail_disk_attachment" "disk2_attachment" {
  disk_name       = aws_lightsail_disk.disk2.name
  instance_name   = aws_lightsail_instance.example.name
  disk_path       = "/dev/xvdc"
  depends_on      = [aws_lightsail_instance.example]
}

# Output the instance details
output "instance_public_ip" {
  value = aws_lightsail_instance.example.public_ip_address
}

output "instance_id" {
  value = aws_lightsail_instance.example.id
}

