provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Create an AWS Certificate Manager (ACM) certificate
resource "aws_acm_certificate" "lightsail_cert" {
  domain_name       = "example.com"  # Replace with your domain
  validation_method = "DNS"

  tags = {
    Name = "lightsail-cert"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Certificate validation (DNS validation record)
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.lightsail_cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = aws_route53_zone.example_zone.zone_id  # Replace with your hosted zone ID
}

# Validate the certificate
resource "aws_acm_certificate_validation" "lightsail_cert_validation" {
  certificate_arn         = aws_acm_certificate.lightsail_cert.arn
  validation_record_fqdns = [for record in aws_route53_record.cert_validation : record.fqdn]
}

