resource "aws_lightsail_instance" "example" {
  name              = "lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # or your preferred blueprint
  bundle_id         = "nano_2_0"        # or your preferred bundle

  tags = {
    Name = "lightsail-example"
  }
}

# Example Lightsail load balancer that can use the ACM certificate
