  name                  = "lightsail-lb"
  instance_ports        = { "HTTP" = 80, "HTTPS" = 443 }
  health_check_path     = "/"
  certificate_name      = aws_acm_certificate.lightsail_cert.id  # Attach the certificate
  certificate_alternative_names = ["www.example.com"]  # Optional SANs

  target {
    instance_name = aws_lightsail_instance.example.id
    port          = 80
  }

  tags = {
    Name = "lightsail-lb"
  }
}

# Required: Route 53 hosted zone (replace with your actual zone)
resource "aws_route53_zone" "example_zone" {
  name = "example.com"  # Replace with your domain
}

