extracted_code:
# Terraform configuration for AWS Lightsail Distribution with S3 origin

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Lightsail Distributions are global, but provider region must be specified
}

# S3 bucket for the origin
resource "aws_s3_bucket" "origin_bucket" {
  bucket = "my-lightsail-origin-bucket"
}

resource "aws_s3_bucket_acl" "origin_bucket_acl" {
  bucket = aws_s3_bucket.origin_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_public_access_block" "origin_bucket_public_access" {
  bucket = aws_s3_bucket.origin_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 bucket policy to allow Lightsail Distribution access
resource "aws_s3_bucket_policy" "origin_bucket_policy" {
  bucket = aws_s3_bucket.origin_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "LightsailDistributionAccess"
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.origin_bucket.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_lightsail_distribution.distribution.arn
          }
        }
      }
    ]
  })
}

# CloudFront Origin Access Identity (OAI) for secure S3 access
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for Lightsail Distribution S3 origin"
}

# Update S3 policy to include CloudFront OAI (alternative approach)
resource "aws_s3_bucket_policy" "origin_bucket_policy_oai" {
  depends_on = [aws_s3_bucket.origin_bucket]
  bucket     = aws_s3_bucket.origin_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudFrontOAI"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_origin_access_identity.oai.id}"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.origin_bucket.arn}/*"
      }
    ]
  })
}

# Lightsail Distribution with S3 origin
resource "aws_lightsail_distribution" "distribution" {
  name = "my-s3-origin-distribution"

  origin {
    name       = "S3Origin"
    region_name = "us-east-1"
    protocol_policy = "http-only"

    # For S3 origin, specify the bucket domain name
    domain_name = aws_s3_bucket.origin_bucket.bucket_regional_domain_name
  }

  default_cache_behavior {
    target_origin_id       = "S3Origin"
    behavior               = "dont-cache"
    viewer_protocol_policy = "redirect-to-https"
  }

  is_enabled = true

  # Optional: Add custom domain (requires Route53 or external DNS)
  # domain_name = "example.com"
  # domain_name_aliases = ["www.example.com"]

  tags = {
    Environment = "production"
    Project     = "lightsail-s3-distribution"
  }
}

# Optional: Sample content in S3 bucket
resource "aws_s3_object" "index_html" {
  bucket       = aws_s3_bucket.origin_bucket.id
  key          = "index.html"
  content      = "<html><body><h1>Hello from S3 + Lightsail Distribution!</h1></body></html>"
  content_type = "text/html"
}

# Output the distribution details
output "lightsail_distribution_domain_name" {
  description = "The domain name of the Lightsail Distribution"
  value       = aws_lightsail_distribution.distribution.domain_name
}

output "lightsail_distribution_arn" {
  description = "The ARN of the Lightsail Distribution"
  value       = aws_lightsail_distribution.distribution.arn
}

output "s3_bucket_name" {
  description = "Name of the S3 origin bucket"
  value       = aws_s3_bucket.origin_bucket.id
}

reference:
resource "aws_lightsail_bucket" "test" {
  name      = "test-bucket"
  bundle_id = "small_1_0"
}
resource "aws_lightsail_distribution" "test" {
  name      = "test-distribution"
  bundle_id = "small_1_0"
  origin {
    name        = aws_lightsail_bucket.test.name
    region_name = aws_lightsail_bucket.test.region
  }
  default_cache_behavior {
    behavior = "cache"
  }
  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0
    forwarded_cookies {
      option = "none"
    }
    forwarded_headers {
      option = "default"
    }
    forwarded_query_strings {
      option = false
    }
  }
}

