# Terraform configuration for AWS Lightsail Distribution with Lightsail Instance as origin

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Create Lightsail Instance to serve as origin
resource "aws_lightsail_instance" "origin_instance" {
  name              = "lightsail-origin-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # Ubuntu, WordPress, etc. available
  bundle_id         = "nano_2_0"        # Adjust size as needed (nano_2_0, micro_2_0, etc.)

  # Optional: User data to install a simple web server
  user_data = <<-EOF
    #!/bin/bash
    yum update -y
    yum install -y httpd
    systemctl start httpd
    systemctl enable httpd
    echo "<h1>Lightsail Instance Origin Server</h1><p>Static IP: \$(curl -s http://169.254.169.254/latest/meta-data/public-ipv4)</p>" > /var/www/html/index.html
  EOF

  tags = {
    Name = "lightsail-origin"
  }
}

# Get the static IP of the Lightsail instance
resource "aws_lightsail_static_ip" "origin_static_ip" {
  name = "lightsail-origin-static-ip"
}

resource "aws_lightsail_static_ip_attachment" "origin_ip_attachment" {
  static_ip_name = aws_lightsail_static_ip.origin_static_ip.id
  instance_name  = aws_lightsail_instance.origin_instance.id
}

# Create Lightsail Distribution (CloudFront-like CDN)
resource "aws_lightsail_distribution" "main" {
  name = "lightsail-distribution"

  # Origin configuration using the Lightsail instance's static IP
  origin {
    name       = "lightsail-origin"
    region_name = "us-east-1"
    protocol_policy = "http-only"

    lightsail_instance {
      instance_name = aws_lightsail_instance.origin_instance.id
    }
  }

  # Default cache behavior
  default_cache_behavior {
    target_origin_id       = "lightsail-origin"
    viewed_cookie_ttl      = 60
    cookie_ttl             = 60
    liveness_enabled       = false
    ttl                     = 3600
    allowed_http_methods   = ["GET", "HEAD"]
  }

  # Cache settings
  cache_behavior_settings {
    ttl                      = 3600
    minimum_ttl              = 0
    allowed_http_methods     = ["GET", "HEAD"]
    forward_values {
      headers {
        include_list = []
      }
      query_strings_allow_list = []
      cookies {
        option = "none"
      }
    }
  }

  # Bundle price ID (choose based on your needs)
  bundle_id = "nano_2_0"

  tags = {
    Name = "lightsail-cdn-distribution"
  }
}

# Output the distribution DNS name
output "distribution_dns_name" {
  value = aws_lightsail_distribution.main.domain_name
}

output "instance_static_ip" {
  value = aws_lightsail_static_ip.origin_static_ip.ip_address
}

output "instance_public_ip" {
  value = aws_lightsail_instance.origin_instance.public_ip_address
}

