terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for long-term data retention with infrequent access and versioning
resource "aws_s3_bucket" "long_term_retention" {
  bucket = "my-long-term-retention-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "long_term_retention_versioning" {
  bucket = aws_s3_bucket.long_term_retention.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "long_term_retention_lifecycle" {
  bucket = aws_s3_bucket.long_term_retention.id

  rule {
    id     = "long-term-retention-rule"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    expiration {
      days = 3650
    }
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "long_term_retention_encryption" {
  bucket = aws_s3_bucket.long_term_retention.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "long_term_retention_public_access" {
  bucket = aws_s3_bucket.long_term_retention.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 Bucket for backups with Glacier Deep Archive
resource "aws_s3_bucket" "backups" {
  bucket = "my-backups-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_versioning" "backups_versioning" {
  bucket = aws_s3_bucket.backups.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "backups_lifecycle" {
  bucket = aws_s3_bucket.backups.id

  rule {
    id     = "backups-glacier-rule"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days      = 7
      storage_class        = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days      = 180
      storage_class        = "DEEP_ARCHIVE"
    }
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "backups_encryption" {
  bucket = aws_s3_bucket.backups.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "backups_public_access" {
  bucket = aws_s3_bucket.backups.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Policy for backup access
resource "aws_iam_policy" "backup_policy" {
  name        = "S3BackupPolicy"
  description = "Policy for accessing backup buckets"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.long_term_retention.arn,
          "${aws_s3_bucket.long_term_retention.arn}/*",
          aws_s3_bucket.backups.arn,
          "${aws_s3_bucket.backups.arn}/*"
        ]
      }
    ]
  })
}

# Output bucket names and ARNs
output "long_term_retention_bucket_name" {
  value = aws_s3_bucket.long_term_retention.bucket
}

output "backups_bucket_name" {
  value = aws_s3_bucket.backups.bucket
}

output "long_term_retention_bucket_arn" {
  value = aws_s3_bucket.long_term_retention.arn
}

output "backups_bucket_arn" {
  value = aws_s3_bucket.backups.arn
}

