  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Amazon S3 Glacier Vault
resource "aws_glacier_vault" "example" {
  name        = "example-glacier-vault"
  description = "Example Glacier vault integrated with DLM"

  tags = {
    Name = "example-glacier-vault"
  }
}

# IAM Role for Data Lifecycle Manager to access Glacier vault
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-glacier-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for DLM to manage Glacier vault
resource "aws_iam_role_policy" "dlm_glacier_policy" {
  name = "dlm-glacier-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "glacier:DeleteArchive",
          "glacier:GetJobOutput",
          "glacier:InitiateJob",
          "glacier:ListJobs",
          "glacier:ListParts",
          "glacier:ListVaults"
        ]
        Resource = aws_glacier_vault.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# Data Lifecycle Manager Policy for Glacier vault lifecycle management
resource "aws_dlm_lifecycle_policy" "glacier_lifecycle" {
  description        = "Glacier vault lifecycle policy"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "DailySnapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["00:00"]
      }

      retain_rule {
        count = 7
