    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Allow SNS Notifications"
        Effect    = "Allow"
        Principal = { Service = "glacier.amazonaws.com" }
        Action    = "glacier:Notify"
        Resource  = ""
      }
    ]
  })

  notification_configuration {
    snstopic  = aws_sns_topic.glacier_notifications.arn
    events    = ["InventoryRetrievalCompleted", "ArchiveRetrievalCompleted"]
  }

