        Action   = "sns:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
        Condition = {
          ArnEquals = {
            "aws:SourceArn" = aws_glacier_vault.example.arn
          }
        }
      }
    ]
  })
}

