}

# Vault lock policy using AWS Compliance mode (WORM)
resource "aws_glacier_vault_lock" "main" {
  vault_name       = aws_glacier_vault.main.name
  policy           = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "DenyArchiveDeletion"
        Effect    = "Deny"
        Principal = "*"
        Action    = "glacier:DeleteArchive"
        Resource  = "arn:aws:glacier:*:*:vaults/${aws_glacier_vault.main.name}/*"
        Condition = {
          DateGreaterThanEquals = {
            "aws:CurrentTime" = "2024-01-01T00:00:00Z"  # Compliance start date
          }
        }
      }
    ]
  })
  complete_lock   = true
}

