  }

  statement {
    sid    = "AllowArchiveRetrieval"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::123456789012:root"]  # Replace with your account ID
    }
    actions = [
      "glacier:InitiateArchiveRetrieval",
      "glacier:GetJobOutput"
    ]
    resources = ["arn:aws:glacier:us-east-1:123456789012:vaults/my-glacier-vault/*"]  # Replace region and account ID
  }
}

# Glacier vault
resource "aws_glacier_vault" "main" {
  name = "my-glacier-vault"

  access_policy = data.aws_iam_policy_document.glacier_vault_policy.json
}

# Vault lock policy using AWS Compliance mode (WORM)
resource "aws_glacier_vault_lock" "main" {
  vault_name       = aws_glacier_vault.main.name
  policy           = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "DenyArchiveDeletion"
        Effect    = "Deny"
        Principal = "*"
        Action    = "glacier:DeleteArchive"
