provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

# Subnets (2 subnets across different AZs for NLB)
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${data.aws_availability_zones.available.names[0]}"
  tags = {
    Name = "private-subnet-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${data.aws_availability_zones.available.names[1]}"
  tags = {
    Name = "private-subnet-b"
  }
}

# Availability Zones data source
data "aws_availability_zones" "available" {
  state = "available"
}

# Network Load Balancer (Internal)
resource "aws_lb" "internal_nlb" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  # Enable subnet IP availability for static private IPs
  enable_cross_zone_load_balancing = true

  tags = {
    Name = "internal-nlb"
  }
}

# Target Groups
resource "aws_lb_target_group" "internal_tg" {
  name     = "internal-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "0-255"
    port                = "traffic-port"
    protocol            = "TCP"
    unhealthy_threshold = 2
  }

  tags = {
    Name = "internal-tg"
  }
}

# Listener
resource "aws_lb_listener" "internal_listener" {
  load_balancer_arn = aws_lb.internal_nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.internal_tg.arn
  }
}

# Static Private IP Addresses for NLB (one per subnet)
resource "aws_network_interface" "nlb_enis" {
  count = 2

  subnet_id       = element([aws_subnet.private_a.id, aws_subnet.private_b.id], count.index)
  private_ips     = ["10.0.1.100", "10.0.2.100"]  # Specific private IPs per subnet
  security_groups = []  # NLB doesn't use security groups

  tags = {
    Name = "nlb-eni-${count.index + 1}"
  }
}

# Associate ENIs with NLB (requires AWS CLI or API after creation for full automation)
# Note: Terraform currently doesn't directly support assigning specific ENIs to NLB.
# Use these ENIs with their static IPs for your internal NLB addressing needs.

# Output the NLB DNS name and private IPs
output "nlb_dns_name" {
  description = "DNS name of the internal NLB"
  value       = aws_lb.internal_nlb.dns_name
}

output "nlb_private_ips" {
  description = "Static private IP addresses assigned to NLB ENIs"
  value       = [for eni in aws_network_interface.nlb_enis : eni.private_ip]
}

output "target_group_arn" {
  description = "ARN of the target group"
  value       = aws_lb_target_group.internal_tg.arn
}

