extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-west-2"
}

# Cognito User Pool
resource "aws_cognito_user_pool" "example" {
  name = "example-user-pool"

  password_policy {
    minimum_length    = 8
    require_lowercase = true
    require_numbers   = true
    require_symbols   = true
    require_uppercase = true
  }

  auto_verified_attributes = ["email"]
}

# Cognito User Pool Domain
resource "aws_cognito_user_pool_domain" "example" {
  domain       = "example-${random_string.domain_suffix.result}"
  user_pool_id = aws_cognito_user_pool.example.id
}

# Cognito User Pool Client
resource "aws_cognito_user_pool_client" "example" {
  name         = "example-client"
  user_pool_id = aws_cognito_user_pool.example.id

  explicit_auth_flows = [
    "ALLOW_USER_SRP_AUTH",
    "ALLOW_REFRESH_TOKEN_AUTH"
  ]
}

# Cognito Identity Pool (optional, for authenticated roles)
resource "aws_cognito_identity_pool" "example" {
  identity_pool_name               = "example-identity-pool"
  allow_unauthenticated_identities = false

  cognito_identity_providers {
    client_id               = aws_cognito_user_pool_client.example.id
    provider_name           = "cognito-idp.${var.aws_region}.amazonaws.com/${aws_cognito_user_pool.example.id}"
    server_side_token_check = false
  }
}

# IAM Role for authenticated users
resource "aws_iam_role" "cognito_authenticated" {
  name = "CognitoAuthenticatedRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRoleWithWebIdentity"
        Effect = "Allow"
        Principal = {
          Federated = "cognito-identity.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "cognito-identity.amazonaws.com:aud" = aws_cognito_identity_pool.example.id
          }
          "ForAnyValue:StringLike" = {
            "cognito-identity.amazonaws.com:amr" = "authenticated"
          }
        }
      }
    ]
  })
}

# Attach basic policy to authenticated role
resource "aws_iam_role_policy_attachment" "cognito_authenticated_poweruser" {
  role       = aws_iam_role.cognito_authenticated.name
  policy_arn = "arn:aws:iam::aws:policy/PowerUserAccess"
}

# Link identity pool to authenticated role
resource "aws_cognito_identity_pool_roles_attachment" "example" {
  identity_pool_id = aws_cognito_identity_pool.example.id

  roles = {
    "authenticated" = aws_iam_role.cognito_authenticated.arn
  }
}

# Application Load Balancer
resource "aws_lb" "example" {
  name               = "example-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = var.public_subnet_ids # Provide your public subnet IDs

  enable_deletion_protection = false

  tags = {
    Name = "example-alb"
  }
}

# Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name_prefix = "alb-sg-"
  vpc_id      = var.vpc_id # Provide your VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Target Group
resource "aws_lb_target_group" "example" {
  name     = "example-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = var.vpc_id # Provide your VPC ID

  health_check {
    path                = "/"
    protocol            = "HTTP"
    matcher             = "200-299"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

# Cognito Authentication Action
resource "aws_lb_listener" "example" {
  load_balancer_arn = aws_lb.example.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = var.certificate_arn # Provide your ACM certificate ARN

  default_action {
    type     = "authenticate-cognito"
    order    = 1

    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.example.arn
      user_pool_client_arn = aws_cognito_user_pool_client.example.arn
      user_pool_domain    = aws_cognito_user_pool_domain.example.domain
    }
  }

  # Forward action after authentication succeeds
  action {
    type             = "forward"
    order            = 2
    target_group_arn = aws_lb_target_group.example.arn
    authenticate_cognito_condition {
      # This condition triggers when authentication succeeds
      action_is_authenticate_cognito = true
    }
  }
}

# HTTP Listener (redirect to HTTPS)
resource "aws_lb_listener" "http_redirect" {
  load_balancer_arn = aws_lb.example.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "redirect"

    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

# Random string for unique domain name
resource "random_string" "domain_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Variables (define these or pass as inputs)
variable "vpc_id" {}
variable "public_subnet_ids" {
  type = list(string)
}
variable "certificate_arn" {}
variable "aws_region" {
  default = "us-west-2"
}

# Outputs
output "alb_dns_name" {
  value = aws_lb.example.dns_name
}

output "cognito_user_pool_endpoint" {
  value = aws_cognito_user_pool_domain.example.endpoint
}

