terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration
provider "aws" {
  region = "us-west-2"
}

# VPC for the Gateway Load Balancer
resource "aws_vpc" "glb_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "glb-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "glb_igw" {
  vpc_id = aws_vpc.glb_vpc.id
  tags = {
    Name = "glb-igw"
  }
}

# Public subnet for Gateway Load Balancer endpoints
resource "aws_subnet" "glb_subnet" {
  vpc_id                  = aws_vpc.glb_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true
  tags = {
    Name = "glb-subnet"
  }
}

# Route table for public subnet
resource "aws_route_table" "glb_rt" {
  vpc_id = aws_vpc.glb_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.glb_igw.id
  }
  tags = {
    Name = "glb-rt"
  }
}

resource "aws_route_table_association" "glb_rta" {
  subnet_id      = aws_subnet.glb_subnet.id
  route_table_id = aws_route_table.glb_rt.id
}

# Gateway Load Balancer
resource "aws_lb" "gateway_load_balancer" {
  name               = "glb-example"
  load_balancer_type = "gateway"
  subnet_mapping {
    subnet_id     = aws_subnet.glb_subnet.id
    allocation_id = aws_eip.glb_eip.id
  }

  enable_deletion_protection = false

  tags = {
    Name = "glb-example"
  }
}

# Elastic IP for Gateway Load Balancer
resource "aws_eip" "glb_eip" {
  domain = "vpc"
  tags = {
    Name = "glb-eip"
  }
}

# Target Group for Gateway Load Balancer (Firewall appliance)
resource "aws_lb_target_group" "glb_tg" {
  name     = "glb-tg"
  port     = 6081
  protocol = "GENEVE"
  vpc_id   = aws_vpc.glb_vpc.id

  health_check {
    protocol = "TCP"
    port     = "traffic-port"
  }

  tags = {
    Name = "glb-tg"
  }
}

# Listener for Gateway Load Balancer
resource "aws_lb_listener" "glb_listener" {
  gateway_lb_endpoint_id = aws_lb.gateway_load_balancer.arn
  protocol               = "GENEVE"
  port                   = 6081

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.glb_tg.arn
  }
}

output "glb_arn" {
  value = aws_lb.gateway_load_balancer.arn
}

output "glb_dns_name" {
  value = aws_lb.gateway_load_balancer.dns_name
}
