  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "postgres-minimal-vpc"
  }
}

# Public subnet
resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "postgres-public-subnet"
  }
}

# Internet gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "postgres-igw"
  }
}

# Route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "postgres-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Security group for PostgreSQL with minimal access
resource "aws_security_group" "postgres" {
  name_prefix = "postgres-minimal"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-minimal-sg"
  }
}

# RDS PostgreSQL instance optimized for minimal memory usage
resource "aws_db_instance" "postgres_minimal" {
  identifier             = "postgres-minimal"
  engine                 = "postgres"
  engine_version         = "15.5"
  instance_class         = "db.t4g.micro"  # Smallest/lowest memory Graviton instance
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = true
  max_allocated_storage  = 100
  db_name                = "minimaldb"
  username               = "postgres"
  password               = "SecurePass123!"  # Use secrets manager in production
  port                   = 5432
  vpc_security_group_ids = [aws_security_group.postgres.id]
  db_subnet_group_name   = aws_db_subnet_group.main.name
  skip_final_snapshot    = true
  backup_retention_period = 1
  multi_az               = false  # Single AZ to minimize costs/resources
  publicly_accessible    = true
  apply_immediately      = true

  # PostgreSQL parameters optimized for minimal memory usage
  parameter_group_name = aws_db_parameter_group.minimal_memory.name

  tags = {
    Name = "postgres-minimal"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "postgres-minimal-subnet-group"
  subnet_ids = [aws_subnet.public.id]

  tags = {
    Name = "postgres-minimal-subnet-group"
  }
}

# Custom parameter group for minimal memory usage
resource "aws_db_parameter_group" "minimal_memory" {
  family = "postgres15"
  name   = "postgres-minimal-memory"

  # Memory-optimized settings for minimal usage
  parameter {
    name  = "shared_preload_libraries"
    value = "pg_stat_statements"
  }

  parameter {
    name  = "effective_cache_size"
    value = "64MB"  # Minimal cache (8% of 768MB instance memory)
  }

  parameter {
    name  = "shared_buffers"
    value = "32MB"  # 25% of instance memory, minimal for t4g.micro
  }

  parameter {
    name  = "work_mem"
    value = "1MB"   # Very conservative per operation
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "16MB"
  }

  parameter {
    name  = "wal_buffers"
    value = "4MB"
  }

  parameter {
    name  = "checkpoint_completion_target"
    value = "0.7"
  }

  parameter {
    name  = "max_wal_size"
    value = "64MB"
  }

  parameter {
    name  = "min_wal_size"
    value = "16MB"
  }

  parameter {
    name  = "random_page_cost"
    value = "1.1"
  }

  parameter {
    name  = "effective_io_concurrency"
    value = "10"
  }

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "autovacuum"
    value = "on"
  }

  parameter {
    name  = "autovacuum_max_workers"
    value = "2"  # Minimal workers
  }

  parameter {
    name  = "autovacuum_vacuum_cost_limit"
    value = "100"
  }
}

# Output the connection details
output "postgres_endpoint" {
  description = "PostgreSQL endpoint"
  value       = aws_db_instance.postgres_minimal.endpoint
}

output "postgres_port" {
  description = "PostgreSQL port"
  value       = aws_db_instance.postgres_minimal.port
}

output "postgres_username" {
  description = "PostgreSQL username"
  value       = aws_db_instance.postgres_minimal.username
}

