  # PostgreSQL parameters optimized for minimal memory usage
  parameter_group_name = aws_db_parameter_group.minimal_memory.name

  tags = {
    Name = "postgres-minimal"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "postgres-minimal-subnet-group"
  subnet_ids = [aws_subnet.public.id]

  tags = {
    Name = "postgres-minimal-subnet-group"
  }
}

# Custom parameter group for minimal memory usage
resource "aws_db_parameter_group" "minimal_memory" {
  family = "postgres15"
  name   = "postgres-minimal-memory"

  # Memory-optimized settings for minimal usage
  parameter {
    name  = "shared_preload_libraries"
    value = "pg_stat_statements"
  }

  parameter {
    name  = "effective_cache_size"
    value = "64MB"  # Minimal cache (8% of 768MB instance memory)
  }

  parameter {
    name  = "shared_buffers"
    value = "32MB"  # 25% of instance memory, minimal for t4g.micro
  }

  parameter {
    name  = "work_mem"
    value = "1MB"   # Very conservative per operation
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "16MB"
  }

  parameter {
    name  = "wal_buffers"
    value = "4MB"
  }

  parameter {
    name  = "checkpoint_completion_target"
    value = "0.7"
  }

  parameter {
    name  = "max_wal_size"
    value = "64MB"
  }

  parameter {
    name  = "min_wal_size"
    value = "16MB"
  }

  parameter {
    name  = "random_page_cost"
    value = "1.1"
  }

  parameter {
    name  = "effective_io_concurrency"
    value = "10"
  }

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "autovacuum"
    value = "on"
  }

  parameter {
    name  = "autovacuum_max_workers"
    value = "2"  # Minimal workers
  }

  parameter {
    name  = "autovacuum_vacuum_cost_limit"
    value = "100"
  }
}

# Output the connection details
output "postgres_endpoint" {
  description = "PostgreSQL endpoint"
  value       = aws_db_instance.postgres_minimal.endpoint
}

output "postgres_port" {
  description = "PostgreSQL port"
  value       = aws_db_instance.postgres_minimal.port
}

output "postgres_username" {
  description = "PostgreSQL username"
  value       = aws_db_instance.postgres_minimal.username
}
```

This configuration creates a PostgreSQL RDS instance with `db.t4g.micro` (lowest memory footprint), custom parameter group optimized for minimal memory usage (shared_buffers=32MB, work_mem=1MB, etc.), single AZ, minimal storage, and essential networking. Connect using the output endpoint.

