  region = "us-east-1"
}

# S3 bucket containing the database backup (assumed to exist)
# data "aws_s3_bucket" "backup" {
#   bucket = "my-db-backup-bucket"
# }

# RDS DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "rds-subnet-group"
  subnet_ids = ["subnet-0123456789abcdef0", "subnet-0123456789abcdef1"]  # Replace with your subnet IDs

  tags = {
    Name = "RDS Subnet Group"
  }
}

# Security group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "rds-sg-"
  vpc_id      = "vpc-0123456789abcdef0"  # Replace with your VPC ID

  ingress {
    from_port   = 3306  # MySQL port - adjust for your DB engine
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Replace with your CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS Security Group"
  }
}

# RDS instance restored from S3 backup
resource "aws_db_instance" "restored" {
  identifier              = "restored-db-instance"
  engine                  = "mysql"  # Change to your DB engine (mysql, postgres, etc.)
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  max_allocated_storage   = 100
  storage_type            = "gp2"
  storage_encrypted       = true
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  skip_final_snapshot     = true
  backup_retention_period = 7

  # Restore from S3 backup
  s3_bucket_name       = "my-db-backup-bucket"  # Replace with your S3 bucket name
  s3_ingestion_role_arn = aws_iam_role.s3_ingestion_role.arn
  source_engine         = "mysql"  # Source engine of the backup
  source_engine_version = "8.0"    # Source engine version
  s3_prefix             = "backups/"  # Prefix/path to backup files in S3

  # Optional: Specify backup timestamps if multiple backups exist
  # s3_backup_file = "backup-2023-10-01.sql.gz"

  tags = {
    Name = "Restored RDS Instance"
  }
}

# IAM role for S3 ingestion
resource "aws_iam_role" "s3_ingestion_role" {
  name = "rds-s3-ingestion-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for S3 access
resource "aws_iam_role_policy" "s3_ingestion_policy" {
  name = "rds-s3-ingestion-policy"
  role = aws_iam_role.s3_ingestion_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject*",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::my-db-backup-bucket",
          "arn:aws:s3:::my-db-backup-bucket/*"
        ]
      }
    ]
  })
}

