# KMS Key for Secrets Manager and RDS encryption
resource "aws_kms_key" "secrets_rds_key" {
  description             = "KMS key for RDS and Secrets Manager"
  enable_key_rotation     = true
  deletion_window_in_days = 7

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS to use KMS key"
        Effect = "Allow"
        Principal = {
          AWS = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow Secrets Manager to use KMS key"
        Effect = "Allow"
        Principal = {
          Service = "secretsmanager.amazonaws.com"
        }
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kms_alias" "secrets_rds_key_alias" {
  name          = "alias/secrets-rds-key"
  target_key_id = aws_kms_key.secrets_rds_key.key_id
}

# Secrets Manager Secret for RDS master credentials
resource "aws_secretsmanager_secret" "rds_master_secret" {
  name                    = "rds-master-secret"
  description             = "Master password for RDS database"
  kms_key_id              = aws_kms_key.secrets_rds_key.key_id
  recovery_window_in_days = 7
}

resource "aws_secretsmanager_secret_version" "rds_master_secret_version" {
  secret_id     = aws_secretsmanager_secret.rds_master_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = "SecureMasterPassword123!"
  })
}

# RDS Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "Main RDS subnet group"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Security group for RDS instance"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MySQL/Aurora from VPC"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# VPC and networking setup
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-b"
  }
}

data "aws_caller_identity" "current" {}

# RDS Aurora MySQL Cluster (serverless for modern setup)
resource "aws_rds_cluster" "main" {
  cluster_identifier      = "aurora-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.02.0"
  database_name           = "mydb"
  master_username         = "admin"
  manage_master_user_password = true
  master_user_secret {
    kms_key_id = aws_kms_key.secrets_rds_key.key_id
    secret_arn = aws_secretsmanager_secret.rds_master_secret.arn
  }
  storage_encrypted       = true
  kms_key_id              = aws_kms_key.secrets_rds_key.key_id
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  skip_final_snapshot     = true
  serverlessv2_scaling_configuration {
    min_capacity = 0.5
    max_capacity = 8.0
  }

  tags = {
    Name = "aurora-cluster"
  }
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.main.engine
  engine_version     = aws_rds_cluster.main.engine_version
  publicly_accessible = false

  tags = {
    Name = "aurora-instance-${count.index}"
  }
}

# Output the secret ARN and cluster endpoint
output "rds_cluster_endpoint" {
  description = "Endpoint for Aurora cluster"
  value       = aws_rds_cluster.main.endpoint
}

output "rds_master_secret_arn" {
  description = "ARN of the master secret"
  value       = aws_secretsmanager_secret.rds_master_secret.arn
}

output "kms_key_arn" {
  description = "ARN of the KMS key"
  value       = aws_kms_key.secrets_rds_key.arn
}
```

