terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# VPC for the EFS setup (required for mount targets)
resource "aws_vpc" "efs_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "efs-vpc"
  }
}

# Subnet for mount target
resource "aws_subnet" "efs_subnet" {
  vpc_id            = aws_vpc.efs_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${var.aws_region}a"
  tags = {
    Name = "efs-subnet"
  }
}

# EFS File System
resource "aws_efs_file_system" "efs_fs" {
  creation_token   = "my-efs-token"
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"
  encrypted        = true

  tags = {
    Name = "my-efs-filesystem"
  }

  # Enable automatic backups
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }
}

# EFS Mount Target
resource "aws_efs_mount_target" "efs_mount" {
  file_system_id  = aws_efs_file_system.efs_fs.id
  subnet_id       = aws_subnet.efs_subnet.id
  security_groups = [aws_security_group.efs_sg.id]
}

# Security Group for EFS Mount Target (NFS port 2049)
resource "aws_security_group" "efs_sg" {
  name_prefix = "efs-sg"
  vpc_id      = aws_vpc.efs_vpc.id

  ingress {
    description = "NFS from VPC"
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.efs_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-security-group"
  }
}

# EFS Access Point (optional but recommended)
resource "aws_efs_access_point" "efs_ap" {
  file_system_id = aws_efs_file_system.efs_fs.id

  posix_user {
    uid = 1000
    gid = 1000
  }

  root_directory {
    path = "/exported/path"
    creation_info {
      owner_gid   = 1000
      owner_uid   = 1000
      permissions = "755"
    }
  }

  tags = {
    Name = "my-efs-access-point"
  }
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-west-2"
}

output "efs_file_system_id" {
  description = "ID of the EFS file system"
  value       = aws_efs_file_system.efs_fs.id
}

output "efs_mount_target_dns" {
  description = "DNS name of the EFS mount target"
  value       = aws_efs_mount_target.efs_mount.dns_name
}

output "efs_access_point_id" {
  description = "ID of the EFS access point"
  value       = aws_efs_access_point.efs_ap.id
}

