# Provider configuration (adjust version and region as needed)
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Variables (customize these as needed)
variable "subnet_id" {
  description = "ID of the subnet where NAT Gateway will be deployed"
  type        = string
}

variable "eip_allocation_id" {
  description = "Elastic IP allocation ID for the NAT Gateway"
  type        = string
}

# Data source to get AWS availability zones (optional, for reference)
data "aws_availability_zones" "available" {}

# NAT Gateway resource
resource "aws_nat_gateway" "public_nat" {
  allocation_id = var.eip_allocation_id
  subnet_id     = var.subnet_id

  tags = {
    Name = "public-nat-gateway"
    pike = "permissions"
  }

  depends_on = [aws_eip.nat_eip] # Ensures EIP is created first
}

# Elastic IP for NAT Gateway (if not pre-existing)
resource "aws_eip" "nat_eip" {
  domain = "vpc"

  tags = {
    Name = "nat-eip"
    pike = "permissions"
  }
}

# Outputs
output "nat_gateway_id" {
  description = "ID of the NAT Gateway"
  value       = aws_nat_gateway.public_nat.id
}

output "nat_gateway_public_ip" {
  description = "Public IP of the NAT Gateway"
  value       = aws_nat_gateway.public_nat.public_ip
}

