# Provider configuration (adjust version and region as needed)
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Variables (customize these as needed)
variable "subnet_id" {
  description = "ID of the subnet where NAT Gateway will be deployed"
  type        = string
}

variable "eip_allocation_id" {
  description = "Elastic IP allocation ID for the NAT Gateway"
  type        = string
}

# Data source to get AWS availability zones (optional, for reference)
data "aws_availability_zones" "available" {}

# NAT Gateway resource
resource "aws_nat_gateway" "public_nat" {
  allocation_id = var.eip_allocation_id
  subnet_id     = var.subnet_id

  tags = {
    Name = "public-nat-gateway"
    pike = "permissions"
  }

  depends_on = [aws_eip.nat_eip] # Ensures EIP is created first
}

# Elastic IP for NAT Gateway (if not pre-existing)
resource "aws_eip" "nat_eip" {
  domain = "vpc"

  tags = {
    Name = "nat-eip"
    pike = "permissions"
  }
}

# Outputs
output "nat_gateway_id" {
  description = "ID of the NAT Gateway"
  value       = aws_nat_gateway.public_nat.id
}

output "nat_gateway_public_ip" {
  description = "Public IP of the NAT Gateway"
  value       = aws_nat_gateway.public_nat.public_ip
}
```

**Usage Notes:**
- Set `subnet_id` and `eip_allocation_id` via `terraform.tfvars` or CLI variables
- Ensure the subnet is in a **public subnet** (with an Internet Gateway route)
- The EIP resource is included for completeness; remove if using a pre-existing allocation ID
- Apply tags ensure proper permissions tracking as requested

extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Example VPC and subnets (adjust as needed for your environment)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-subnet"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat" {
  domain = "vpc"
  tags = {
    Name = "nat-eip"
    pike = "permissions"
  }
}

# NAT Gateway in public subnet
resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id
  tags = {
    Name  = "main-nat"
    pike  = "permissions"
  }

  # Ensures EIP is attached before NAT Gateway creation
  depends_on = [aws_internet_gateway.main]
}

# Private route table for private subnet
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }
  tags = {
    Name = "private-rt"
  }
}

# Associate private route table with private subnet
resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

