# Provider configuration (update region as needed)
provider "aws" {
  region = "us-east-1"
}

# Variables
variable "subnet_id" {
  description = "ID of the subnet where the NAT Gateway will be deployed"
  type        = string
}

variable "eip_allocation_id" {
  description = "Elastic IP allocation ID to associate with the NAT Gateway"
  type        = string
}

# Data source to reference the subnet (optional, if subnet_id is provided as variable)
# If you have the subnet ID directly, you can use it without this data source

# NAT Gateway
resource "aws_nat_gateway" "public_nat" {
  allocation_id = var.eip_allocation_id
  subnet_id     = var.subnet_id

  tags = {
    Name = "public-nat-gateway"
  }

  depends_on = [aws_eip.nat_eip]  # Ensures EIP is created first
}

# Elastic IP for NAT Gateway (if not pre-existing)
